/* AUTO-GENERATED — Wyoming Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["WY"] = {"code":"WY","name":"Wyoming","agency":"Wyoming WYDOT","agencyShort":"WYDOT","handbook":"https://www.dot.state.wy.us/files/live/sites/wydot/files/shared/Driver_Services/Help%20Documents%20and%20Manuals/Wyoming%20CDL%20Manual_Oct%202024_full.pdf","links":{},"en":[{"q":"What is the maximum legal width for most commercial vehicles on Wyoming highways without an oversize permit?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":1,"explanation":"Wyoming limits vehicle width to 8 feet 6 inches (102 inches) on its highways, matching the federal standard. Anything wider requires an oversize permit. Source: W.S. 31-18-802; Wyoming Highway Patrol Commercial Carrier size and weight rules.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height on Wyoming highways without a permit?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":2,"explanation":"Wyoming allows a maximum vehicle height of 14 feet on all highways before an oversize permit is needed. Source: W.S. 31-18-802; Wyoming Highway Patrol Commercial Carrier rules.","handbook":"","hbref":""},{"q":"On Wyoming highways, what is the maximum load a single axle may legally carry without an overweight permit?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"answer":1,"explanation":"Wyoming limits a single axle to 20,000 pounds, the same as the federal single-axle limit. Source: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier weight limits.","handbook":"","hbref":""},{"q":"What is the maximum legal weight for a tandem axle (two axles spaced close together) on Wyoming highways without a permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":2,"explanation":"Wyoming permits a tandem axle to carry up to 36,000 pounds without an overweight permit. Source: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier weight limits.","handbook":"","hbref":""},{"q":"What is the basic maximum gross vehicle weight allowed on Wyoming highways before special permitting or formula provisions apply?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"answer":2,"explanation":"Wyoming's baseline maximum gross vehicle weight is 80,000 pounds, consistent with the federal limit. Higher weights are governed by the bridge-formula weight tables. Source: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier rules.","handbook":"","hbref":""},{"q":"Before any oversize permit is required, how much weight may each wheel legally carry in Wyoming?","options":["8,000 pounds","9,000 pounds","10,000 pounds","12,000 pounds"],"answer":2,"explanation":"Wyoming limits each wheel to 10,000 pounds. This per-wheel cap supplements the single- and tandem-axle limits. Source: Wyoming Highway Patrol Commercial Carrier weight limits; W.S. 31-18-805.","handbook":"","hbref":""},{"q":"What is the maximum overall length allowed in Wyoming for a combination of vehicles other than a tractor-semitrailer or recognized double combination?","options":["75 feet","81 feet","85 feet","97 feet"],"answer":2,"explanation":"For any other combination of vehicles, Wyoming sets an overall length limit of 85 feet. Source: W.S. 31-18-802 General Requirements.","handbook":"","hbref":""},{"q":"In a Wyoming truck-tractor with two trailers, the combined length of the trailing units (including connecting mechanisms) may not exceed what?","options":["75 feet","81 feet","85 feet","88 feet"],"answer":1,"explanation":"Wyoming limits the combined length of the semitrailer and trailer (or two semitrailers), including connecting mechanisms, to 81 feet, with the first trailer no more than 48 feet and the second no more than 40 feet. Source: W.S. 31-18-802.","handbook":"","hbref":""},{"q":"What is the maximum legal weight for a tridem axle group (three consecutive axles) on Wyoming highways without a permit?","options":["38,000 pounds","40,000 pounds","42,000 pounds","48,000 pounds"],"answer":2,"explanation":"Wyoming allows up to 42,000 pounds on a tridem (three consecutive) axle group before an overweight permit is required. Source: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier weight limits.","handbook":"","hbref":""},{"q":"In Wyoming, in a single trailer combination, the second trailer or second semitrailer may not exceed what length?","options":["28 feet","33 feet","40 feet","48 feet"],"answer":2,"explanation":"Wyoming limits the trailer or second semitrailer in a double combination to 40 feet (not counting the connecting mechanism). Source: W.S. 31-18-802 General Requirements.","handbook":"","hbref":""},{"q":"What is the federal bridge formula, as applied in Wyoming, used to determine?","options":["The maximum width of a load that can cross a bridge","The allowable gross weight on a group of axles based on axle count and spacing","The toll charged for heavy trucks crossing state bridges","The minimum tire pressure required on Interstate bridges"],"answer":1,"explanation":"Wyoming applies the federal bridge formula (W = 500[LN/(N-1) + 12N + 36]) to set the allowable gross weight on any group of two or more consecutive axles based on the number of axles (N) and the distance (L) between the extremes. Source: Wyoming weight tables; W.S. 31-18-805.","handbook":"","hbref":""},{"q":"Under Wyoming's bridge-formula weight tables, what is the maximum gross weight that may be authorized on the Interstate system by Table I (the inner-bridge formula table)?","options":["80,000 pounds","105,500 pounds","117,000 pounds","129,000 pounds"],"answer":2,"explanation":"Using Wyoming's Table I (the inner-bridge formula that checks all consecutive axle groups), gross weights up to 117,000 pounds may be carried on Interstate, primary and secondary highways when axle and bridge limits are met. Source: Wyoming Highway Patrol Commercial Carrier weight tables; WYDOT.","handbook":"","hbref":""},{"q":"In Wyoming, when may a divisible load exceed 80,000 pounds gross weight without an overweight permit?","options":["Only during daylight hours on Interstate highways","When legal on all axle and bridge weights and registered/licensed for at least that gross weight","Only if the load is agricultural and moved within 50 miles","Never, because any load over 80,000 pounds always requires a permit"],"answer":1,"explanation":"Wyoming allows a divisible load to exceed 80,000 pounds on state and Interstate highways without a permit, provided it is legal on every axle weight and under the bridge formula and the vehicle is licensed (registered) for at least its actual gross weight. Source: Wyoming Highway Patrol Commercial Carrier rules; WYDOT.","handbook":"","hbref":""},{"q":"A carrier wants to move a load wider than 8 feet 6 inches on a Wyoming highway. What must they do first?","options":["Nothing, as long as the load is under 10 feet wide","Obtain an oversize permit (or permission) before operating on the highway","Simply travel only at night with hazard lights","Reduce tire pressure and notify local police"],"answer":1,"explanation":"Any vehicle or load over legal size or weight in Wyoming must obtain a permit or permission before operating on a Wyoming state highway. Source: Wyoming Highway Patrol Commercial Carrier rules; WYDOT Permitting.","handbook":"","hbref":""},{"q":"Which Wyoming office handles overweight/oversize permits that exceed the limits a Port of Entry or highway shop can issue?","options":["The county sheriff's office in each county of travel","The Overweight Loads Office in Cheyenne (WYDOT)","The Federal Highway Administration regional office","The Wyoming Game and Fish Department"],"answer":1,"explanation":"Permits beyond routine Port of Entry/highway-shop thresholds are issued through WYDOT's Overweight Loads Office in Cheyenne (307-777-4376). Ports of entry and highway shops can issue permits up to set limits below that. Source: Wyoming Highway Patrol Commercial Carrier; WYDOT.","handbook":"","hbref":""},{"q":"What is the general permitted travel window in Wyoming for an oversize load that requires escorts?","options":["Midnight to 6:00 a.m. only","One-half hour before sunrise to one-half hour after sunset","Only Monday through Friday, 9:00 a.m. to 5:00 p.m.","24 hours a day with no restriction"],"answer":1,"explanation":"Oversize movements in Wyoming are generally restricted to daylight, from one-half hour before sunrise to one-half hour after sunset, including weekends; limited night travel is allowed only for narrower loads on Interstates with proper lighting. Source: WYDOT oversize permit conditions.","handbook":"","hbref":""},{"q":"What is the maximum number of single vehicles allowed in any one combination of vehicles on Wyoming highways?","options":["Two","Three","Four","Five"],"answer":1,"explanation":"Wyoming statute provides that no combination of vehicles shall consist of more than three single vehicles. Source: W.S. 31-18-802 General Requirements.","handbook":"","hbref":""},{"q":"In Wyoming, which CDL class is required to operate a combination vehicle with a gross combination weight rating (GCWR) of 26,001 lbs or more, where the towed unit has a GVWR of more than 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Wyoming follows the federal CDL classification (49 CFR 383.91): a Class A CDL covers any combination of vehicles with a GCWR of 26,001 lbs or more, provided the towed unit(s) have a GVWR over 10,000 lbs. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Under Wyoming rules, a single vehicle with a GVWR of 26,001 lbs or more (or such a vehicle towing a unit not over 10,000 lbs) requires which CDL class?","options":["Class C","Class B","Class A","Class M"],"answer":1,"explanation":"Wyoming uses the federal definitions: a Class B CDL covers a single vehicle with a GVWR of 26,001 lbs or more, or any such vehicle towing a unit with a GVWR not exceeding 10,000 lbs. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91.","handbook":"","hbref":""},{"q":"A Wyoming vehicle that does not meet the Class A or B weight thresholds but is designed to carry 16 or more passengers (including the driver) or carries placarded hazardous materials requires which CDL class?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"Wyoming follows the federal definition: a Class C CDL covers a vehicle that does not meet the Class A or B criteria but either is designed to transport 16 or more people (including the driver) or is used to carry hazardous materials requiring placards. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Which endorsement code does Wyoming place on a CDL that authorizes the driver to operate tank vehicles?","options":["T","N","H","X"],"answer":1,"explanation":"The tank vehicle endorsement is code N in Wyoming, consistent with the federal endorsement codes. (Code X denotes a combined tank/HazMat endorsement.) Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153.","handbook":"","hbref":""},{"q":"In Wyoming, which endorsement is required to pull double or triple trailers?","options":["N endorsement","P endorsement","T endorsement","S endorsement"],"answer":2,"explanation":"The T (Doubles/Triples) endorsement is required in Wyoming to operate a combination towing more than one trailer. It is obtained by passing the doubles/triples knowledge test. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Wyoming CDL restricted to INTRASTATE (within-state) commercial driving only?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Wyoming allows a CDL at 18 years of age for intrastate operation only; interstate operation requires age 21. Source: Wyoming CDL Manual (WYDOT) / W.S. Title 31 and 49 CFR 391.11.","handbook":"","hbref":""},{"q":"What is the minimum age to hold a Wyoming CDL that authorizes INTERSTATE commercial driving?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"A driver must be at least 21 to operate a CMV in interstate commerce; drivers aged 18-20 are limited to intrastate driving in Wyoming. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Before taking the CDL skills (road) test in Wyoming, how long must an applicant have held the Commercial Learner Permit (CLP)?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"A CLP must be held for a minimum of 14 days after issuance before the holder is eligible to take the CDL skills test. This federal hold applies in Wyoming. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25.","handbook":"","hbref":""},{"q":"While operating a CMV on a Wyoming CLP, the permit holder must always be accompanied by a person who holds a valid CDL for that vehicle. Where must that CDL holder be located?","options":["In the seat directly behind the driver","Anywhere inside the vehicle's cab","In the front passenger seat next to the CLP holder","Following in a separate vehicle"],"answer":2,"explanation":"A CLP holder must at all times be accompanied by a properly licensed CDL holder seated in the front seat beside the driver, providing direct supervision. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which restriction applies to a tank vehicle when operated by a Wyoming CLP holder who has the N (tank) area on the permit?","options":["The tank may be loaded up to 50% capacity","The tank must be empty (no liquid or gas cargo)","Only water may be carried","No tank operation is allowed at all on a CLP"],"answer":1,"explanation":"A CLP holder with a tank (N) authorization may only operate a tank vehicle that is empty of all liquid or gaseous cargo; loaded tanks are prohibited until the CDL is issued. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25.","handbook":"","hbref":""},{"q":"In Wyoming, which federal database must a driver use to complete required Entry-Level Driver Training (ELDT) before the CDL or covered endorsement test?","options":["The National Driver Register","The FMCSA Training Provider Registry (TPR)","The Wyoming WYDOT eDriver portal","The CDLIS clearinghouse"],"answer":1,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR), which records the trainee's completion for the state to verify. Source: Wyoming CDL Manual (WYDOT) / FMCSA ELDT rule, 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which applicants are required to complete ELDT before testing in Wyoming?","options":["Only drivers under age 21","First-time Class A or B applicants, Class B-to-A upgrades, and first-time P, S, or H endorsement applicants","Only HazMat (H) endorsement applicants","All CDL renewal applicants"],"answer":1,"explanation":"Federal ELDT (effective Feb. 7, 2022) applies to first-time Class A/B applicants, drivers upgrading Class B to Class A, and first-time applicants for the P, S, or H endorsements. It is not retroactive. Source: FMCSA ELDT rule, 49 CFR Part 380 / WYDOT.","handbook":"","hbref":""},{"q":"Beyond passing the knowledge test, what does Wyoming require for a HazMat (H) endorsement?","options":["A TSA security threat assessment including fingerprinting","A separate Wyoming Highway Patrol interview","A second physical examination","A notarized employer sponsorship letter"],"answer":0,"explanation":"Wyoming requires applicants for the H endorsement to pass a Transportation Security Administration (TSA) security threat assessment, which includes fingerprinting and a criminal/immigration background check, in addition to the HazMat knowledge test and ELDT theory training. Source: WYDOT Hazardous Materials Assessment page / 49 CFR 1572.","handbook":"","hbref":""},{"q":"How often must a Wyoming driver renew the TSA security threat assessment to keep the HazMat (H) endorsement?","options":["Every year","Every 2 years","Every 5 years","Every 8 years"],"answer":2,"explanation":"The TSA security threat assessment for the HazMat endorsement is valid for five years and must be renewed (with a new background check and knowledge test) to retain the H endorsement; it cannot be renewed by mail. Source: WYDOT Hazardous Materials Assessment page / 49 CFR 1572.","handbook":"","hbref":""},{"q":"In Wyoming, before a driver may hold an S (School Bus) endorsement, which other endorsement must also be obtained?","options":["H (HazMat)","N (Tank)","P (Passenger)","T (Doubles/Triples)"],"answer":2,"explanation":"The S (School Bus) endorsement requires the driver to first qualify for the P (Passenger) endorsement, since a school bus is a passenger-carrying vehicle. Both knowledge and skills testing apply. Source: Wyoming CDL Manual (WYDOT) / 49 CFR 383.123.","handbook":"","hbref":""},{"q":"Which set of documents must a Wyoming CDL applicant present to the issuing agency (WYDOT Driver Services)?","options":["Only a current Wyoming photo driver license","Proof of identity/lawful presence, Social Security number, and Wyoming residency","A passport and an employer letter only","A birth certificate and a vehicle title"],"answer":1,"explanation":"Wyoming requires CDL applicants to prove identity and lawful presence in the U.S., provide a Social Security number, and show proof of Wyoming residency (typically two documents). Source: WYDOT Driver Services document requirements.","handbook":"","hbref":""},{"q":"On the Wyoming CDL self-certification, a driver who operates across state lines and is NOT exempt from federal physical qualification must select which category?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"answer":1,"explanation":"A driver in interstate commerce who is not exempt from the federal medical rules self-certifies as Non-Excepted Interstate (NI) and must maintain a valid DOT medical examiner's certificate on file. Source: WYDOT CDL self-certification / 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which Wyoming CDL self-certification category does NOT require the driver to maintain a federal (DOT) medical examiner's certificate?","options":["Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Interstate (EI)","Both NI and NA"],"answer":2,"explanation":"Excepted Interstate (EI) and Excepted Intrastate (EA) drivers are exempt from maintaining a DOT medical card; only Non-Excepted drivers (NI and NA) must keep a current medical examiner's certificate. Source: WYDOT CDL self-certification / 49 CFR 383.71 and 390.3.","handbook":"","hbref":""},{"q":"What is the maximum blood alcohol concentration (BAC) at which a driver may legally operate a commercial motor vehicle (CMV) in Wyoming?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"answer":0,"explanation":"Wyoming follows the federal CMV standard: it is unlawful to operate a CMV with a BAC of 0.04 percent or more, half the 0.08 limit for regular drivers. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Wyoming's implied consent law, by driving or being in actual physical control of a vehicle in the state, a driver is deemed to have consented to what?","options":["A chemical test of blood, breath, or urine when lawfully requested","A vehicle search at any checkpoint","Mandatory drug treatment after any stop","A field sobriety test that cannot be refused"],"answer":0,"explanation":"Wyoming's implied consent statute provides that anyone driving or in actual physical control of a vehicle in the state automatically consents to a chemical test of blood, breath, or urine when lawfully requested by an officer. Source: Wyoming CDL Manual; W.S. 31-6-102 (implied consent).","handbook":"","hbref":""},{"q":"For a first major (mandatory) offense such as driving a CMV with a BAC of 0.04 or higher, how long is a Wyoming CDL holder disqualified (non-HazMat)?","options":["1 year","6 months","90 days","3 years"],"answer":0,"explanation":"A first conviction for a major offense results in a 1-year CDL disqualification in Wyoming. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a driver commits a first major offense while operating a CMV that is placarded for hazardous materials, the Wyoming disqualification period increases to what?","options":["3 years","2 years","18 months","5 years"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the Wyoming CDL disqualification period for a second major (mandatory) offense?","options":["Lifetime","10 years","5 years","3 years"],"answer":0,"explanation":"A second conviction for any major offense results in a lifetime CDL disqualification. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Wyoming CDL holder refuses a lawfully requested chemical test while operating a CMV. What is the minimum disqualification period for this refusal?","options":["1 year","90 days","6 months","60 days"],"answer":0,"explanation":"Refusing the required chemical test is treated as a major offense, resulting in at least a 1-year disqualification (3 years if placarded for HazMat). Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Wyoming CDL holder?","options":["Speeding 15 mph or more over the limit","Speeding 5 mph over the limit","A parking violation","An expired registration sticker"],"answer":0,"explanation":"Serious traffic violations include speeding 15 mph or more over the limit, reckless driving, following too closely, erratic/improper lane changes, and texting or handheld phone use while driving a CMV. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Wyoming CDL holder is convicted of two serious traffic violations arising from separate incidents within a 3-year period. What is the disqualification?","options":["60 days","30 days","120 days","90 days"],"answer":0,"explanation":"Two serious traffic violations within 3 years result in a 60-day disqualification. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is a Wyoming CDL holder disqualified for three serious traffic violations from separate incidents within a 3-year period?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Three serious traffic violations within 3 years result in a 120-day disqualification. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which CDL endorsement holders are required to STOP at every railroad-highway grade crossing while operating a CMV in Wyoming?","options":["Passenger and hazardous materials (placarded) vehicle drivers","Only drivers with a tanker endorsement","All CMV drivers without exception","Only school bus drivers under age 21"],"answer":0,"explanation":"Drivers carrying passengers or placarded hazardous materials must stop at all railroad crossings; other CMVs must slow down and check. Source: Wyoming CDL Manual; 49 CFR 392.10 / 383.51.","handbook":"","hbref":""},{"q":"What is the minimum Wyoming disqualification for a FIRST railroad-highway grade crossing violation in a CMV?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-crossing violation results in disqualification of not less than 60 days. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A driver commits a SECOND railroad-grade-crossing violation within 3 years. What is the minimum disqualification?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A second railroad-crossing violation within 3 years results in disqualification of not less than 120 days. Source: Wyoming CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a THIRD railroad-grade-crossing violation within a 3-year period?","options":["1 year","120 days","60 days","Lifetime"],"answer":0,"explanation":"A third or subsequent railroad-crossing violation within 3 years results in disqualification of not less than 1 year. Source: Wyoming CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a CDL driver's FIRST conviction of violating an out-of-service (OOS) order while operating a CMV?","options":["180 days to 1 year","30 to 60 days","2 to 5 years","60 to 120 days"],"answer":0,"explanation":"A first OOS-order violation results in a disqualification of not less than 180 days and not more than 1 year. Source: Wyoming CDL Manual; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"What is the disqualification range for a SECOND out-of-service order violation within a 10-year period (non-HazMat/non-passenger)?","options":["2 to 5 years","180 days to 1 year","1 to 2 years","3 to 5 years"],"answer":0,"explanation":"A second OOS-order violation within 10 years results in disqualification of not less than 2 years and not more than 5 years. Source: Wyoming CDL Manual; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A driver transporting placarded hazardous materials or 16-or-more passengers commits a FIRST out-of-service order violation. What is the disqualification range?","options":["180 days to 2 years","60 to 120 days","1 to 3 years","3 to 5 years"],"answer":0,"explanation":"A first OOS-order violation while hauling placarded HazMat or carrying 16+ passengers results in disqualification of not less than 180 days and not more than 2 years. Source: Wyoming CDL Manual; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"Texting or using a handheld mobile phone while driving a CMV in Wyoming is treated as which kind of CDL violation?","options":["A serious traffic violation that counts toward 60/120-day disqualification","A non-reportable minor infraction","An automatic lifetime disqualification","A railroad-crossing violation"],"answer":0,"explanation":"Texting and handheld phone use while driving a CMV are serious traffic violations; two within 3 years bring a 60-day, and three a 120-day, disqualification. Source: Wyoming CDL Manual; 49 CFR 383.51; 49 CFR 392.80/392.82.","handbook":"","hbref":""},{"q":"What is the maximum federal civil penalty a CMV driver in Wyoming can face for a single texting-or-handheld-phone-while-driving offense?","options":["Up to $2,750","Up to $250","Up to $11,000","Up to $500"],"answer":0,"explanation":"A CMV driver can be fined up to $2,750 per texting/handheld-phone offense; the employing motor carrier can be fined up to $11,000 for allowing it. Source: FMCSA Mobile Phone / No-Texting rules; 49 CFR 392.80-392.82, applicable in Wyoming.","handbook":"","hbref":""},{"q":"After a lifetime CDL disqualification, when (if at all) may a Wyoming driver become eligible to apply for reinstatement under the limited reinstatement provision?","options":["After at least 10 years, with conditions (HazMat remains ineligible)","After 5 years automatically","Never under any circumstance","After 3 years with a clean record"],"answer":0,"explanation":"A driver disqualified for life may, after a minimum of 10 years and meeting reinstatement conditions, be considered for reinstatement; HazMat eligibility is not restored. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Disqualifying major offenses such as DUI or using a vehicle to commit a felony apply to a Wyoming CDL holder even when the offense occurs in what type of vehicle?","options":["Any motor vehicle, including the driver's personal car","Only a placarded HazMat CMV","Only a vehicle owned by the employer","Only a vehicle over 26,001 lbs GVWR"],"answer":0,"explanation":"Major offenses like DUI count against the CDL regardless of vehicle type; a CDL holder convicted of DUI in a personal car is still disqualified. Source: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Wyoming, a CDL driver hauling placarded hazardous materials approaches a railroad-highway grade crossing. Where must the vehicle stop?","options":["No closer than 5 feet and no farther than 25 feet from the nearest rail","No closer than 50 feet and no farther than 100 feet from the nearest rail","At least 10 feet but no more than 30 feet from the nearest rail","No closer than 15 feet and no farther than 50 feet from the nearest rail"],"answer":3,"explanation":"Wyoming rule: A vehicle that is placarded for hazardous materials (or carries any chlorine or has loaded/empty HazMat cargo tanks) must stop between 15 and 50 feet from the nearest rail and proceed only when no train is coming. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 9 - Hazardous Materials, railroad crossing provision.","handbook":"","hbref":""},{"q":"A Wyoming bus driver carrying passengers must stop at a railroad crossing. What is the required stopping zone before the crossing?","options":["Between 20 and 60 feet before the crossing","Between 15 and 50 feet before the crossing","Between 10 and 40 feet before the crossing","Between 25 and 75 feet before the crossing"],"answer":1,"explanation":"Wyoming rule: Bus drivers must stop the bus between 15 and 50 feet before railroad crossings, then look and listen in both directions for trains before crossing. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 4 - Transporting Passengers (Railroad-Highway Crossings and Stops).","handbook":"","hbref":""},{"q":"Under Wyoming's Move Over law, a CDL driver on an interstate or other highway with two or more lanes in their direction approaches a stopped emergency vehicle displaying visual signals. What is the driver required to do, when safe?","options":["Come to a complete stop until the emergency vehicle leaves","Sound the horn and continue at the posted speed in the same lane","Merge into a lane not next to the emergency vehicle (the lane farthest from it)","Pull onto the right shoulder and wait for an officer to wave them on"],"answer":2,"explanation":"Wyoming rule: On a highway with two or more lanes in the direction of travel, a driver approaching a stopped authorized emergency vehicle using visual signals must merge into a lane not adjacent to that vehicle (the lane farthest away) when safe; if a lane change is unsafe, slow down and proceed with caution. Source: Wyoming Statute 31-5-224; 2024 Wyoming CDL Manual (Move-Over Laws).","handbook":"","hbref":""},{"q":"Under Wyoming's Move Over law, on a TWO-LANE road posted at 45 mph or greater, a driver passing a stopped emergency or tow vehicle who cannot safely change lanes must reduce speed to what level?","options":["20 mph less than the posted speed limit","10 mph less than the posted speed limit","15 mph less than the posted speed limit","Exactly 25 mph regardless of the posted limit"],"answer":0,"explanation":"Wyoming rule: On a two-lane road with a posted speed limit of 45 mph or greater, a driver must slow to a speed that is 20 mph less than the posted speed limit when passing a stopped emergency, utility, maintenance, or tow vehicle using visual signals. Source: Wyoming Statute 31-5-224.","handbook":"","hbref":""},{"q":"Wyoming's Move Over law (W.S. 31-5-224) protects more than police and ambulances. Which of these is ALSO expressly covered?","options":["Any passenger car parked on the shoulder with its hazard flashers on","A wrecker or tow truck at a disabled-vehicle scene displaying a flashing red or red-and-blue lamp","A school bus stopped to load children","A delivery truck double-parked on a city street"],"answer":1,"explanation":"Wyoming rule: The Move Over law covers authorized emergency vehicles, municipal/public-utility/highway construction or maintenance vehicles, and wrecker or tow trucks at the scene of a wrecked, disabled, or stalled vehicle when equipped with at least one flashing red or red-and-blue lamp visible 500 feet front and rear. Source: Wyoming Statute 31-5-224.","handbook":"","hbref":""},{"q":"On a two-lane, two-way Wyoming highway, a school bus stops with its red lights flashing and stop arm extended. What must an approaching CDL driver coming from the OPPOSITE direction do?","options":["Slow to 15 mph and pass with caution","Stop before reaching the bus and remain stopped until the lights stop flashing or the bus moves","Continue at posted speed because oncoming traffic is exempt","Stop only if children are visibly crossing the road"],"answer":1,"explanation":"Wyoming rule: On meeting or overtaking from either direction a stopped school bus showing flashing red lights, a driver must stop before reaching the bus and not proceed until the bus moves or the red lights are no longer flashing. Source: Wyoming Statute 31-5-507.","handbook":"","hbref":""},{"q":"Wyoming's school-bus stopping law has a divided-highway exception. When is a driver NOT required to stop for a school bus showing flashing red lights?","options":["Only when there is a painted center line between the directions of travel","Whenever the driver is more than two lanes away from the bus","Whenever the road has a posted speed limit above 55 mph","When the bus is on a different roadway of a highway with separate roadways"],"answer":3,"explanation":"Wyoming rule: A driver on a highway with separate roadways need not stop when meeting or passing a school bus that is on a DIFFERENT roadway, or when on a controlled-access highway and the bus is stopped in a loading zone where pedestrians are not permitted to cross. A painted line alone does not qualify. Source: Wyoming Statute 31-5-507.","handbook":"","hbref":""},{"q":"A Wyoming CDL driver must stop the vehicle on the shoulder of a one-way or divided highway. Within how long must emergency warning devices be placed, and where?","options":["Within 30 minutes, at 25 feet, 100 feet, and 250 feet toward approaching traffic","Within 10 minutes, at 50 feet, 150 feet, and 300 feet toward approaching traffic","Within 10 minutes, at 10 feet, 100 feet, and 200 feet toward approaching traffic","Within 5 minutes, at 10 feet, 50 feet, and 100 feet toward approaching traffic"],"answer":2,"explanation":"Wyoming rule: If you stop on or by a one-way or divided highway, place warning devices within 10 minutes at 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely (warning devices for stopped vehicles).","handbook":"","hbref":""},{"q":"A Wyoming CDL driver stops on a two-lane road carrying traffic in both directions. How should the three reflective triangles be placed?","options":["Within 10 feet, 100 feet, and 200 feet, all behind the vehicle only","At 25 feet, 100 feet, and 200 feet ahead of the vehicle only","Within 10 feet of the vehicle, plus 100 feet behind and 100 feet ahead of the vehicle","Within 10 feet, 50 feet, and 150 feet to the rear of the vehicle"],"answer":2,"explanation":"Wyoming rule: On a two-lane road carrying traffic in both directions (or an undivided highway), place warning devices within 10 feet of the front or rear corners to mark the vehicle, and 100 feet behind and 100 feet ahead of the vehicle. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely.","handbook":"","hbref":""},{"q":"If a hill or curve blocks the view of a CDL vehicle stopped on a Wyoming roadway, what does the manual say to do with the rear-most warning triangle?","options":["Move it farther back down the road so warning is provided beyond the obstruction, up to 500 feet","Leave all triangles at the standard 10/100/200-foot spacing","Place it directly on the obstruction itself for maximum visibility","Remove it entirely and rely only on the four-way flashers"],"answer":0,"explanation":"Wyoming rule: If the line-of-sight view is obstructed by a hill, curve, or other obstruction, move the rear-most triangle back down the road (back beyond the obstruction so the vehicle can be seen within 500 feet) to give proper warning. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely.","handbook":"","hbref":""},{"q":"On Wyoming's rural interstate highways posted at 80 mph, how does the speed limit apply to a tractor-trailer compared with a passenger car?","options":["Trucks are limited to 70 mph while cars may go 80 mph","Trucks and cars share the same 80 mph maximum; Wyoming sets no separate lower truck limit","Trucks are limited to 65 mph while cars may go 80 mph","Trucks are limited to 75 mph while cars may go 80 mph"],"answer":1,"explanation":"Wyoming rule: Wyoming's maximum interstate speed limit (up to 80 mph on designated rural segments) applies equally to commercial trucks and passenger cars. Unlike some states, Wyoming does not set a separate, lower statutory truck speed limit. Source: Wyoming Statute 31-5-301; WYDOT 80 mph corridor designations.","handbook":"","hbref":""},{"q":"Wyoming activates a tiered chain law on mountain segments of I-80. Under the more severe LEVEL 2 (extremely hazardous), what may a commercial vehicle rely on?","options":["Snow tires alone on the drive axle","Front-wheel drive with standard highway tires","Tire chains, or AWD equipped with M+S or all-weather rated tires (snow tires alone are not enough)","Reduced speed only, with no equipment requirement"],"answer":2,"explanation":"Wyoming rule: Under Level 1, a CMV may use chains, adequate snow tires, or AWD; under Level 2 (extremely hazardous), snow tires alone are insufficient and the vehicle must use tire chains, or AWD equipped with M+S or all-weather-rated tires. Source: WYDOT Wyoming chain-law levels (commonly enforced on the I-80 'Three Sisters' segment).","handbook":"","hbref":""},{"q":"During an extreme high-wind event, Wyoming closes stretches of I-80 and I-25 to which vehicles first?","options":["Only passenger cars and motorcycles","Light, high-profile commercial vehicles (such as empty or lightly loaded vans)","Only fully loaded tankers carrying liquids","Only buses carrying passengers"],"answer":1,"explanation":"Wyoming rule: Because of frequent blow-over crashes, WYDOT restricts and closes segments of I-80 and I-25 to light, high-profile vehicles (and, in the worst conditions, to all commercial vehicles). Closures are posted on wyoroad.info / Wyoming 511. Source: WYDOT high-wind / blow-over restrictions.","handbook":"","hbref":""},{"q":"What is the maximum width of a commercial vehicle that may travel on Wyoming highways WITHOUT an oversize permit?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"answer":2,"explanation":"Wyoming rule: The legal maximum vehicle width without a permit is 8 feet 6 inches (102 inches); anything wider requires an oversize permit from WYDOT. Source: Wyoming Statute 31-18-802 / WYDOT oversize-permit regulations.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum legal vehicle HEIGHT on Wyoming highways?","options":["14 feet","13 feet 6 inches","13 feet","15 feet"],"answer":0,"explanation":"Wyoming rule: The legal maximum vehicle height without a permit is 14 feet; loads exceeding this require an oversize permit. Source: Wyoming Statute 31-18-802 / WYDOT oversize regulations.","handbook":"","hbref":""},{"q":"A Wyoming carrier needs a single-trip oversize permit from WYDOT for one over-width move. What is the base single-trip oversize permit fee?","options":["$10.00","$50.00","$100.00","$25.00"],"answer":3,"explanation":"Wyoming rule: The fee for a single-trip oversize permit is $25.00, with additional mileage-based charges for loads exceeding 15 feet wide, 15 feet high, or 75 feet long. Source: Wyoming Statute 31-18-804 / WYDOT oversize-permit fee schedule.","handbook":"","hbref":""},{"q":"In a Wyoming tractor-semitrailer combination, what is the maximum length allowed for the semitrailer itself without a permit?","options":["60 feet","48 feet","53 feet","57 feet"],"answer":0,"explanation":"Wyoming rule: In a truck-tractor semitrailer combination, the semitrailer may not exceed 60 feet in length (Wyoming notably allows a longer single semitrailer than the common 53-foot trailer). Source: Wyoming Statute 31-18-802 (size and weight limits).","handbook":"","hbref":""},{"q":"While crossing a set of railroad tracks in Wyoming, what does the CDL manual instruct a driver of a manual-transmission CMV to do?","options":["Do not shift gears while any part of the vehicle is on the tracks","Downshift to the lowest gear midway across for maximum traction","Shift to neutral and coast across the tracks","Shift up one gear to clear the tracks as fast as possible"],"answer":0,"explanation":"Wyoming rule: The manual directs that you not shift gears while crossing railroad tracks, because changing gears risks stalling on the tracks; select a gear that will get you all the way across before starting. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2.15 - Railroad/Highway Crossings.","handbook":"","hbref":""},{"q":"Approaching a railroad crossing in Wyoming, a school bus, passenger bus, or placarded vehicle should take which action with its lights as it nears the tracks?","options":["Turn off all exterior lights to avoid confusing train crews","Flash the high beams continuously until across the tracks","Activate the turn signal in the direction of the nearest rail","Activate the four-way (hazard) flashers on the approach, and deactivate them after clearing the tracks"],"answer":3,"explanation":"Wyoming rule: A bus, school bus, or placarded vehicle should activate the four-way flashers as it approaches the crossing, stop within 50 feet but not less than 15 feet from the nearest rail, look and listen, then deactivate the flashers after crossing. Source: 2024 Wyoming Commercial Driver License Manual (WYDOT), railroad-crossing road-test procedures.","handbook":"","hbref":""},{"q":"Which Wyoming agency administers driving records and issues all classes of commercial driver licenses (CDLs) in the state?","options":["The Wyoming Department of Transportation (WYDOT), Driver Services Program","The Wyoming Department of Motor Vehicles, a standalone agency","The Wyoming Highway Patrol, Licensing Division","The county clerk's office in the applicant's county of residence"],"answer":0,"explanation":"In Wyoming, WYDOT's Driver Services Program administers the driving records system and tests, issues, and processes all classes of driver and commercial driver licenses. Wyoming has no separate 'DMV' agency. Source: WYDOT Driver Services / Commercial License page.","handbook":"","hbref":""},{"q":"Before WYDOT can administer a CDL skills test, an entry-level applicant for a first Class A or Class B CDL must complete what requirement?","options":["Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry","A 40-hour defensive-driving course approved by the Wyoming Highway Patrol","Two years of documented intrastate driving experience","A WYDOT-administered medical aptitude evaluation"],"answer":0,"explanation":"Federal ELDT rules, applied in Wyoming, require entry-level drivers to complete theory and behind-the-wheel training from a provider listed on the FMCSA Training Provider Registry (TPR) before taking the skills test. WYDOT states CDL skills tests may be given only to those who completed ELDT or hold a grandfather exemption. Source: WYDOT CDL Testing page; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"The Wyoming CDL skills test is made up of which three parts, administered in order?","options":["Pre-trip (vehicle) inspection, basic control skills, and on-road driving","Written knowledge test, vision screening, and on-road driving","Air-brake test, coupling test, and night driving","Defensive driving, basic control skills, and a hazmat handling demonstration"],"answer":0,"explanation":"Wyoming's CDL skills examination consists of a vehicle pre-trip inspection, a basic control skills test, and an over-the-road (on-road) driving test. Source: WYDOT CDL Testing page; AAMVA CDL skills standards adopted by Wyoming.","handbook":"","hbref":""},{"q":"Which four self-certification categories must a Wyoming CDL applicant choose from when declaring the type of commercial driving they do?","options":["Non-excepted interstate, excepted interstate, non-excepted intrastate, excepted intrastate","Local, regional, over-the-road, and seasonal","Class A, Class B, Class C, and endorsement-only","For-hire, private, agricultural, and emergency"],"answer":0,"explanation":"Wyoming requires each CDL holder to self-certify to one of four categories: non-excepted interstate (NI), excepted interstate (EI), non-excepted intrastate (NA), and excepted intrastate (EA). Source: WYDOT Driver Certification page; 49 CFR 383.71(b).","handbook":"","hbref":""},{"q":"Under the federal commercial learner's permit (CLP) rule applied in Wyoming, how long must an applicant hold a CLP before being allowed to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"A Wyoming CLP holder must wait at least 14 days after the CLP is issued before taking the CDL skills test. Source: 49 CFR 383.25(a)(3), applied by WYDOT Driver Services.","handbook":"","hbref":""},{"q":"A Wyoming CDL holder self-certifies as 'non-excepted interstate' (NI). What additional documentation must they keep current with WYDOT?","options":["A valid DOT medical examiner's certificate from a National Registry examiner","An annual interstate operating authority letter from FMCSA","A notarized affidavit of intrastate-only operation","A Wyoming-issued hazardous materials background clearance"],"answer":0,"explanation":"Drivers who self-certify as non-excepted interstate (NI) or non-excepted intrastate (NA) must be medically qualified and keep a current DOT medical certificate on file. Excepted (EI/EA) drivers do not. The examiner must be on the FMCSA National Registry. Source: WYDOT Driver Certification / DOT Medical Certificate pages; 49 CFR 383.71(h).","handbook":"","hbref":""},{"q":"What happens to a Wyoming CDL if the holder allows their required DOT medical certificate to lapse and becomes 'not-certified'?","options":["The CDL is subject to being downgraded to a non-commercial driver license","The CDL is immediately and permanently revoked with no path to reinstatement","The CDL converts automatically to an excepted-intrastate status with no action needed","The CDL is suspended for exactly 90 days, then auto-reinstated"],"answer":0,"explanation":"If a Wyoming CDL holder does not keep a current medical certificate on file, they become 'not-certified' and the CDL is subject to being downgraded to a non-commercial license. Source: WYDOT Driver Certification / DOT Medical Certificate pages; 49 CFR 383.73(o).","handbook":"","hbref":""},{"q":"What minimum passing score does Wyoming require on each CDL knowledge (written) test?","options":["80 percent","70 percent","75 percent","90 percent"],"answer":0,"explanation":"Wyoming CDL knowledge tests are multiple-choice and require at least 80% correct to pass; applicants only retake the tests they fail. Source: WYDOT CDL Testing page.","handbook":"","hbref":""},{"q":"How often must a Wyoming CDL be renewed to keep commercial driving privileges?","options":["Every 4 years","Every 5 years","Every 8 years","Every 2 years"],"answer":0,"explanation":"Wyoming CDLs are issued on a 4-year renewal cycle. Source: WYDOT Driver License renewal information.","handbook":"","hbref":""},{"q":"As Wyoming implements the FMCSA National Registry II (NRII) process, how is a driver's DOT medical certification normally provided to WYDOT?","options":["The certified medical examiner transmits the results electronically through the FMCSA National Registry to the state driving record","The driver mails a photocopy of the paper certificate to the county clerk","The employer faxes the certificate to the Wyoming Highway Patrol","The driver uploads a scanned image to a personal FMCSA driver account"],"answer":0,"explanation":"Under FMCSA's National Registry II rule (effective June 23, 2025), the certified medical examiner electronically transmits the medical certification results through the National Registry directly to the State Driver Licensing Agency record; the examiner has until midnight of the next calendar day to enter the results. Source: WYDOT DOT Medical Certificate page; FMCSA NRII rule.","handbook":"","hbref":""},{"q":"What is the form number of the federal Medical Examiner's Certificate used to document DOT medical qualification for a Wyoming CDL?","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"answer":0,"explanation":"The Medical Examiner's Certificate is FMCSA Form MCSA-5876 (the longer Medical Examination Report is MCSA-5875). Source: FMCSA medical forms; WYDOT DOT Medical Certificate page.","handbook":"","hbref":""},{"q":"A driver who self-certifies as 'excepted intrastate' (EA) in Wyoming is making which statement about their operation?","options":["They operate only within Wyoming and are not required to meet federal DOT medical-card requirements","They operate across state lines and must hold a federal DOT medical card","They haul hazardous materials only and need a separate medical waiver","They drive only government-owned vehicles exempt from licensing"],"answer":0,"explanation":"Excepted intrastate (EA) means the driver operates only in intrastate commerce and is excepted from the federal DOT medical certificate requirement. Source: WYDOT Driver Certification page; 49 CFR 383.71(b).","handbook":"","hbref":""},{"q":"When applying for a first-time Wyoming CDL or CLP, which document is typically required to prove identity?","options":["A certified birth certificate or a valid U.S. passport","A current employer ID badge","A signed CDL endorsement waiver form","A vehicle registration card in the applicant's name"],"answer":0,"explanation":"Wyoming requires proof of identity such as a certified birth certificate (or U.S. passport in lieu of it), along with proof of Social Security number and Wyoming residency, to apply. Source: WYDOT Driver Services; Wyoming CDL application requirements.","handbook":"","hbref":""},{"q":"Wyoming administers CDL skills testing under which scheduling arrangement?","options":["By appointment only, after all required written tests are passed","On a walk-in basis at any DMV kiosk statewide","Only during a single annual testing week each spring","Online via a remote proctored video session"],"answer":0,"explanation":"Wyoming skills tests are given by appointment only and only after the applicant has passed all required written (knowledge) tests. WYDOT offers skills testing at a limited number of locations across the state. Source: WYDOT CDL Testing page.","handbook":"","hbref":""},{"q":"For the Wyoming CDL skills test, who is responsible for providing a representative vehicle of the proper class?","options":["The applicant must supply a vehicle representative of the class/type being tested","WYDOT provides a state-owned test vehicle for every applicant","The certified medical examiner provides the test vehicle","The Wyoming Highway Patrol loans a vehicle at no cost"],"answer":0,"explanation":"Applicants must furnish their own vehicle representative of the class and type of CDL sought; for example, a tank vehicle must carry an N endorsement and purge documentation, and placarded hazmat loads may not be used during testing. Source: WYDOT CDL Testing page.","handbook":"","hbref":""},{"q":"In Wyoming, obtaining a hazardous materials (H) endorsement requires which training/testing sequence?","options":["Complete hazmat ELDT theory training, then pass the hazmat knowledge test (plus a TSA background check)","Pass an additional on-road skills test specific to tankers","Complete 200 hours of behind-the-wheel hazmat driving","Obtain a county-issued hazardous cargo permit before any testing"],"answer":0,"explanation":"For a first-time hazmat (H) endorsement, ELDT hazmat theory training must be completed before taking the hazmat knowledge test; a TSA security threat assessment (background check) is also required. There is no separate hazmat skills test. Source: WYDOT CDL Testing/Commercial License pages; 49 CFR Part 380 Subpart B.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Wyoming CDL for intrastate (within-Wyoming) commercial driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"A Wyoming CDL may be issued at 18 for intrastate operation; a driver must be 21 to operate in interstate commerce, haul hazardous materials requiring placards, or transport passengers across state lines. Source: WYDOT Commercial Learner's Permit / Commercial License pages.","handbook":"","hbref":""},{"q":"How long does a Wyoming commercial learner's permit (CLP) remain valid according to WYDOT?","options":["365 days","30 days","60 days","10 years"],"answer":0,"explanation":"Per WYDOT, a Wyoming CLP is valid for 365 days. (Federal rules require the holder to wait at least 14 days after issuance before taking the skills test.) Source: WYDOT Commercial Learner's Permit page.","handbook":"","hbref":""},{"q":"If a Wyoming driver lets a CDL expire and does not renew it within the state's grace period (about two years), what is generally required to get a CDL again?","options":["Start over by obtaining a new CLP and re-taking the required knowledge and skills tests","Pay a flat late fee and the CDL is reinstated with no testing","Submit only a new DOT medical certificate to restore the CDL","Wait five additional years before any reapplication is allowed"],"answer":0,"explanation":"Wyoming allows renewal of an expired CDL within roughly a two-year grace period without retesting; beyond that, the driver must start over with a new CLP and retake the required knowledge and skills tests. Source: WYDOT Driver License renewal information.","handbook":"","hbref":""},{"q":"Which statement best describes how CDL knowledge (written) test results are treated during the life of a Wyoming CLP?","options":["Passed knowledge tests remain valid for the duration of the CLP, so only failed tests must be retaken","All knowledge tests must be re-passed on the same day as the skills test","Knowledge test results expire 7 days after the test date","Knowledge tests need only be passed once and never expire, even without a CLP"],"answer":0,"explanation":"In Wyoming, knowledge tests are tied to the CLP: passed tests remain valid for the duration of the permit, and an applicant retakes only the tests they failed. Source: WYDOT CDL Testing page.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина для большинства коммерческих транспортных средств на автомагистралях Вайоминга без разрешения на негабаритный груз?","options":["8 футов (96 inches)","8 футов 6 inches (102 inches)","9 футов (108 inches)","10 футов (120 inches)"],"explanation":"Вайоминг ограничивает ширину транспортного средства до 8 футов 6 inches (102 inches) на своих автомагистралях, что соответствует федеральному стандарту. Всё, что шире, требует разрешения на негабаритный груз. Источник: W.S. 31-18-802; правила Wyoming Highway Patrol по размеру и весу для коммерческих перевозчиков."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства на автомагистралях Вайоминга без разрешения?","options":["13 футов","13 футов 6 inches","14 футов","15 футов"],"explanation":"Вайоминг допускает максимальную высоту транспортного средства 14 футов на всех автомагистралях до того, как потребуется разрешение на негабаритный груз. Источник: W.S. 31-18-802; правила Wyoming Highway Patrol для коммерческих перевозчиков."},"2":{"q":"На автомагистралях Вайоминга какую максимальную нагрузку может законно нести одиночная ось без разрешения на перевес?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Вайоминг ограничивает нагрузку на одиночную ось до 20,000 pounds, что совпадает с федеральным ограничением для одиночной оси. Источник: W.S. 31-18-805; весовые ограничения Wyoming Highway Patrol для коммерческих перевозчиков."},"3":{"q":"Каков максимальный разрешённый вес для сдвоенной оси (две близко расположенные оси) на автомагистралях Вайоминга без разрешения?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Вайоминг позволяет сдвоенной оси нести до 36,000 pounds без разрешения на перевес. Источник: W.S. 31-18-805; весовые ограничения Wyoming Highway Patrol для коммерческих перевозчиков."},"4":{"q":"Каков базовый максимальный полный вес транспортного средства, разрешённый на автомагистралях Вайоминга, прежде чем применяются особые разрешения или положения формулы?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Базовый максимальный полный вес транспортного средства в Вайоминге составляет 80,000 pounds, что соответствует федеральному ограничению. Более высокие значения веса регулируются таблицами веса по мостовой формуле. Источник: W.S. 31-18-805; правила Wyoming Highway Patrol для коммерческих перевозчиков."},"5":{"q":"Прежде чем потребуется какое-либо разрешение на негабаритный груз, какой вес может законно нести каждое колесо в Вайоминге?","options":["8,000 pounds","9,000 pounds","10,000 pounds","12,000 pounds"],"explanation":"Вайоминг ограничивает нагрузку на каждое колесо до 10,000 pounds. Это ограничение на колесо дополняет ограничения для одиночной и сдвоенной осей. Источник: весовые ограничения Wyoming Highway Patrol для коммерческих перевозчиков; W.S. 31-18-805."},"6":{"q":"Какова максимальная общая длина, разрешённая в Вайоминге для сцепки транспортных средств, отличной от сцепки тягач-полуприцеп или признанной двойной сцепки?","options":["75 футов","81 футов","85 футов","97 футов"],"explanation":"Для любой другой сцепки транспортных средств Вайоминг устанавливает ограничение общей длины 85 футов. Источник: W.S. 31-18-802 «Общие требования»."},"7":{"q":"В сцепке тягача с двумя прицепами в Вайоминге суммарная длина прицепных единиц (включая соединительные механизмы) не может превышать какого значения?","options":["75 футов","81 футов","85 футов","88 футов"],"explanation":"Вайоминг ограничивает суммарную длину полуприцепа и прицепа (или двух полуприцепов), включая соединительные механизмы, до 81 футов, при этом первый прицеп не более 48 футов, а второй не более 40 футов. Источник: W.S. 31-18-802."},"8":{"q":"Каков максимальный разрешённый вес для группы из трёх осей (три последовательные оси) на автомагистралях Вайоминга без разрешения?","options":["38,000 pounds","40,000 pounds","42,000 pounds","48,000 pounds"],"explanation":"Вайоминг допускает до 42,000 pounds на группе из трёх последовательных осей до того, как потребуется разрешение на перевес. Источник: W.S. 31-18-805; весовые ограничения Wyoming Highway Patrol для коммерческих перевозчиков."},"9":{"q":"В Вайоминге в одиночной сцепке с прицепом второй прицеп или второй полуприцеп не может превышать какой длины?","options":["28 футов","33 футов","40 футов","48 футов"],"explanation":"Вайоминг ограничивает длину прицепа или второго полуприцепа в двойной сцепке до 40 футов (не считая соединительного механизма). Источник: W.S. 31-18-802 «Общие требования»."},"10":{"q":"Для чего используется федеральная мостовая формула в её применении в Вайоминге?","options":["Для определения максимальной ширины груза, который может проехать по мосту","Для определения допустимого полного веса на группе осей в зависимости от количества осей и расстояния между ними","Для определения платы за проезд тяжёлых грузовиков по мостам штата","Для определения минимального давления в шинах, требуемого на мостах автомагистралей Interstate"],"explanation":"Вайоминг применяет федеральную мостовую формулу (W = 500[LN/(N-1) + 12N + 36]) для установления допустимого полного веса на любой группе из двух или более последовательных осей в зависимости от количества осей (N) и расстояния (L) между крайними осями. Источник: весовые таблицы Вайоминга; W.S. 31-18-805."},"11":{"q":"Согласно таблицам веса по мостовой формуле Вайоминга, каков максимальный полный вес, который может быть разрешён на системе Interstate по Таблице I (таблица внутренней мостовой формулы)?","options":["80,000 pounds","105,500 pounds","117,000 pounds","129,000 pounds"],"explanation":"Используя Таблицу I Вайоминга (внутренняя мостовая формула, проверяющая все группы последовательных осей), на автомагистралях Interstate, основных и второстепенных дорогах может перевозиться полный вес до 117,000 pounds при соблюдении осевых и мостовых ограничений. Источник: весовые таблицы Wyoming Highway Patrol для коммерческих перевозчиков; WYDOT."},"12":{"q":"В Вайоминге когда неделимый делимый груз может превышать полный вес 80,000 pounds без разрешения на перевес?","options":["Только в светлое время суток на автомагистралях Interstate","Когда он не превышает все ограничения по осям и по мостовой формуле и зарегистрирован/лицензирован как минимум на этот полный вес","Только если груз сельскохозяйственный и перевозится в пределах 50 миль","Никогда, потому что любой груз свыше 80,000 pounds всегда требует разрешения"],"explanation":"Вайоминг позволяет делимому грузу превышать 80,000 pounds на дорогах штата и автомагистралях Interstate без разрешения при условии, что он не превышает все ограничения по весу на каждую ось и по мостовой формуле, а транспортное средство лицензировано (зарегистрировано) как минимум на свой фактический полный вес. Источник: правила Wyoming Highway Patrol для коммерческих перевозчиков; WYDOT."},"13":{"q":"Перевозчик хочет перевезти груз шире 8 футов 6 inches по автомагистрали Вайоминга. Что он должен сделать в первую очередь?","options":["Ничего, пока груз менее 10 футов в ширину","Получить разрешение на негабаритный груз (или разрешение на проезд) до выезда на автомагистраль","Просто ехать только ночью с включённой аварийной сигнализацией","Снизить давление в шинах и уведомить местную полицию"],"explanation":"Любое транспортное средство или груз, превышающий разрешённый размер или вес в Вайоминге, должны получить разрешение или допуск до выезда на автомагистраль штата Вайоминг. Источник: правила Wyoming Highway Patrol для коммерческих перевозчиков; выдача разрешений WYDOT."},"14":{"q":"Какое ведомство Вайоминга занимается разрешениями на перевес/негабарит, превышающими лимиты, которые могут выдавать пункт въезда (Port of Entry) или дорожная мастерская?","options":["Офис шерифа округа в каждом округе по маршруту движения","Офис тяжеловесных грузов (Overweight Loads Office) в Шайенне (WYDOT)","Региональное отделение Федеральной администрации автомобильных дорог","Департамент охоты и рыболовства Вайоминга"],"explanation":"Разрешения, выходящие за рамки обычных пороговых значений пунктов въезда/дорожных мастерских, выдаются через Офис тяжеловесных грузов WYDOT в Шайенне (307-777-4376). Пункты въезда и дорожные мастерские могут выдавать разрешения до установленных лимитов ниже этого. Источник: Wyoming Highway Patrol для коммерческих перевозчиков; WYDOT."},"15":{"q":"Каково общее разрешённое окно движения в Вайоминге для негабаритного груза, требующего сопровождения?","options":["Только с полуночи до 6:00 утра","С получаса до восхода солнца до получаса после захода солнца","Только с понедельника по пятницу, с 9:00 утра до 5:00 вечера","24 часа в сутки без ограничений"],"explanation":"Перевозки негабаритных грузов в Вайоминге, как правило, ограничены светлым временем суток — с получаса до восхода солнца до получаса после захода солнца, включая выходные; ограниченное ночное движение разрешено только для более узких грузов на автомагистралях Interstate при надлежащем освещении. Источник: условия разрешений на негабарит WYDOT."},"16":{"q":"Каково максимальное количество одиночных транспортных средств, разрешённое в любой одной сцепке транспортных средств на автомагистралях Вайоминга?","options":["Два","Три","Четыре","Пять"],"explanation":"Закон Вайоминга предусматривает, что никакая сцепка транспортных средств не должна состоять более чем из трёх одиночных транспортных средств. Источник: W.S. 31-18-802 «Общие требования»."},"17":{"q":"В Вайоминге какой класс CDL требуется для управления составной сцепкой с полной массой автопоезда (GCWR) 26,001 lbs или более, где буксируемая единица имеет GVWR более 10,000 lbs?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Вайоминг следует федеральной классификации CDL (49 CFR 383.91): CDL класса A охватывает любую сцепку транспортных средств с GCWR 26,001 lbs или более при условии, что буксируемая единица (единицы) имеют GVWR более 10,000 lbs. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91."},"18":{"q":"Согласно правилам Вайоминга, одиночное транспортное средство с GVWR 26,001 lbs или более (или такое транспортное средство, буксирующее единицу не более 10,000 lbs) требует какого класса CDL?","options":["Класс C","Класс B","Класс A","Класс M"],"explanation":"Вайоминг использует федеральные определения: CDL класса B охватывает одиночное транспортное средство с GVWR 26,001 lbs или более, либо любое такое транспортное средство, буксирующее единицу с GVWR не более 10,000 lbs. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91."},"19":{"q":"Транспортное средство в Вайоминге, которое не соответствует весовым порогам класса A или B, но рассчитано на перевозку 16 или более пассажиров (включая водителя) либо перевозит опасные грузы, требующие маркировки плакатами, требует какого класса CDL?","options":["Класс A","Класс B","Класс C","CDL не требуется"],"explanation":"Вайоминг следует федеральному определению: CDL класса C охватывает транспортное средство, которое не соответствует критериям класса A или B, но либо рассчитано на перевозку 16 или более человек (включая водителя), либо используется для перевозки опасных грузов, требующих маркировки плакатами. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91."},"20":{"q":"Какой код подтверждения (эндорсмента) Вайоминг проставляет на CDL, разрешающий водителю управлять цистернами?","options":["T","N","H","X"],"explanation":"Подтверждение на управление цистернами имеет код N в Вайоминге, что соответствует федеральным кодам подтверждений. (Код X обозначает совмещённое подтверждение цистерна/HazMat.) Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153."},"21":{"q":"В Вайоминге какое подтверждение требуется для буксировки двойных или тройных прицепов?","options":["Подтверждение N","Подтверждение P","Подтверждение T","Подтверждение S"],"explanation":"Подтверждение T (двойные/тройные прицепы) требуется в Вайоминге для управления сцепкой, буксирующей более одного прицепа. Оно получается путём сдачи теоретического теста на двойные/тройные прицепы. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153."},"22":{"q":"Каков минимальный возраст для получения CDL Вайоминга, ограниченного только ВНУТРИШТАТНЫМ (в пределах штата) коммерческим вождением?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Вайоминг разрешает получение CDL в возрасте 18 лет только для внутриштатных перевозок; межштатные перевозки требуют возраста 21 год. Источник: Wyoming CDL Manual (WYDOT) / W.S. Title 31 и 49 CFR 391.11."},"23":{"q":"Каков минимальный возраст для владения CDL Вайоминга, разрешающим МЕЖШТАТНОЕ коммерческое вождение?","options":["18 лет","19 лет","21 год","23 года"],"explanation":"Водитель должен быть не моложе 21 года, чтобы управлять CMV в межштатной торговле; водители в возрасте 18-20 лет ограничены внутриштатным вождением в Вайоминге. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 391.11."},"24":{"q":"Перед сдачей практического (дорожного) экзамена CDL в Вайоминге, как долго заявитель должен владеть коммерческим учебным разрешением (CLP)?","options":["Не менее 7 days","Не менее 14 days","Не менее 30 days","Не менее 60 days"],"explanation":"CLP должно находиться во владении не менее 14 days после выдачи, прежде чем владелец получит право сдавать практический экзамен CDL. Это федеральное требование о выдержке действует в Вайоминге. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25."},"25":{"q":"При управлении CMV по CLP Вайоминга владелец разрешения всегда должен сопровождаться лицом, имеющим действующий CDL для данного транспортного средства. Где должен находиться этот владелец CDL?","options":["На сиденье непосредственно за водителем","В любом месте внутри кабины транспортного средства","На переднем пассажирском сиденье рядом с владельцем CLP","Следуя за ним в отдельном транспортном средстве"],"explanation":"Владелец CLP всё время должен сопровождаться надлежащим образом лицензированным владельцем CDL, сидящим на переднем сиденье рядом с водителем и обеспечивающим непосредственный надзор. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25."},"26":{"q":"Какое ограничение применяется к цистерне при управлении ею владельцем CLP Вайоминга, имеющим зону N (цистерна) в разрешении?","options":["Цистерна может быть загружена до 50% емкости","Цистерна должна быть пустой (без жидкого или газообразного груза)","Можно перевозить только воду","По CLP управление цистерной вообще не разрешено"],"explanation":"Владелец CLP с допуском на цистерну (N) может управлять только цистерной, пустой от любого жидкого или газообразного груза; загруженные цистерны запрещены до выдачи CDL. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25."},"27":{"q":"В Вайоминге какую федеральную базу данных должен использовать водитель для прохождения обязательного обучения водителей начального уровня (ELDT) перед экзаменом на CDL или соответствующее подтверждение?","options":["Национальный реестр водителей (National Driver Register)","Реестр поставщиков обучения FMCSA (TPR)","Портал eDriver WYDOT Вайоминга","Информационный центр CDLIS"],"explanation":"ELDT должно быть пройдено у поставщика, указанного в Реестре поставщиков обучения FMCSA (TPR), который фиксирует прохождение обучаемым для проверки штатом. Источник: Wyoming CDL Manual (WYDOT) / правило ELDT FMCSA, 49 CFR Part 380."},"28":{"q":"Какие заявители обязаны пройти ELDT перед сдачей экзамена в Вайоминге?","options":["Только водители моложе 21 года","Впервые подающие на класс A или B, повышающие с класса B до A, и впервые подающие на подтверждения P, S или H","Только заявители на подтверждение HazMat (H)","Все заявители на продление CDL"],"explanation":"Федеральное ELDT (вступило в силу 7 февраля 2022 года) применяется к впервые подающим на класс A/B, водителям, повышающим класс с B до A, и впервые подающим на подтверждения P, S или H. Оно не имеет обратной силы. Источник: правило ELDT FMCSA, 49 CFR Part 380 / WYDOT."},"29":{"q":"Помимо сдачи теоретического теста, что требует Вайоминг для подтверждения HazMat (H)?","options":["Оценку угрозы безопасности TSA, включая снятие отпечатков пальцев","Отдельное собеседование в Wyoming Highway Patrol","Второе медицинское обследование","Нотариально заверенное спонсорское письмо от работодателя"],"explanation":"Вайоминг требует, чтобы заявители на подтверждение H прошли оценку угрозы безопасности Управления транспортной безопасности (TSA), которая включает снятие отпечатков пальцев и проверку криминального/иммиграционного прошлого, в дополнение к теоретическому тесту HazMat и теоретическому обучению ELDT. Источник: страница оценки по опасным материалам WYDOT / 49 CFR 1572."},"30":{"q":"Как часто водитель в Вайоминге должен обновлять оценку угрозы безопасности TSA, чтобы сохранить подтверждение HazMat (H)?","options":["Каждый год","Каждые 2 года","Каждые 5 лет","Каждые 8 лет"],"explanation":"Оценка угрозы безопасности TSA для подтверждения HazMat действительна пять лет и должна обновляться (с новой проверкой прошлого и теоретическим тестом) для сохранения подтверждения H; её нельзя обновить по почте. Источник: страница оценки по опасным материалам WYDOT / 49 CFR 1572."},"31":{"q":"В Вайоминге, прежде чем водитель сможет иметь подтверждение S (школьный автобус), какое другое подтверждение также должно быть получено?","options":["H (HazMat)","N (цистерна)","P (пассажирское)","T (двойные/тройные прицепы)"],"explanation":"Подтверждение S (школьный автобус) требует, чтобы водитель сначала получил квалификацию для подтверждения P (пассажирское), поскольку школьный автобус является пассажирским транспортным средством. Применяются как теоретическое, так и практическое тестирование. Источник: Wyoming CDL Manual (WYDOT) / 49 CFR 383.123."},"32":{"q":"Какой набор документов должен предъявить заявитель на CDL Вайоминга в выдающее ведомство (WYDOT Driver Services)?","options":["Только действующие водительские права Вайоминга с фотографией","Подтверждение личности/законного пребывания, номер социального страхования и резидентство Вайоминга","Только паспорт и письмо работодателя","Свидетельство о рождении и право собственности на транспортное средство"],"explanation":"Вайоминг требует, чтобы заявители на CDL подтвердили личность и законное пребывание в США, предоставили номер социального страхования и показали подтверждение резидентства Вайоминга (обычно два документа). Источник: требования к документам WYDOT Driver Services."},"33":{"q":"При самосертификации для CDL Вайоминга водитель, который работает через границы штатов и НЕ освобождён от федеральных требований по физической пригодности, должен выбрать какую категорию?","options":["Освобождённый межштатный (Excepted Interstate, EI)","Неосвобождённый межштатный (Non-Excepted Interstate, NI)","Освобождённый внутриштатный (Excepted Intrastate, EA)","Неосвобождённый внутриштатный (Non-Excepted Intrastate, NA)"],"explanation":"Водитель в межштатной торговле, не освобождённый от федеральных медицинских правил, самосертифицируется как неосвобождённый межштатный (NI) и должен иметь действующий медицинский сертификат врача-эксперта DOT в деле. Источник: самосертификация CDL WYDOT / 49 CFR 383.71."},"34":{"q":"Какая категория самосертификации CDL Вайоминга НЕ требует от водителя наличия федерального (DOT) медицинского сертификата врача-эксперта?","options":["Неосвобождённый межштатный (Non-Excepted Interstate, NI)","Неосвобождённый внутриштатный (Non-Excepted Intrastate, NA)","Освобождённый межштатный (Excepted Interstate, EI)","Как NI, так и NA"],"explanation":"Освобождённые межштатные (EI) и освобождённые внутриштатные (EA) водители освобождены от наличия медицинской карты DOT; только неосвобождённые водители (NI и NA) должны иметь действующий медицинский сертификат врача-эксперта. Источник: самосертификация CDL WYDOT / 49 CFR 383.71 и 390.3."},"35":{"q":"Какова максимальная концентрация алкоголя в крови (BAC), при которой водитель может законно управлять коммерческим транспортным средством (CMV) в Вайоминге?","options":["0.04 процента","0.08 процента","0.02 процента","0.10 процента"],"explanation":"Вайоминг следует федеральному стандарту для CMV: незаконно управлять CMV с BAC 0.04 процента или более, что вдвое меньше предела 0.08 для обычных водителей. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"36":{"q":"Согласно закону Вайоминга о подразумеваемом согласии, управляя транспортным средством или находясь в фактическом физическом контроле над ним в штате, водитель считается давшим согласие на что?","options":["Химический анализ крови, дыхания или мочи при законном запросе","Обыск транспортного средства на любом контрольно-пропускном пункте","Обязательное лечение от наркозависимости после любой остановки","Тест на трезвость на месте, от которого нельзя отказаться"],"explanation":"Закон Вайоминга о подразумеваемом согласии предусматривает, что любой, кто управляет транспортным средством или находится в фактическом физическом контроле над ним в штате, автоматически даёт согласие на химический анализ крови, дыхания или мочи при законном запросе со стороны сотрудника. Источник: Wyoming CDL Manual; W.S. 31-6-102 (подразумеваемое согласие)."},"37":{"q":"За первое серьёзное (обязательное) нарушение, такое как управление CMV с BAC 0.04 или выше, на какой срок дисквалифицируется владелец CDL Вайоминга (не-HazMat)?","options":["1 год","6 месяцев","90 days","3 года"],"explanation":"Первое осуждение за серьёзное нарушение приводит к дисквалификации CDL на 1 год в Вайоминге. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"38":{"q":"Если водитель совершает первое серьёзное нарушение при управлении CMV, маркированным плакатами для опасных грузов, срок дисквалификации в Вайоминге увеличивается до чего?","options":["3 года","2 года","18 месяцев","5 лет"],"explanation":"Первое серьёзное нарушение, совершённое при перевозке опасных грузов с маркировкой плакатами, повышает дисквалификацию с 1 года до 3 лет. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"39":{"q":"Каков срок дисквалификации CDL в Вайоминге за второе серьёзное (обязательное) нарушение?","options":["Пожизненно","10 лет","5 лет","3 года"],"explanation":"Второе осуждение за любое серьёзное нарушение приводит к пожизненной дисквалификации CDL. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"40":{"q":"Владелец CDL Вайоминга отказывается от законно запрошенного химического анализа при управлении CMV. Каков минимальный срок дисквалификации за этот отказ?","options":["1 год","90 days","6 месяцев","60 days"],"explanation":"Отказ от обязательного химического анализа рассматривается как серьёзное нарушение, что приводит к дисквалификации не менее чем на 1 год (3 года при наличии маркировки плакатами для HazMat). Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"41":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение правил дорожного движения» для владельца CDL Вайоминга?","options":["Превышение скорости на 15 mph или более сверх лимита","Превышение скорости на 5 mph сверх лимита","Нарушение правил парковки","Просроченная наклейка о регистрации"],"explanation":"Серьёзные нарушения правил дорожного движения включают превышение скорости на 15 mph или более сверх лимита, безрассудное вождение, слишком близкое следование, беспорядочное/неправильное перестроение, а также написание сообщений или использование телефона в руке при управлении CMV. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"42":{"q":"Владелец CDL Вайоминга осуждён за два серьёзных нарушения правил дорожного движения, возникших в результате отдельных инцидентов в течение 3-летнего периода. Какова дисквалификация?","options":["60 days","30 days","120 days","90 days"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации на 60 days. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"43":{"q":"На какой срок дисквалифицируется владелец CDL Вайоминга за три серьёзных нарушения правил дорожного движения в результате отдельных инцидентов в течение 3-летнего периода?","options":["120 days","60 days","1 год","90 days"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации на 120 days. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"44":{"q":"Владельцы каких подтверждений CDL обязаны ОСТАНАВЛИВАТЬСЯ на каждом железнодорожном переезде при управлении CMV в Вайоминге?","options":["Водители пассажирских транспортных средств и транспортных средств с опасными грузами (с маркировкой плакатами)","Только водители с подтверждением на цистерну","Все водители CMV без исключения","Только водители школьных автобусов моложе 21 года"],"explanation":"Водители, перевозящие пассажиров или опасные грузы с маркировкой плакатами, должны останавливаться на всех железнодорожных переездах; другие CMV должны замедлиться и проверить. Источник: Wyoming CDL Manual; 49 CFR 392.10 / 383.51."},"45":{"q":"Какова минимальная дисквалификация в Вайоминге за ПЕРВОЕ нарушение на железнодорожном переезде на CMV?","options":["60 days","30 days","120 days","1 год"],"explanation":"Первое нарушение на железнодорожном переезде приводит к дисквалификации не менее чем на 60 days. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51 Table 3."},"46":{"q":"Водитель совершает ВТОРОЕ нарушение на железнодорожном переезде в течение 3 лет. Какова минимальная дисквалификация?","options":["120 days","60 days","90 days","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет приводит к дисквалификации не менее чем на 120 days. Источник: Wyoming CDL Manual; 49 CFR 383.51 Table 3."},"47":{"q":"Какова минимальная дисквалификация за ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["1 год","120 days","60 days","Пожизненно"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 лет приводит к дисквалификации не менее чем на 1 год. Источник: Wyoming CDL Manual; 49 CFR 383.51 Table 3."},"48":{"q":"Какова минимальная дисквалификация для водителя CDL за ПЕРВОЕ осуждение за нарушение приказа о выводе из эксплуатации (OOS) при управлении CMV?","options":["От 180 days до 1 года","От 30 до 60 days","От 2 до 5 лет","От 60 до 120 days"],"explanation":"Первое нарушение приказа OOS приводит к дисквалификации не менее чем на 180 days и не более чем на 1 год. Источник: Wyoming CDL Manual; 49 CFR 383.51 Table 4."},"49":{"q":"Каков диапазон дисквалификации за ВТОРОЕ нарушение приказа о выводе из эксплуатации в течение 10-летнего периода (не-HazMat/не-пассажирское)?","options":["От 2 до 5 лет","От 180 days до 1 года","От 1 до 2 лет","От 3 до 5 лет"],"explanation":"Второе нарушение приказа OOS в течение 10 лет приводит к дисквалификации не менее чем на 2 года и не более чем на 5 лет. Источник: Wyoming CDL Manual; 49 CFR 383.51 Table 4."},"50":{"q":"Водитель, перевозящий опасные грузы с маркировкой плакатами или 16 или более пассажиров, совершает ПЕРВОЕ нарушение приказа о выводе из эксплуатации. Каков диапазон дисквалификации?","options":["От 180 days до 2 лет","От 60 до 120 days","От 1 до 3 лет","От 3 до 5 лет"],"explanation":"Первое нарушение приказа OOS при перевозке опасных грузов с маркировкой плакатами или перевозке 16+ пассажиров приводит к дисквалификации не менее чем на 180 days и не более чем на 2 года. Источник: Wyoming CDL Manual; 49 CFR 383.51 Table 4."},"51":{"q":"Написание сообщений или использование мобильного телефона в руке при управлении CMV в Вайоминге рассматривается как какой вид нарушения CDL?","options":["Серьёзное нарушение правил дорожного движения, которое засчитывается в дисквалификацию на 60/120 days","Незначительное нарушение, не подлежащее отчётности","Автоматическая пожизненная дисквалификация","Нарушение на железнодорожном переезде"],"explanation":"Написание сообщений и использование телефона в руке при управлении CMV являются серьёзными нарушениями правил дорожного движения; два таких нарушения в течение 3 лет влекут дисквалификацию на 60 days, а три — на 120 days. Источник: Wyoming CDL Manual; 49 CFR 383.51; 49 CFR 392.80/392.82."},"52":{"q":"Каков максимальный федеральный гражданский штраф, который может грозить водителю CMV в Вайоминге за одно нарушение, связанное с написанием сообщений или использованием телефона в руке при вождении?","options":["До $2,750","До $250","До $11,000","До $500"],"explanation":"Водитель CMV может быть оштрафован на сумму до $2,750 за каждое нарушение, связанное с написанием сообщений/использованием телефона в руке; нанимающий автоперевозчик может быть оштрафован на сумму до $11,000 за разрешение этого. Источник: правила FMCSA о мобильном телефоне / запрете на написание сообщений; 49 CFR 392.80-392.82, применимые в Вайоминге."},"53":{"q":"После пожизненной дисквалификации CDL когда (если вообще) водитель в Вайоминге может получить право подать заявление о восстановлении согласно положению об ограниченном восстановлении?","options":["Не ранее чем через 10 лет, с условиями (HazMat остаётся недоступным)","Через 5 лет автоматически","Никогда ни при каких обстоятельствах","Через 3 года при безупречной истории"],"explanation":"Водитель, дисквалифицированный пожизненно, может, по истечении минимум 10 лет и при соблюдении условий восстановления, быть рассмотрен на восстановление; право на HazMat не восстанавливается. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"54":{"q":"Дисквалифицирующие серьёзные нарушения, такие как вождение в нетрезвом виде или использование транспортного средства для совершения тяжкого преступления, применяются к владельцу CDL Вайоминга даже когда нарушение происходит в каком типе транспортного средства?","options":["В любом моторном транспортном средстве, включая личный автомобиль водителя","Только в CMV с опасными грузами и маркировкой плакатами","Только в транспортном средстве, принадлежащем работодателю","Только в транспортном средстве с GVWR более 26,001 lbs"],"explanation":"Серьёзные нарушения, такие как вождение в нетрезвом виде, засчитываются против CDL независимо от типа транспортного средства; владелец CDL, осуждённый за вождение в нетрезвом виде на личном автомобиле, всё равно дисквалифицируется. Источник: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51."},"55":{"q":"В штате Вайоминг водитель CDL, перевозящий опасные материалы с табличками, приближается к железнодорожному переезду. Где транспортное средство должно остановиться?","options":["Не ближе 5 футов и не дальше 25 футов от ближайшего рельса","Не ближе 50 футов и не дальше 100 футов от ближайшего рельса","Не менее 10 футов, но не более 30 футов от ближайшего рельса","Не ближе 15 футов и не дальше 50 футов от ближайшего рельса"],"explanation":"Правило штата Вайоминг: транспортное средство с табличками опасных материалов (либо перевозящее любой хлор, либо имеющее загруженные или порожние грузовые цистерны для HazMat) должно остановиться на расстоянии от 15 до 50 футов от ближайшего рельса и продолжать движение только тогда, когда поезда нет. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 9 — Опасные материалы, положение о железнодорожных переездах."},"56":{"q":"Водитель автобуса в Вайоминге, перевозящий пассажиров, должен остановиться на железнодорожном переезде. Какова требуемая зона остановки перед переездом?","options":["От 20 до 60 футов перед переездом","От 15 до 50 футов перед переездом","От 10 до 40 футов перед переездом","От 25 до 75 футов перед переездом"],"explanation":"Правило штата Вайоминг: водители автобусов должны останавливать автобус на расстоянии от 15 до 50 футов перед железнодорожными переездами, а затем смотреть и слушать в обоих направлениях, нет ли поездов, прежде чем пересекать пути. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 4 — Перевозка пассажиров (Железнодорожные переезды и остановки)."},"57":{"q":"Согласно закону штата Вайоминг \"Move Over\", водитель CDL на межштатной автомагистрали или другой дороге с двумя или более полосами в его направлении приближается к остановившемуся аварийному транспортному средству, подающему световые сигналы. Что водитель обязан сделать, когда это безопасно?","options":["Полностью остановиться и ждать, пока аварийное транспортное средство уедет","Подать звуковой сигнал и продолжать движение с установленной скоростью в той же полосе","Перестроиться в полосу, не примыкающую к аварийному транспортному средству (наиболее удалённую от него)","Съехать на правую обочину и ждать, пока сотрудник не подаст знак продолжать движение"],"explanation":"Правило штата Вайоминг: на дороге с двумя или более полосами в направлении движения водитель, приближающийся к остановившемуся уполномоченному аварийному транспортному средству, использующему световые сигналы, должен перестроиться в полосу, не примыкающую к этому транспортному средству (наиболее удалённую), когда это безопасно; если перестроение небезопасно, нужно снизить скорость и продолжать движение с осторожностью. Источник: Wyoming Statute 31-5-224; 2024 Wyoming CDL Manual (законы Move-Over)."},"58":{"q":"Согласно закону штата Вайоминг \"Move Over\", на ДВУХПОЛОСНОЙ дороге с установленной скоростью 45 mph или выше водитель, проезжающий мимо остановившегося аварийного или эвакуационного транспортного средства и не имеющий возможности безопасно перестроиться, должен снизить скорость до какого уровня?","options":["На 20 mph меньше установленного ограничения скорости","На 10 mph меньше установленного ограничения скорости","На 15 mph меньше установленного ограничения скорости","Ровно до 25 mph независимо от установленного ограничения"],"explanation":"Правило штата Вайоминг: на двухполосной дороге с установленным ограничением скорости 45 mph или выше водитель должен снизить скорость до значения на 20 mph меньше установленного ограничения, проезжая мимо остановившегося аварийного, коммунального, ремонтного или эвакуационного транспортного средства, использующего световые сигналы. Источник: Wyoming Statute 31-5-224."},"59":{"q":"Закон штата Вайоминг \"Move Over\" (W.S. 31-5-224) защищает не только полицию и машины скорой помощи. Что из перечисленного ТАКЖЕ прямо охватывается этим законом?","options":["Любой легковой автомобиль, припаркованный на обочине с включённой аварийной сигнализацией","Эвакуатор или буксировочный грузовик на месте неисправного транспортного средства, использующий мигающий красный или красно-синий фонарь","Школьный автобус, остановившийся для посадки детей","Грузовик доставки, припаркованный вторым рядом на городской улице"],"explanation":"Правило штата Вайоминг: закон Move Over охватывает уполномоченные аварийные транспортные средства, муниципальные транспортные средства / транспортные средства коммунальных служб / транспортные средства дорожного строительства или обслуживания, а также эвакуаторы или буксировочные грузовики на месте разбитого, неисправного или заглохшего транспортного средства, оснащённые как минимум одним мигающим красным или красно-синим фонарём, видимым на 500 футов спереди и сзади. Источник: Wyoming Statute 31-5-224."},"60":{"q":"На двухполосной дороге с двусторонним движением в Вайоминге школьный автобус останавливается с мигающими красными огнями и выдвинутым знаком \"Стоп\". Что должен сделать приближающийся водитель CDL, едущий с ПРОТИВОПОЛОЖНОЙ стороны?","options":["Снизить скорость до 15 mph и проехать с осторожностью","Остановиться, не доезжая до автобуса, и оставаться на месте, пока огни не перестанут мигать или автобус не тронется","Продолжать движение с установленной скоростью, поскольку встречный транспорт освобождён от этого требования","Остановиться только если видно, что дети переходят дорогу"],"explanation":"Правило штата Вайоминг: при встрече или обгоне с любого направления остановившегося школьного автобуса с мигающими красными огнями водитель должен остановиться, не доезжая до автобуса, и не продолжать движение, пока автобус не тронется или красные огни не перестанут мигать. Источник: Wyoming Statute 31-5-507."},"61":{"q":"В законе штата Вайоминг об остановке перед школьным автобусом есть исключение для разделённой автомагистрали. Когда водитель НЕ обязан останавливаться перед школьным автобусом с мигающими красными огнями?","options":["Только когда между направлениями движения есть нарисованная центральная линия","Всякий раз, когда водитель находится более чем в двух полосах от автобуса","Всякий раз, когда на дороге установлено ограничение скорости выше 55 mph","Когда автобус находится на другой проезжей части автомагистрали с раздельными проезжими частями"],"explanation":"Правило штата Вайоминг: водителю на автомагистрали с раздельными проезжими частями не нужно останавливаться при встрече или проезде мимо школьного автобуса, который находится на ДРУГОЙ проезжей части, либо когда он находится на автомагистрали с контролируемым доступом, а автобус остановился в зоне посадки, где пешеходам не разрешено переходить дорогу. Одна лишь нарисованная линия не считается основанием. Источник: Wyoming Statute 31-5-507."},"62":{"q":"Водитель CDL в Вайоминге вынужден остановить транспортное средство на обочине дороги с односторонним движением или разделённой автомагистрали. В течение какого времени и где должны быть выставлены аварийные предупреждающие устройства?","options":["В течение 30 минут, на 25 футов, 100 футов и 250 футов в сторону приближающегося транспорта","В течение 10 минут, на 50 футов, 150 футов и 300 футов в сторону приближающегося транспорта","В течение 10 минут, на 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта","В течение 5 минут, на 10 футов, 50 футов и 100 футов в сторону приближающегося транспорта"],"explanation":"Правило штата Вайоминг: если вы останавливаетесь на дороге с односторонним движением или разделённой автомагистрали или рядом с ними, выставьте предупреждающие устройства в течение 10 минут на 10 футов, 100 футов и 200 футов от транспортного средства в сторону приближающегося транспорта. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 2 — Безопасное вождение (предупреждающие устройства для остановившихся транспортных средств)."},"63":{"q":"Водитель CDL в Вайоминге останавливается на двухполосной дороге с движением в обоих направлениях. Как следует разместить три светоотражающих треугольника?","options":["На 10 футов, 100 футов и 200 футов, все только позади транспортного средства","На 25 футов, 100 футов и 200 футов только впереди транспортного средства","В пределах 10 футов от транспортного средства, плюс 100 футов позади и 100 футов впереди транспортного средства","На 10 футов, 50 футов и 150 футов позади транспортного средства"],"explanation":"Правило штата Вайоминг: на двухполосной дороге с движением в обоих направлениях (или на неразделённой автомагистрали) выставьте предупреждающие устройства в пределах 10 футов от передних или задних углов, чтобы обозначить транспортное средство, а также на 100 футов позади и 100 футов впереди транспортного средства. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 2 — Безопасное вождение."},"64":{"q":"Если холм или поворот закрывает обзор транспортного средства CDL, остановившегося на дороге в Вайоминге, что, согласно руководству, нужно сделать с самым задним предупреждающим треугольником?","options":["Отнести его дальше назад по дороге, чтобы предупреждение действовало за пределами препятствия, на расстояние до 500 футов","Оставить все треугольники на стандартном расстоянии 10/100/200 футов","Поставить его прямо на само препятствие для максимальной видимости","Полностью убрать его и полагаться только на аварийную сигнализацию"],"explanation":"Правило штата Вайоминг: если обзор по линии видимости перекрыт холмом, поворотом или другим препятствием, отнесите самый задний треугольник дальше назад по дороге (за препятствие, чтобы транспортное средство было видно в пределах 500 футов), чтобы обеспечить надлежащее предупреждение. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 2 — Безопасное вождение."},"65":{"q":"На сельских межштатных автомагистралях Вайоминга с установленной скоростью 80 mph как применяется ограничение скорости к тягачу с прицепом по сравнению с легковым автомобилем?","options":["Грузовики ограничены 70 mph, тогда как легковым автомобилям разрешено 80 mph","У грузовиков и легковых автомобилей одинаковый максимум 80 mph; Вайоминг не устанавливает отдельного более низкого ограничения для грузовиков","Грузовики ограничены 65 mph, тогда как легковым автомобилям разрешено 80 mph","Грузовики ограничены 75 mph, тогда как легковым автомобилям разрешено 80 mph"],"explanation":"Правило штата Вайоминг: максимальное ограничение скорости на межштатных автомагистралях Вайоминга (до 80 mph на определённых сельских участках) применяется одинаково к коммерческим грузовикам и легковым автомобилям. В отличие от некоторых штатов, Вайоминг не устанавливает отдельного, более низкого законодательного ограничения скорости для грузовиков. Источник: Wyoming Statute 31-5-301; обозначения коридоров 80 mph WYDOT."},"66":{"q":"Вайоминг вводит многоуровневый закон о цепях противоскольжения на горных участках I-80. При более суровом УРОВНЕ 2 (крайне опасные условия) на что может полагаться коммерческое транспортное средство?","options":["Только на зимние шины на ведущей оси","На передний привод со стандартными шоссейными шинами","На цепи противоскольжения или на полный привод (AWD), оснащённый шинами с маркировкой M+S или всесезонными шинами (одних зимних шин недостаточно)","Только на снижение скорости, без требований к оборудованию"],"explanation":"Правило штата Вайоминг: при Уровне 1 коммерческое транспортное средство может использовать цепи, подходящие зимние шины или AWD; при Уровне 2 (крайне опасные условия) одних зимних шин недостаточно, и транспортное средство должно использовать цепи противоскольжения или AWD, оснащённый шинами с маркировкой M+S или всесезонными шинами. Источник: уровни закона о цепях штата Вайоминг WYDOT (как правило применяется на участке I-80 'Three Sisters')."},"67":{"q":"Во время сильного ветра Вайоминг закрывает участки I-80 и I-25 для каких транспортных средств в первую очередь?","options":["Только для легковых автомобилей и мотоциклов","Для лёгких высокопрофильных коммерческих транспортных средств (например, порожних или слабо загруженных фургонов)","Только для полностью загруженных автоцистерн, перевозящих жидкости","Только для автобусов, перевозящих пассажиров"],"explanation":"Правило штата Вайоминг: из-за частых аварий с опрокидыванием от ветра WYDOT ограничивает движение и закрывает участки I-80 и I-25 для лёгких высокопрофильных транспортных средств (а в наихудших условиях — для всех коммерческих транспортных средств). Закрытия публикуются на wyoroad.info / Wyoming 511. Источник: ограничения WYDOT при сильном ветре / риске опрокидывания."},"68":{"q":"Какова максимальная ширина коммерческого транспортного средства, которое может двигаться по дорогам Вайоминга БЕЗ разрешения на негабаритный груз?","options":["8 футов 0 дюймов","9 футов 0 дюймов","8 футов 6 дюймов","10 футов 0 дюймов"],"explanation":"Правило штата Вайоминг: законная максимальная ширина транспортного средства без разрешения составляет 8 футов 6 дюймов (102 inches); всё, что шире, требует разрешения на негабаритный груз от WYDOT. Источник: Wyoming Statute 31-18-802 / правила WYDOT о разрешениях на негабаритный груз."},"69":{"q":"Какова законная максимальная ВЫСОТА транспортного средства на дорогах Вайоминга без разрешения?","options":["14 футов","13 футов 6 дюймов","13 футов","15 футов"],"explanation":"Правило штата Вайоминг: законная максимальная высота транспортного средства без разрешения составляет 14 футов; грузы, превышающие это значение, требуют разрешения на негабаритный груз. Источник: Wyoming Statute 31-18-802 / правила WYDOT о негабаритных грузах."},"70":{"q":"Перевозчику в Вайоминге нужно одноразовое разрешение на негабаритный груз от WYDOT для одной перевозки сверхширокого груза. Какова базовая стоимость одноразового разрешения на негабаритный груз?","options":["$10.00","$50.00","$100.00","$25.00"],"explanation":"Правило штата Вайоминг: стоимость одноразового разрешения на негабаритный груз составляет $25.00, с дополнительными сборами в зависимости от пробега для грузов, превышающих 15 футов в ширину, 15 футов в высоту или 75 футов в длину. Источник: Wyoming Statute 31-18-804 / тарифная сетка сборов WYDOT за разрешения на негабаритный груз."},"71":{"q":"В составе автопоезда (тягач с полуприцепом) в Вайоминге какова максимальная разрешённая длина самого полуприцепа без разрешения?","options":["60 футов","48 футов","53 фута","57 футов"],"explanation":"Правило штата Вайоминг: в составе автопоезда из тягача с полуприцепом полуприцеп не может превышать 60 футов в длину (примечательно, что Вайоминг допускает более длинный одиночный полуприцеп, чем распространённый 53-футовый прицеп). Источник: Wyoming Statute 31-18-802 (ограничения по габаритам и весу)."},"72":{"q":"При пересечении железнодорожных путей в Вайоминге что руководство CDL предписывает делать водителю коммерческого транспортного средства с механической коробкой передач?","options":["Не переключать передачи, пока какая-либо часть транспортного средства находится на путях","Переключиться на самую низкую передачу на середине переезда для максимального сцепления","Переключиться на нейтраль и катиться по инерции через пути","Повысить передачу на одну ступень, чтобы пересечь пути как можно быстрее"],"explanation":"Правило штата Вайоминг: руководство предписывает не переключать передачи при пересечении железнодорожных путей, поскольку смена передач создаёт риск заглохнуть на путях; выберите передачу, которая позволит проехать весь переезд до начала движения. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), раздел 2.15 — Железнодорожные переезды."},"73":{"q":"Приближаясь к железнодорожному переезду в Вайоминге, школьный автобус, пассажирский автобус или транспортное средство с табличками должно совершить какое действие с фарами по мере приближения к путям?","options":["Выключить все внешние огни, чтобы не сбивать с толку поездные бригады","Непрерывно мигать дальним светом, пока не пересечёт пути","Включить указатель поворота в сторону ближайшего рельса","Включить аварийную сигнализацию при приближении и выключить её после пересечения путей"],"explanation":"Правило штата Вайоминг: автобус, школьный автобус или транспортное средство с табличками должно включить аварийную сигнализацию при приближении к переезду, остановиться в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, посмотреть и прислушаться, а затем выключить аварийную сигнализацию после пересечения путей. Источник: 2024 Wyoming Commercial Driver License Manual (WYDOT), процедуры дорожного экзамена на железнодорожных переездах."},"74":{"q":"Какое ведомство Вайоминга ведёт записи о вождении и выдаёт все классы коммерческих водительских удостоверений (CDL) в штате?","options":["Программа Driver Services Министерства транспорта Вайоминга (WYDOT)","Управление транспортных средств Вайоминга (DMV), отдельное ведомство","Отдел лицензирования Дорожного патруля Вайоминга","Канцелярия секретаря округа по месту жительства заявителя"],"explanation":"В Вайоминге программа Driver Services при WYDOT ведёт систему записей о вождении, проводит экзамены, выдаёт и обрабатывает все классы водительских и коммерческих водительских удостоверений. В Вайоминге нет отдельного ведомства 'DMV'. Источник: страница WYDOT Driver Services / Commercial License."},"75":{"q":"Прежде чем WYDOT сможет провести экзамен по навыкам CDL, начинающий заявитель на получение первого CDL класса A или класса B должен выполнить какое требование?","options":["Пройти обучение начинающих водителей (ELDT) у провайдера из реестра FMCSA Training Provider Registry","Пройти 40-часовой курс безопасного вождения, одобренный Дорожным патрулём Вайоминга","Иметь два года документально подтверждённого опыта вождения внутри штата","Пройти медицинскую оценку профпригодности, проводимую WYDOT"],"explanation":"Федеральные правила ELDT, применяемые в Вайоминге, требуют, чтобы начинающие водители прошли теоретическое и практическое (за рулём) обучение у провайдера, включённого в реестр FMCSA Training Provider Registry (TPR), прежде чем сдавать экзамен по навыкам. WYDOT указывает, что экзамены по навыкам CDL могут проводиться только для тех, кто прошёл ELDT или имеет освобождение по 'дедушкиной оговорке'. Источник: страница WYDOT CDL Testing; 49 CFR Part 380 Subpart F."},"76":{"q":"Из каких трёх частей состоит экзамен по навыкам CDL в Вайоминге, проводимых по порядку?","options":["Предрейсовый (осмотр транспортного средства) осмотр, базовые навыки управления и вождение по дороге","Письменный теоретический тест, проверка зрения и вождение по дороге","Тест на пневматические тормоза, тест на сцепку и ночное вождение","Безопасное вождение, базовые навыки управления и демонстрация обращения с опасными грузами"],"explanation":"Экзамен по навыкам CDL в Вайоминге состоит из предрейсового осмотра транспортного средства, теста на базовые навыки управления и дорожного (по дороге) экзамена по вождению. Источник: страница WYDOT CDL Testing; стандарты навыков CDL AAMVA, принятые Вайомингом."},"77":{"q":"Из каких четырёх категорий самосертификации должен выбрать заявитель на CDL в Вайоминге при декларировании типа коммерческого вождения, которым он занимается?","options":["Неосвобождённые межштатные, освобождённые межштатные, неосвобождённые внутриштатные, освобождённые внутриштатные","Местные, региональные, дальнобойные и сезонные","Класс A, класс B, класс C и только с подтверждениями","Коммерческие, частные, сельскохозяйственные и аварийные"],"explanation":"Вайоминг требует, чтобы каждый владелец CDL самостоятельно сертифицировался по одной из четырёх категорий: неосвобождённые межштатные (NI), освобождённые межштатные (EI), неосвобождённые внутриштатные (NA) и освобождённые внутриштатные (EA). Источник: страница WYDOT Driver Certification; 49 CFR 383.71(b)."},"78":{"q":"Согласно федеральному правилу о коммерческом ученическом разрешении (CLP), применяемому в Вайоминге, как долго заявитель должен владеть CLP, прежде чем ему будет разрешено сдавать экзамен по навыкам CDL?","options":["Не менее 14 days","Не менее 30 days","Не менее 7 days","Не менее 60 days"],"explanation":"Владелец CLP в Вайоминге должен подождать не менее 14 days после выдачи CLP, прежде чем сдавать экзамен по навыкам CDL. Источник: 49 CFR 383.25(a)(3), применяемый WYDOT Driver Services."},"79":{"q":"Владелец CDL в Вайоминге самостоятельно сертифицируется как 'неосвобождённый межштатный' (NI). Какую дополнительную документацию он должен поддерживать в актуальном состоянии в WYDOT?","options":["Действующий медицинский сертификат DOT от медицинского эксперта из Национального реестра","Ежегодное письмо о праве на межштатные перевозки от FMCSA","Нотариально заверенное аффидевит о работе только внутри штата","Выданное Вайомингом заключение о проверке благонадёжности для перевозки опасных материалов"],"explanation":"Водители, самостоятельно сертифицирующиеся как неосвобождённые межштатные (NI) или неосвобождённые внутриштатные (NA), должны быть медицински годными и иметь в деле действующий медицинский сертификат DOT. Освобождённые водители (EI/EA) — нет. Эксперт должен быть в Национальном реестре FMCSA. Источник: страницы WYDOT Driver Certification / DOT Medical Certificate; 49 CFR 383.71(h)."},"80":{"q":"Что происходит с CDL в Вайоминге, если владелец допускает истечение срока действия требуемого медицинского сертификата DOT и становится 'несертифицированным'?","options":["CDL подлежит понижению до некоммерческого водительского удостоверения","CDL немедленно и безвозвратно отзывается без возможности восстановления","CDL автоматически переходит в статус освобождённого внутриштатного без каких-либо действий","CDL приостанавливается ровно на 90 дней, а затем автоматически восстанавливается"],"explanation":"Если владелец CDL в Вайоминге не поддерживает в деле действующий медицинский сертификат, он становится 'несертифицированным', и CDL подлежит понижению до некоммерческого удостоверения. Источник: страницы WYDOT Driver Certification / DOT Medical Certificate; 49 CFR 383.73(o)."},"81":{"q":"Какой минимальный проходной балл требует Вайоминг на каждом теоретическом (письменном) тесте CDL?","options":["80 процентов","70 процентов","75 процентов","90 процентов"],"explanation":"Теоретические тесты CDL в Вайоминге проводятся в формате с выбором ответа и требуют не менее 80% правильных ответов для прохождения; заявители пересдают только те тесты, которые они не прошли. Источник: страница WYDOT CDL Testing."},"82":{"q":"Как часто необходимо продлевать CDL в Вайоминге, чтобы сохранить право на коммерческое вождение?","options":["Каждые 4 года","Каждые 5 лет","Каждые 8 лет","Каждые 2 года"],"explanation":"CDL в Вайоминге выдаются с циклом продления каждые 4 года. Источник: информация о продлении водительских удостоверений WYDOT."},"83":{"q":"По мере внедрения Вайомингом процесса FMCSA National Registry II (NRII) каким образом обычно предоставляется в WYDOT медицинская сертификация DOT водителя?","options":["Сертифицированный медицинский эксперт передаёт результаты электронно через FMCSA National Registry в запись о вождении штата","Водитель отправляет почтой фотокопию бумажного сертификата секретарю округа","Работодатель отправляет сертификат по факсу в Дорожный патруль Вайоминга","Водитель загружает отсканированное изображение в личный аккаунт водителя FMCSA"],"explanation":"Согласно правилу FMCSA National Registry II (вступившему в силу 23 июня 2025 г.), сертифицированный медицинский эксперт электронно передаёт результаты медицинской сертификации через National Registry напрямую в запись Управления по выдаче водительских удостоверений штата; у эксперта есть время до полуночи следующего календарного дня для внесения результатов. Источник: страница WYDOT DOT Medical Certificate; правило FMCSA NRII."},"84":{"q":"Каков номер формы федерального Сертификата медицинского эксперта (Medical Examiner's Certificate), используемого для подтверждения медицинской годности DOT для CDL в Вайоминге?","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"explanation":"Сертификат медицинского эксперта — это форма FMCSA Form MCSA-5876 (более длинный отчёт о медицинском обследовании — MCSA-5875). Источник: медицинские формы FMCSA; страница WYDOT DOT Medical Certificate."},"85":{"q":"Водитель, который самостоятельно сертифицируется как 'освобождённый внутриштатный' (EA) в Вайоминге, делает какое заявление о своей деятельности?","options":["Он работает только в пределах Вайоминга и не обязан соответствовать требованиям федеральной медицинской карты DOT","Он работает за пределами штата и должен иметь федеральную медицинскую карту DOT","Он перевозит только опасные материалы и нуждается в отдельном медицинском освобождении","Он водит только государственные транспортные средства, освобождённые от лицензирования"],"explanation":"Освобождённый внутриштатный (EA) означает, что водитель работает только во внутриштатной торговле и освобождён от требования о медицинском сертификате DOT. Источник: страница WYDOT Driver Certification; 49 CFR 383.71(b)."},"86":{"q":"При подаче заявления на CDL или CLP в Вайоминге впервые какой документ обычно требуется для подтверждения личности?","options":["Заверенное свидетельство о рождении или действующий паспорт США","Действующий служебный пропуск работодателя","Подписанная форма отказа от подтверждения CDL","Свидетельство о регистрации транспортного средства на имя заявителя"],"explanation":"Вайоминг требует подтверждение личности, такое как заверенное свидетельство о рождении (или паспорт США вместо него), наряду с подтверждением номера социального страхования и проживания в Вайоминге для подачи заявления. Источник: WYDOT Driver Services; требования к заявлению на CDL в Вайоминге."},"87":{"q":"Вайоминг проводит экзамены по навыкам CDL по какому порядку записи?","options":["Только по предварительной записи, после прохождения всех требуемых письменных тестов","В порядке живой очереди в любом киоске DMV по всему штату","Только в течение одной ежегодной недели тестирования каждую весну","Онлайн через удалённую видеосессию под наблюдением"],"explanation":"Экзамены по навыкам в Вайоминге проводятся только по предварительной записи и только после того, как заявитель прошёл все требуемые письменные (теоретические) тесты. WYDOT предлагает экзамены по навыкам в ограниченном числе мест по всему штату. Источник: страница WYDOT CDL Testing."},"88":{"q":"Для экзамена по навыкам CDL в Вайоминге кто несёт ответственность за предоставление репрезентативного транспортного средства надлежащего класса?","options":["Заявитель должен предоставить транспортное средство, репрезентативное для тестируемого класса/типа","WYDOT предоставляет каждому заявителю государственное тестовое транспортное средство","Сертифицированный медицинский эксперт предоставляет тестовое транспортное средство","Дорожный патруль Вайоминга предоставляет транспортное средство бесплатно"],"explanation":"Заявители должны предоставить собственное транспортное средство, репрезентативное для класса и типа запрашиваемого CDL; например, для автоцистерны необходимо подтверждение N и документация об очистке (продувке), а грузы HazMat с табличками не могут использоваться во время тестирования. Источник: страница WYDOT CDL Testing."},"89":{"q":"В Вайоминге получение подтверждения на перевозку опасных материалов (H) требует какой последовательности обучения/тестирования?","options":["Пройти теоретическое обучение HazMat ELDT, затем сдать теоретический тест по HazMat (плюс проверка благонадёжности TSA)","Сдать дополнительный дорожный экзамен по навыкам, специфичный для автоцистерн","Пройти 200 часов вождения с опасными грузами за рулём","Получить выданное округом разрешение на опасный груз до какого-либо тестирования"],"explanation":"Для получения подтверждения на перевозку опасных материалов (H) впервые необходимо пройти теоретическое обучение HazMat ELDT до сдачи теоретического теста по HazMat; также требуется оценка угрозы безопасности TSA (проверка благонадёжности). Отдельного экзамена по навыкам для HazMat нет. Источник: страницы WYDOT CDL Testing/Commercial License; 49 CFR Part 380 Subpart B."},"90":{"q":"Каков минимальный возраст для выдачи CDL в Вайоминге для внутриштатного (в пределах Вайоминга) коммерческого вождения?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"CDL в Вайоминге может быть выдан в 18 лет для работы внутри штата; водителю должен быть 21 год, чтобы работать в межштатной торговле, перевозить опасные материалы, требующие табличек, или перевозить пассажиров через границы штатов. Источник: страницы WYDOT Commercial Learner's Permit / Commercial License."},"91":{"q":"Как долго коммерческое ученическое разрешение (CLP) Вайоминга остаётся действительным согласно WYDOT?","options":["365 days","30 days","60 days","10 лет"],"explanation":"Согласно WYDOT, CLP в Вайоминге действителен в течение 365 days. (Федеральные правила требуют, чтобы владелец подождал не менее 14 days после выдачи, прежде чем сдавать экзамен по навыкам.) Источник: страница WYDOT Commercial Learner's Permit."},"92":{"q":"Если водитель в Вайоминге допускает истечение срока действия CDL и не продлевает его в течение льготного периода штата (около двух лет), что обычно требуется, чтобы снова получить CDL?","options":["Начать заново, получив новый CLP и повторно сдав требуемые теоретические тесты и экзамены по навыкам","Заплатить фиксированный штраф за просрочку, и CDL восстанавливается без тестирования","Предоставить только новый медицинский сертификат DOT для восстановления CDL","Подождать ещё пять лет, прежде чем будет разрешена повторная подача заявления"],"explanation":"Вайоминг разрешает продление просроченного CDL в течение примерно двухлетнего льготного периода без повторного тестирования; по истечении этого срока водитель должен начать заново с нового CLP и повторно сдать требуемые теоретические тесты и экзамены по навыкам. Источник: информация о продлении водительских удостоверений WYDOT."},"93":{"q":"Какое утверждение лучше всего описывает, как результаты теоретических (письменных) тестов CDL учитываются в течение срока действия CLP в Вайоминге?","options":["Пройденные теоретические тесты остаются действительными в течение всего срока действия CLP, поэтому пересдавать нужно только проваленные тесты","Все теоретические тесты должны быть пересданы в тот же день, что и экзамен по навыкам","Результаты теоретического теста истекают через 7 days после даты теста","Теоретические тесты нужно пройти только один раз, и они никогда не истекают, даже без CLP"],"explanation":"В Вайоминге теоретические тесты привязаны к CLP: пройденные тесты остаются действительными в течение всего срока действия разрешения, и заявитель пересдаёт только те тесты, которые он провалил. Источник: страница WYDOT CDL Testing."}},"tr":{"0":{"q":"Wyoming karayollarında çoğu ticari araç için, büyük boy izni olmadan izin verilen maksimum yasal genişlik nedir?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"Wyoming, karayollarında araç genişliğini federal standartla uyumlu olarak 8 feet 6 inches (102 inches) ile sınırlar. Bundan daha geniş olan her şey büyük boy izni gerektirir. Kaynak: W.S. 31-18-802; Wyoming Highway Patrol Ticari Taşıyıcı boyut ve ağırlık kuralları."},"1":{"q":"Wyoming karayollarında izin olmadan izin verilen maksimum yasal araç yüksekliği nedir?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Wyoming, tüm karayollarında büyük boy izni gerekmeden önce maksimum 14 feet araç yüksekliğine izin verir. Kaynak: W.S. 31-18-802; Wyoming Highway Patrol Ticari Taşıyıcı kuralları."},"2":{"q":"Wyoming karayollarında, fazla ağırlık izni olmadan tek bir aksın yasal olarak taşıyabileceği maksimum yük nedir?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Wyoming, tek aksı federal tek aks limitiyle aynı olacak şekilde 20,000 pounds ile sınırlar. Kaynak: W.S. 31-18-805; Wyoming Highway Patrol Ticari Taşıyıcı ağırlık limitleri."},"3":{"q":"Wyoming karayollarında izin olmadan bir tandem aks (birbirine yakın yerleştirilmiş iki aks) için izin verilen maksimum yasal ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Wyoming, bir tandem aksın fazla ağırlık izni olmadan 36,000 pounds'a kadar taşımasına izin verir. Kaynak: W.S. 31-18-805; Wyoming Highway Patrol Ticari Taşıyıcı ağırlık limitleri."},"4":{"q":"Özel izin veya formül hükümleri uygulanmadan önce Wyoming karayollarında izin verilen temel maksimum brüt araç ağırlığı nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Wyoming'in taban maksimum brüt araç ağırlığı, federal limitle tutarlı olarak 80,000 pounds'tur. Daha yüksek ağırlıklar köprü-formülü ağırlık tablolarıyla yönetilir. Kaynak: W.S. 31-18-805; Wyoming Highway Patrol Ticari Taşıyıcı kuralları."},"5":{"q":"Herhangi bir büyük boy izni gerekmeden önce, Wyoming'de her tekerlek yasal olarak ne kadar ağırlık taşıyabilir?","options":["8,000 pounds","9,000 pounds","10,000 pounds","12,000 pounds"],"explanation":"Wyoming, her tekerleği 10,000 pounds ile sınırlar. Bu tekerlek başına üst sınır, tek ve tandem aks limitlerini tamamlar. Kaynak: Wyoming Highway Patrol Ticari Taşıyıcı ağırlık limitleri; W.S. 31-18-805."},"6":{"q":"Wyoming'de, çekici-yarı römork veya tanınan ikili kombinasyon dışındaki bir araç kombinasyonu için izin verilen maksimum toplam uzunluk nedir?","options":["75 feet","81 feet","85 feet","97 feet"],"explanation":"Diğer herhangi bir araç kombinasyonu için Wyoming, 85 feet toplam uzunluk limiti belirler. Kaynak: W.S. 31-18-802 Genel Gereklilikler."},"7":{"q":"İki römorklu bir Wyoming çekicisinde, çekilen birimlerin (bağlantı mekanizmaları dahil) toplam uzunluğu neyi aşamaz?","options":["75 feet","81 feet","85 feet","88 feet"],"explanation":"Wyoming, yarı römork ve römorkun (veya iki yarı römorkun) bağlantı mekanizmaları dahil toplam uzunluğunu 81 feet ile sınırlar; ilk römork en fazla 48 feet ve ikincisi en fazla 40 feet olabilir. Kaynak: W.S. 31-18-802."},"8":{"q":"Wyoming karayollarında izin olmadan bir üçlü aks grubu (üç ardışık aks) için izin verilen maksimum yasal ağırlık nedir?","options":["38,000 pounds","40,000 pounds","42,000 pounds","48,000 pounds"],"explanation":"Wyoming, fazla ağırlık izni gerekmeden önce bir üçlü (üç ardışık) aks grubunda 42,000 pounds'a kadar izin verir. Kaynak: W.S. 31-18-805; Wyoming Highway Patrol Ticari Taşıyıcı ağırlık limitleri."},"9":{"q":"Wyoming'de, tek römorklu bir kombinasyonda, ikinci römork veya ikinci yarı römork hangi uzunluğu aşamaz?","options":["28 feet","33 feet","40 feet","48 feet"],"explanation":"Wyoming, ikili bir kombinasyondaki römork veya ikinci yarı römorku (bağlantı mekanizması hariç) 40 feet ile sınırlar. Kaynak: W.S. 31-18-802 Genel Gereklilikler."},"10":{"q":"Wyoming'de uygulandığı şekliyle federal köprü formülü neyi belirlemek için kullanılır?","options":["Bir köprüden geçebilecek bir yükün maksimum genişliği","Aks sayısı ve aralığına dayalı olarak bir aks grubu üzerindeki izin verilen brüt ağırlık","Eyalet köprülerini geçen ağır kamyonlardan alınan geçiş ücreti","Eyaletler arası köprülerde gerekli minimum lastik basıncı"],"explanation":"Wyoming, aks sayısına (N) ve uçlar arasındaki mesafeye (L) dayalı olarak iki veya daha fazla ardışık akstan oluşan herhangi bir grup üzerindeki izin verilen brüt ağırlığı belirlemek için federal köprü formülünü (W = 500[LN/(N-1) + 12N + 36]) uygular. Kaynak: Wyoming ağırlık tabloları; W.S. 31-18-805."},"11":{"q":"Wyoming'in köprü-formülü ağırlık tablolarına göre, Tablo I (iç köprü formülü tablosu) tarafından Interstate sistemde izin verilebilen maksimum brüt ağırlık nedir?","options":["80,000 pounds","105,500 pounds","117,000 pounds","129,000 pounds"],"explanation":"Wyoming'in Tablo I'ini (tüm ardışık aks gruplarını kontrol eden iç köprü formülü) kullanarak, aks ve köprü limitleri karşılandığında Interstate, birincil ve ikincil karayollarında 117,000 pounds'a kadar brüt ağırlık taşınabilir. Kaynak: Wyoming Highway Patrol Ticari Taşıyıcı ağırlık tabloları; WYDOT."},"12":{"q":"Wyoming'de, bölünebilir bir yük fazla ağırlık izni olmadan ne zaman 80,000 pounds brüt ağırlığı aşabilir?","options":["Yalnızca Interstate karayollarında gündüz saatlerinde","Tüm aks ve köprü ağırlıklarında yasal olduğunda ve en azından o brüt ağırlık için tescilli/ruhsatlı olduğunda","Yalnızca yük tarımsalsa ve 50 mil içinde taşınıyorsa","Asla, çünkü 80,000 pounds'un üzerindeki herhangi bir yük her zaman izin gerektirir"],"explanation":"Wyoming, her aks ağırlığında ve köprü formülü altında yasal olması ve aracın en azından gerçek brüt ağırlığı için ruhsatlı (tescilli) olması koşuluyla, bölünebilir bir yükün eyalet ve Interstate karayollarında izin olmadan 80,000 pounds'u aşmasına izin verir. Kaynak: Wyoming Highway Patrol Ticari Taşıyıcı kuralları; WYDOT."},"13":{"q":"Bir taşıyıcı, Wyoming karayolunda 8 feet 6 inches'tan daha geniş bir yük taşımak istiyor. Önce ne yapmaları gerekir?","options":["Yük 10 feet genişlikten az olduğu sürece hiçbir şey","Karayolunda çalışmadan önce bir büyük boy izni (veya izin) almak","Sadece geceleri tehlike ışıklarıyla seyahat etmek","Lastik basıncını düşürmek ve yerel polise haber vermek"],"explanation":"Wyoming'de yasal boyut veya ağırlığı aşan herhangi bir araç veya yük, bir Wyoming eyalet karayolunda çalışmadan önce bir izin veya onay almalıdır. Kaynak: Wyoming Highway Patrol Ticari Taşıyıcı kuralları; WYDOT İzinlendirme."},"14":{"q":"Bir Giriş Noktasının (Port of Entry) veya karayolu atölyesinin verebileceği limitleri aşan fazla ağırlık/büyük boy izinlerini hangi Wyoming ofisi ele alır?","options":["Her seyahat ilçesindeki ilçe şerif ofisi","Cheyenne'deki Fazla Ağırlık Yükleri Ofisi (WYDOT)","Federal Karayolu İdaresi bölge ofisi","Wyoming Av ve Balıkçılık Departmanı"],"explanation":"Rutin Giriş Noktası/karayolu atölyesi eşiklerinin ötesindeki izinler, WYDOT'un Cheyenne'deki Fazla Ağırlık Yükleri Ofisi (307-777-4376) aracılığıyla verilir. Giriş noktaları ve karayolu atölyeleri bunun altındaki belirlenmiş limitlere kadar izin verebilir. Kaynak: Wyoming Highway Patrol Ticari Taşıyıcı; WYDOT."},"15":{"q":"Refakat gerektiren bir büyük boy yük için Wyoming'de izin verilen genel seyahat penceresi nedir?","options":["Yalnızca gece yarısından sabah 6:00'ya kadar","Gün doğumundan yarım saat önce gün batımından yarım saat sonraya kadar","Yalnızca Pazartesiden Cumaya, sabah 9:00'dan akşam 5:00'a kadar","Hiçbir kısıtlama olmaksızın günde 24 saat"],"explanation":"Wyoming'deki büyük boy hareketler genellikle gün doğumundan yarım saat önce gün batımından yarım saat sonraya kadar, hafta sonları dahil, gündüzle sınırlıdır; sınırlı gece seyahatine yalnızca uygun aydınlatmaya sahip daha dar yükler için Interstate'lerde izin verilir. Kaynak: WYDOT büyük boy izin koşulları."},"16":{"q":"Wyoming karayollarında herhangi bir araç kombinasyonunda izin verilen maksimum tekil araç sayısı nedir?","options":["İki","Üç","Dört","Beş"],"explanation":"Wyoming yasası, hiçbir araç kombinasyonunun üçten fazla tekil araçtan oluşamayacağını öngörür. Kaynak: W.S. 31-18-802 Genel Gereklilikler."},"17":{"q":"Wyoming'de, çekilen birimin GVWR'si 10,000 lbs'den fazla olduğu durumda, 26,001 lbs veya daha fazla brüt kombinasyon ağırlık derecesine (GCWR) sahip bir kombinasyon aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Wyoming, federal CDL sınıflandırmasını (49 CFR 383.91) takip eder: çekilen birim(ler)in GVWR'si 10,000 lbs'nin üzerinde olmak kaydıyla, Class A CDL, 26,001 lbs veya daha fazla GCWR'ye sahip herhangi bir araç kombinasyonunu kapsar. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.91."},"18":{"q":"Wyoming kurallarına göre, 26,001 lbs veya daha fazla GVWR'ye sahip tek bir araç (veya 10,000 lbs'yi geçmeyen bir birimi çeken böyle bir araç) hangi CDL sınıfını gerektirir?","options":["Class C","Class B","Class A","Class M"],"explanation":"Wyoming, federal tanımları kullanır: Class B CDL, 26,001 lbs veya daha fazla GVWR'ye sahip tek bir aracı veya GVWR'si 10,000 lbs'yi aşmayan bir birimi çeken böyle bir aracı kapsar. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.91."},"19":{"q":"Class A veya B ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya plakartlı tehlikeli madde taşıyan bir Wyoming aracı hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Wyoming, federal tanımı takip eder: Class C CDL, Class A veya B kriterlerini karşılamayan ancak ya 16 veya daha fazla kişi (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli maddeleri taşımak için kullanılan bir aracı kapsar. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.91."},"20":{"q":"Wyoming, sürücüye tank araçlarını kullanma yetkisi veren bir CDL üzerine hangi onay kodunu koyar?","options":["T","N","H","X"],"explanation":"Tank aracı onayı, federal onay kodlarıyla tutarlı olarak Wyoming'de N kodudur. (X kodu, birleşik tank/HazMat onayını belirtir.) Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.153."},"21":{"q":"Wyoming'de, ikili veya üçlü römork çekmek için hangi onay gereklidir?","options":["N onayı","P onayı","T onayı","S onayı"],"explanation":"Wyoming'de birden fazla römork çeken bir kombinasyonu kullanmak için T (İkili/Üçlü) onayı gereklidir. İkili/üçlü bilgi testini geçerek elde edilir. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.153."},"22":{"q":"Yalnızca EYALET İÇİ (eyalet sınırları içinde) ticari sürüşle sınırlı bir Wyoming CDL'si almak için minimum yaş nedir?","options":["16 yaşında","18 yaşında","19 yaşında","21 yaşında"],"explanation":"Wyoming, yalnızca eyalet içi çalışma için 18 yaşında CDL'ye izin verir; eyaletler arası çalışma 21 yaş gerektirir. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / W.S. Title 31 ve 49 CFR 391.11."},"23":{"q":"EYALETLER ARASI ticari sürüşe yetki veren bir Wyoming CDL'sine sahip olmak için minimum yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","23 yaşında"],"explanation":"Bir sürücünün eyaletler arası ticarette bir CMV kullanması için en az 21 yaşında olması gerekir; 18-20 yaş arası sürücüler Wyoming'de eyalet içi sürüşle sınırlıdır. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 391.11."},"24":{"q":"Wyoming'de CDL beceri (yol) testine girmeden önce, bir başvuru sahibinin Ticari Öğrenci İzni'ne (CLP) ne kadar süre sahip olması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Bir CLP, sahibinin CDL beceri testine girmeye hak kazanmasından önce verildikten sonra en az 14 gün boyunca tutulmalıdır. Bu federal bekleme süresi Wyoming'de geçerlidir. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.25."},"25":{"q":"Bir Wyoming CLP'si ile bir CMV kullanırken, izin sahibine her zaman o araç için geçerli bir CDL'ye sahip bir kişi eşlik etmelidir. Bu CDL sahibinin nerede bulunması gerekir?","options":["Doğrudan sürücünün arkasındaki koltukta","Aracın kabininin içinde herhangi bir yerde","CLP sahibinin yanında, ön yolcu koltuğunda","Ayrı bir araçta arkadan takip ederek"],"explanation":"Bir CLP sahibine her zaman, sürücünün yanındaki ön koltukta oturan ve doğrudan denetim sağlayan, uygun şekilde ruhsatlı bir CDL sahibi eşlik etmelidir. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.25."},"26":{"q":"İzin üzerinde N (tank) yetkisi olan bir Wyoming CLP sahibi tarafından kullanıldığında, bir tank aracına hangi kısıtlama uygulanır?","options":["Tank %50 kapasiteye kadar doldurulabilir","Tank boş olmalıdır (sıvı veya gaz yük olmadan)","Yalnızca su taşınabilir","CLP ile hiçbir tank operasyonuna izin verilmez"],"explanation":"Tank (N) yetkisine sahip bir CLP sahibi yalnızca tüm sıvı veya gaz yükten boş bir tank aracını kullanabilir; CDL verilene kadar dolu tanklar yasaktır. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.25."},"27":{"q":"Wyoming'de, CDL veya kapsanan onay testinden önce gerekli Giriş Seviyesi Sürücü Eğitimi'ni (ELDT) tamamlamak için bir sürücünün hangi federal veritabanını kullanması gerekir?","options":["National Driver Register","FMCSA Eğitim Sağlayıcı Sicili (TPR)","Wyoming WYDOT eDriver portalı","CDLIS clearinghouse"],"explanation":"ELDT, eyaletin doğrulaması için eğitilenin tamamlamasını kaydeden FMCSA Eğitim Sağlayıcı Sicili'nde (TPR) listelenen bir sağlayıcı ile tamamlanmalıdır. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / FMCSA ELDT kuralı, 49 CFR Part 380."},"28":{"q":"Wyoming'de hangi başvuru sahiplerinin testten önce ELDT'yi tamamlaması gerekir?","options":["Yalnızca 21 yaşın altındaki sürücüler","İlk kez Class A veya B başvuranlar, Class B'den A'ya yükseltmeler ve ilk kez P, S veya H onayı başvuranları","Yalnızca HazMat (H) onayı başvuranları","Tüm CDL yenileme başvuranları"],"explanation":"Federal ELDT (7 Şubat 2022'de yürürlüğe girdi) ilk kez Class A/B başvuranlarına, Class B'den Class A'ya yükselten sürücülere ve P, S veya H onayları için ilk kez başvuranlara uygulanır. Geriye dönük değildir. Kaynak: FMCSA ELDT kuralı, 49 CFR Part 380 / WYDOT."},"29":{"q":"Bilgi testini geçmenin ötesinde, Wyoming bir HazMat (H) onayı için ne gerektirir?","options":["Parmak izi alımı dahil bir TSA güvenlik tehdit değerlendirmesi","Ayrı bir Wyoming Highway Patrol görüşmesi","İkinci bir fiziksel muayene","Noter onaylı bir işveren sponsorluk mektubu"],"explanation":"Wyoming, H onayı için başvuranlardan, HazMat bilgi testi ve ELDT teori eğitimine ek olarak, parmak izi alımı ve cezai/göçmenlik geçmiş kontrolünü içeren bir Ulaştırma Güvenliği İdaresi (TSA) güvenlik tehdit değerlendirmesini geçmelerini ister. Kaynak: WYDOT Tehlikeli Maddeler Değerlendirme sayfası / 49 CFR 1572."},"30":{"q":"Bir Wyoming sürücüsü, HazMat (H) onayını korumak için TSA güvenlik tehdit değerlendirmesini ne sıklıkla yenilemelidir?","options":["Her yıl","Her 2 yılda bir","Her 5 yılda bir","Her 8 yılda bir"],"explanation":"HazMat onayı için TSA güvenlik tehdit değerlendirmesi beş yıl geçerlidir ve H onayını korumak için (yeni bir geçmiş kontrolü ve bilgi testi ile) yenilenmelidir; posta yoluyla yenilenemez. Kaynak: WYDOT Tehlikeli Maddeler Değerlendirme sayfası / 49 CFR 1572."},"31":{"q":"Wyoming'de, bir sürücünün S (Okul Otobüsü) onayına sahip olabilmesi için önce hangi diğer onayın da alınması gerekir?","options":["H (HazMat)","N (Tank)","P (Yolcu)","T (İkili/Üçlü)"],"explanation":"S (Okul Otobüsü) onayı, bir okul otobüsü yolcu taşıyan bir araç olduğundan, sürücünün önce P (Yolcu) onayına hak kazanmasını gerektirir. Hem bilgi hem de beceri testi geçerlidir. Kaynak: Wyoming CDL Kılavuzu (WYDOT) / 49 CFR 383.123."},"32":{"q":"Bir Wyoming CDL başvuru sahibi, veren kuruma (WYDOT Sürücü Hizmetleri) hangi belge setini sunmalıdır?","options":["Yalnızca güncel bir Wyoming fotoğraflı sürücü belgesi","Kimlik/yasal varlık kanıtı, Sosyal Güvenlik numarası ve Wyoming ikameti","Yalnızca bir pasaport ve bir işveren mektubu","Bir doğum belgesi ve bir araç ruhsatı"],"explanation":"Wyoming, CDL başvuranlarından kimliklerini ve ABD'deki yasal varlıklarını kanıtlamalarını, bir Sosyal Güvenlik numarası vermelerini ve Wyoming ikamet kanıtını (genellikle iki belge) göstermelerini ister. Kaynak: WYDOT Sürücü Hizmetleri belge gereklilikleri."},"33":{"q":"Wyoming CDL öz-sertifikasyonunda, eyalet sınırları boyunca çalışan ve federal fiziksel yeterlilikten MUAF OLMAYAN bir sürücü hangi kategoriyi seçmelidir?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Eyaletler arası ticarette federal tıbbi kurallardan muaf olmayan bir sürücü, Non-Excepted Interstate (NI) olarak öz-sertifikasyon yapar ve dosyada geçerli bir DOT tıbbi muayene sertifikası bulundurmalıdır. Kaynak: WYDOT CDL öz-sertifikasyon / 49 CFR 383.71."},"34":{"q":"Hangi Wyoming CDL öz-sertifikasyon kategorisi, sürücünün federal (DOT) tıbbi muayene sertifikası bulundurmasını GEREKTİRMEZ?","options":["Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Interstate (EI)","Hem NI hem de NA"],"explanation":"Excepted Interstate (EI) ve Excepted Intrastate (EA) sürücüleri bir DOT tıbbi kartı bulundurmaktan muaftır; yalnızca Non-Excepted sürücüler (NI ve NA) güncel bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: WYDOT CDL öz-sertifikasyon / 49 CFR 383.71 ve 390.3."},"35":{"q":"Wyoming'de bir sürücünün ticari motorlu araç (CMV) kullanabileceği yasal maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"Wyoming, federal CMV standardını takip eder: 0.04 percent veya daha fazla BAC ile bir CMV kullanmak yasa dışıdır; bu, normal sürücüler için 0.08 limitinin yarısıdır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"36":{"q":"Wyoming'in zımni rıza yasasına göre, eyalette bir araç kullanarak veya bir aracın fiili fiziksel kontrolünde olarak, bir sürücü neye rıza göstermiş sayılır?","options":["Yasal olarak talep edildiğinde kan, nefes veya idrarın kimyasal testi","Herhangi bir kontrol noktasında araç araması","Herhangi bir durdurmadan sonra zorunlu uyuşturucu tedavisi","Reddedilemeyen bir saha ayıklık testi"],"explanation":"Wyoming'in zımni rıza yasası, eyalette bir araç kullanan veya bir aracın fiili fiziksel kontrolünde olan herkesin, bir memur tarafından yasal olarak talep edildiğinde kan, nefes veya idrarın kimyasal testine otomatik olarak rıza gösterdiğini öngörür. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-6-102 (zımni rıza)."},"37":{"q":"0.04 veya daha yüksek BAC ile bir CMV kullanmak gibi ilk büyük (zorunlu) suç için, bir Wyoming CDL sahibi ne kadar süre diskalifiye edilir (HazMat dışı)?","options":["1 yıl","6 ay","90 gün","3 yıl"],"explanation":"Bir büyük suç için ilk mahkumiyet, Wyoming'de 1 yıllık CDL diskalifikasyonuyla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"38":{"q":"Bir sürücü, tehlikeli maddeler için plakartlı bir CMV kullanırken ilk büyük suçu işlerse, Wyoming diskalifikasyon süresi neye yükselir?","options":["3 yıl","2 yıl","18 ay","5 yıl"],"explanation":"Plakartlı tehlikeli maddeler taşınırken işlenen ilk büyük suç, diskalifikasyonu 1 yıldan 3 yıla çıkarır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"39":{"q":"İkinci bir büyük (zorunlu) suç için Wyoming CDL diskalifikasyon süresi nedir?","options":["Ömür boyu","10 yıl","5 yıl","3 yıl"],"explanation":"Herhangi bir büyük suç için ikinci mahkumiyet, ömür boyu CDL diskalifikasyonuyla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"40":{"q":"Bir Wyoming CDL sahibi, bir CMV kullanırken yasal olarak talep edilen bir kimyasal testi reddediyor. Bu reddetme için minimum diskalifikasyon süresi nedir?","options":["1 yıl","90 gün","6 ay","60 gün"],"explanation":"Gerekli kimyasal testi reddetmek büyük bir suç olarak değerlendirilir ve en az 1 yıllık diskalifikasyonla sonuçlanır (HazMat için plakartlıysa 3 yıl). Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"41":{"q":"Aşağıdakilerden hangisi bir Wyoming CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Limitin 15 mph veya daha fazla üzerinde hız yapmak","Limitin 5 mph üzerinde hız yapmak","Bir park ihlali","Süresi dolmuş bir tescil etiketi"],"explanation":"Ciddi trafik ihlalleri arasında limitin 15 mph veya daha fazla üzerinde hız yapmak, dikkatsiz sürüş, çok yakın takip, düzensiz/uygunsuz şerit değiştirme ve bir CMV kullanırken mesaj yazma veya elde telefon kullanma yer alır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"42":{"q":"Bir Wyoming CDL sahibi, 3 yıllık bir süre içinde ayrı olaylardan kaynaklanan iki ciddi trafik ihlalinden mahkum oluyor. Diskalifikasyon nedir?","options":["60 gün","30 gün","120 gün","90 gün"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, 60 günlük diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"43":{"q":"Bir Wyoming CDL sahibi, 3 yıllık bir süre içinde ayrı olaylardan üç ciddi trafik ihlali için ne kadar süre diskalifiye edilir?","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, 120 günlük diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"44":{"q":"Wyoming'de bir CMV kullanırken her demiryolu-karayolu hemzemin geçidinde DURMAK zorunda olan onay sahipleri hangileridir?","options":["Yolcu ve tehlikeli madde (plakartlı) araç sürücüleri","Yalnızca tanker onayı olan sürücüler","İstisnasız tüm CMV sürücüleri","Yalnızca 21 yaşın altındaki okul otobüsü sürücüleri"],"explanation":"Yolcu veya plakartlı tehlikeli madde taşıyan sürücüler tüm demiryolu geçitlerinde durmalıdır; diğer CMV'ler yavaşlamalı ve kontrol etmelidir. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 392.10 / 383.51."},"45":{"q":"Bir CMV'de İLK demiryolu-karayolu hemzemin geçit ihlali için minimum Wyoming diskalifikasyonu nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu geçit ihlali, 60 günden az olmamak üzere diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51 Table 3."},"46":{"q":"Bir sürücü, 3 yıl içinde İKİNCİ bir demiryolu-hemzemin geçit ihlali işliyor. Minimum diskalifikasyon nedir?","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu geçit ihlali, 120 günden az olmamak üzere diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51 Table 3."},"47":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-hemzemin geçit ihlali için minimum diskalifikasyon nedir?","options":["1 yıl","120 gün","60 gün","Ömür boyu"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu geçit ihlali, 1 yıldan az olmamak üzere diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51 Table 3."},"48":{"q":"Bir CDL sürücüsünün, bir CMV kullanırken bir hizmet dışı (OOS) emrini ihlal etmekten İLK mahkumiyeti için minimum diskalifikasyon nedir?","options":["180 gün ila 1 yıl","30 ila 60 gün","2 ila 5 yıl","60 ila 120 gün"],"explanation":"İlk OOS-emri ihlali, 180 günden az ve 1 yıldan fazla olmamak üzere bir diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51 Table 4."},"49":{"q":"10 yıllık bir süre içinde İKİNCİ bir hizmet dışı emir ihlali için diskalifikasyon aralığı nedir (HazMat dışı/yolcu dışı)?","options":["2 ila 5 yıl","180 gün ila 1 yıl","1 ila 2 yıl","3 ila 5 yıl"],"explanation":"10 yıl içinde ikinci bir OOS-emri ihlali, 2 yıldan az ve 5 yıldan fazla olmamak üzere diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51 Table 4."},"50":{"q":"Plakartlı tehlikeli madde veya 16 ya da daha fazla yolcu taşıyan bir sürücü, İLK bir hizmet dışı emir ihlali işliyor. Diskalifikasyon aralığı nedir?","options":["180 gün ila 2 yıl","60 ila 120 gün","1 ila 3 yıl","3 ila 5 yıl"],"explanation":"Plakartlı HazMat taşırken veya 16+ yolcu taşırken işlenen ilk OOS-emri ihlali, 180 günden az ve 2 yıldan fazla olmamak üzere diskalifikasyonla sonuçlanır. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51 Table 4."},"51":{"q":"Wyoming'de bir CMV kullanırken mesaj yazmak veya elde mobil telefon kullanmak ne tür bir CDL ihlali olarak değerlendirilir?","options":["60/120 günlük diskalifikasyona doğru sayılan ciddi bir trafik ihlali","Bildirilmesi gerekmeyen küçük bir kabahat","Otomatik ömür boyu diskalifikasyon","Bir demiryolu geçit ihlali"],"explanation":"Bir CMV kullanırken mesaj yazma ve elde telefon kullanma ciddi trafik ihlalleridir; 3 yıl içinde iki tanesi 60 günlük, üç tanesi 120 günlük diskalifikasyon getirir. Kaynak: Wyoming CDL Kılavuzu; 49 CFR 383.51; 49 CFR 392.80/392.82."},"52":{"q":"Wyoming'deki bir CMV sürücüsünün tek bir mesaj-yazma-veya-elde-telefon-kullanma-sırasında-sürüş suçu için karşılaşabileceği maksimum federal sivil para cezası nedir?","options":["$2,750'ye kadar","$250'ye kadar","$11,000'e kadar","$500'e kadar"],"explanation":"Bir CMV sürücüsüne mesaj yazma/elde telefon suçu başına $2,750'ye kadar ceza verilebilir; buna izin verdiği için işveren motorlu taşıyıcıya $11,000'e kadar ceza verilebilir. Kaynak: FMCSA Mobil Telefon / Mesaj Yazmama kuralları; Wyoming'de geçerli 49 CFR 392.80-392.82."},"53":{"q":"Ömür boyu CDL diskalifikasyonundan sonra, bir Wyoming sürücüsü sınırlı yeniden onay hükmü kapsamında yeniden onay için başvurmaya ne zaman (eğer mümkünse) hak kazanabilir?","options":["En az 10 yıl sonra, koşullarla (HazMat uygunsuz kalır)","5 yıl sonra otomatik olarak","Hiçbir koşulda asla","Temiz bir sicille 3 yıl sonra"],"explanation":"Ömür boyu diskalifiye edilen bir sürücü, en az 10 yıl sonra ve yeniden onay koşullarını karşılayarak, yeniden onay için değerlendirilebilir; HazMat uygunluğu geri verilmez. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"54":{"q":"DUI veya bir suç işlemek için bir aracı kullanmak gibi diskalifiye edici büyük suçlar, suç ne tür bir araçta gerçekleşse bile bir Wyoming CDL sahibine uygulanır?","options":["Sürücünün kişisel arabası dahil herhangi bir motorlu araç","Yalnızca plakartlı bir HazMat CMV","Yalnızca işveren tarafından sahip olunan bir araç","Yalnızca 26,001 lbs GVWR üzerindeki bir araç"],"explanation":"DUI gibi büyük suçlar, araç tipinden bağımsız olarak CDL'ye karşı sayılır; kişisel arabasında DUI'den mahkum olan bir CDL sahibi yine de diskalifiye edilir. Kaynak: Wyoming CDL Kılavuzu; W.S. 31-7-305; 49 CFR 383.51."},"55":{"q":"Wyoming'de plakartlı tehlikeli madde taşıyan bir CDL sürücüsü, demiryolu-karayolu hemzemin geçidine yaklaşır. Araç nerede durmalıdır?","options":["En yakın raya 5 feet'ten daha yakın olmamak ve 25 feet'ten daha uzak olmamak üzere","En yakın raya 50 feet'ten daha yakın olmamak ve 100 feet'ten daha uzak olmamak üzere","En yakın raya en az 10 feet ama en fazla 30 feet mesafede","En yakın raya 15 feet'ten daha yakın olmamak ve 50 feet'ten daha uzak olmamak üzere"],"explanation":"Wyoming kuralı: Tehlikeli maddeler için plakartlı olan (veya herhangi bir miktarda klor taşıyan ya da yüklü/boş HazMat kargo tankları bulunan) bir araç, en yakın raydan 15 ile 50 feet arasında durmalı ve yalnızca yaklaşan bir tren olmadığında ilerlemelidir. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 9 - Tehlikeli Maddeler, demiryolu geçidi hükmü."},"56":{"q":"Yolcu taşıyan bir Wyoming otobüs sürücüsü, bir demiryolu geçidinde durmak zorundadır. Geçit öncesi gereken durma bölgesi nedir?","options":["Geçitten önce 20 ile 60 feet arasında","Geçitten önce 15 ile 50 feet arasında","Geçitten önce 10 ile 40 feet arasında","Geçitten önce 25 ile 75 feet arasında"],"explanation":"Wyoming kuralı: Otobüs sürücüleri, demiryolu geçitlerinden önce otobüsü 15 ile 50 feet arasında durdurmalı, ardından geçmeden önce her iki yönde de trenleri görmek ve duymak için bakıp dinlemelidir. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 4 - Yolcu Taşıma (Demiryolu-Karayolu Geçitleri ve Duraklar)."},"57":{"q":"Wyoming'in Move Over (Şerit Değiştir) yasası kapsamında, kendi yönünde iki veya daha fazla şeridi olan bir eyaletler arası veya başka bir karayolundaki bir CDL sürücüsü, görsel sinyaller gösteren durmuş bir acil durum aracına yaklaşır. Sürücünün, güvenli olduğunda, ne yapması gerekir?","options":["Acil durum aracı ayrılana kadar tamamen durmak","Korna çalmak ve aynı şeritte ilan edilen hızda devam etmek","Acil durum aracının yanında olmayan bir şeride (ondan en uzak şeride) geçmek","Sağ banket üzerine çekmek ve bir memurun el sallayarak geçmesine izin vermesini beklemek"],"explanation":"Wyoming kuralı: Seyahat yönünde iki veya daha fazla şeridi olan bir karayolunda, görsel sinyaller kullanan durmuş yetkili bir acil durum aracına yaklaşan bir sürücü, güvenli olduğunda o araca bitişik olmayan bir şeride (en uzaktaki şeride) geçmelidir; şerit değiştirmek güvenli değilse, yavaşlamalı ve dikkatle ilerlemelidir. Kaynak: Wyoming Statute 31-5-224; 2024 Wyoming CDL Manual (Move-Over Yasaları)."},"58":{"q":"Wyoming'in Move Over yasası kapsamında, 45 mph veya daha yüksek hızla ilan edilmiş İKİ ŞERİTLİ bir yolda, durmuş bir acil durum veya çekici aracını geçen ve güvenli bir şekilde şerit değiştiremeyen bir sürücü, hızını hangi seviyeye düşürmelidir?","options":["İlan edilen hız sınırından 20 mph daha az","İlan edilen hız sınırından 10 mph daha az","İlan edilen hız sınırından 15 mph daha az","İlan edilen sınırdan bağımsız olarak tam 25 mph"],"explanation":"Wyoming kuralı: İlan edilen hız sınırı 45 mph veya daha yüksek olan iki şeritli bir yolda, sürücü görsel sinyaller kullanan durmuş bir acil durum, kamu hizmeti, bakım veya çekici aracını geçerken hızını ilan edilen hız sınırından 20 mph daha az olacak şekilde düşürmelidir. Kaynak: Wyoming Statute 31-5-224."},"59":{"q":"Wyoming'in Move Over yasası (W.S. 31-5-224) sadece polis ve ambulanslardan fazlasını korur. Bunlardan hangisi de açıkça kapsam dahilindedir?","options":["Tehlike uyarı lambaları açık olarak bankette park edilmiş herhangi bir binek otomobil","Arızalı araç olay yerinde, yanıp sönen kırmızı veya kırmızı-mavi lamba gösteren bir kurtarıcı veya çekici kamyon","Çocukları bindirmek için durmuş bir okul otobüsü","Bir şehir caddesinde çift sıra park etmiş bir teslimat kamyonu"],"explanation":"Wyoming kuralı: Move Over yasası, yetkili acil durum araçlarını, belediye/kamu hizmeti/karayolu inşaat veya bakım araçlarını ve hasar görmüş, arızalı veya durmuş bir aracın olay yerinde ön ve arkadan 500 feet görünür en az bir yanıp sönen kırmızı veya kırmızı-mavi lamba ile donatılmış kurtarıcı veya çekici kamyonları kapsar. Kaynak: Wyoming Statute 31-5-224."},"60":{"q":"İki şeritli, iki yönlü bir Wyoming karayolunda, bir okul otobüsü kırmızı ışıkları yanıp sönerek ve dur kolu açık olarak durur. KARŞI yönden gelen yaklaşan bir CDL sürücüsü ne yapmalıdır?","options":["15 mph'e yavaşlamak ve dikkatle geçmek","Otobüse ulaşmadan önce durmak ve ışıklar yanıp sönmeyi bırakana veya otobüs hareket edene kadar durmuş kalmak","İlan edilen hızda devam etmek, çünkü karşıdan gelen trafik muaftır","Yalnızca çocuklar gözle görülür şekilde yoldan geçiyorsa durmak"],"explanation":"Wyoming kuralı: Yanıp sönen kırmızı ışıklar gösteren durmuş bir okul otobüsüyle her iki yönden karşılaşıldığında veya geçildiğinde, sürücü otobüse ulaşmadan önce durmalı ve otobüs hareket edene veya kırmızı ışıklar artık yanıp sönmeyene kadar ilerlememelidir. Kaynak: Wyoming Statute 31-5-507."},"61":{"q":"Wyoming'in okul otobüsü durma yasasının bölünmüş karayolu istisnası vardır. Bir sürücü, yanıp sönen kırmızı ışıklar gösteren bir okul otobüsü için ne zaman durmak zorunda DEĞİLDİR?","options":["Yalnızca seyahat yönleri arasında boyalı bir orta çizgi olduğunda","Sürücü otobüsten iki şeritten fazla uzakta olduğunda","Yolun ilan edilen hız sınırı 55 mph'nin üzerinde olduğunda","Otobüs, ayrı taşıt yolları olan bir karayolunun farklı bir taşıt yolunda olduğunda"],"explanation":"Wyoming kuralı: Ayrı taşıt yolları olan bir karayolundaki bir sürücü, FARKLI bir taşıt yolunda olan bir okul otobüsüyle karşılaştığında veya geçtiğinde ya da kontrollü erişimli bir karayolunda olup otobüs yayaların geçmesine izin verilmeyen bir bindirme bölgesinde durduğunda durmak zorunda değildir. Tek başına boyalı bir çizgi bu istisna için geçerli değildir. Kaynak: Wyoming Statute 31-5-507."},"62":{"q":"Bir Wyoming CDL sürücüsü, aracı tek yönlü veya bölünmüş bir karayolunun banketinde durdurmak zorundadır. Acil durum uyarı cihazları ne kadar süre içinde ve nereye yerleştirilmelidir?","options":["30 dakika içinde, yaklaşan trafiğe doğru 25 feet, 100 feet ve 250 feet'te","10 dakika içinde, yaklaşan trafiğe doğru 50 feet, 150 feet ve 300 feet'te","10 dakika içinde, yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'te","5 dakika içinde, yaklaşan trafiğe doğru 10 feet, 50 feet ve 100 feet'te"],"explanation":"Wyoming kuralı: Tek yönlü veya bölünmüş bir karayolu üzerinde ya da yanında durursanız, uyarı cihazlarını 10 dakika içinde araçtan yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafede yerleştirin. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 2 - Güvenli Sürüş (durmuş araçlar için uyarı cihazları)."},"63":{"q":"Bir Wyoming CDL sürücüsü, her iki yönde de trafik taşıyan iki şeritli bir yolda durur. Üç reflektörlü üçgen nasıl yerleştirilmelidir?","options":["10 feet, 100 feet ve 200 feet içinde, hepsi yalnızca aracın arkasında","Yalnızca aracın önünde 25 feet, 100 feet ve 200 feet'te","Aracın 10 feet içinde, ayrıca aracın 100 feet arkasında ve 100 feet önünde","Aracın arkasına doğru 10 feet, 50 feet ve 150 feet içinde"],"explanation":"Wyoming kuralı: Her iki yönde de trafik taşıyan iki şeritli bir yolda (veya bölünmemiş bir karayolunda), uyarı cihazlarını aracı işaretlemek için ön veya arka köşelerin 10 feet içine ve aracın 100 feet arkasına ve 100 feet önüne yerleştirin. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 2 - Güvenli Sürüş."},"64":{"q":"Bir tepe veya viraj, bir Wyoming yolunda durmuş bir CDL aracının görüşünü engelliyorsa, kılavuz en arkadaki uyarı üçgeni ile ne yapılması gerektiğini söyler?","options":["Engelin ötesinde uyarı sağlanacak şekilde yol boyunca daha geriye, 500 feet'e kadar taşıyın","Tüm üçgenleri standart 10/100/200 feet aralıkta bırakın","Maksimum görünürlük için doğrudan engelin üzerine yerleştirin","Tamamen çıkarın ve yalnızca dörtlü flaşörlere güvenin"],"explanation":"Wyoming kuralı: Görüş hattı bir tepe, viraj veya başka bir engel tarafından engelleniyorsa, uygun uyarı sağlamak için en arkadaki üçgeni yol boyunca geriye (aracın 500 feet içinde görülebileceği şekilde engelin ötesine geriye) taşıyın. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 2 - Güvenli Sürüş."},"65":{"q":"80 mph olarak ilan edilen Wyoming'in kırsal eyaletler arası karayollarında, hız sınırı bir çekici-römork için bir binek otomobile kıyasla nasıl uygulanır?","options":["Kamyonlar 70 mph ile sınırlıyken otomobiller 80 mph'e gidebilir","Kamyonlar ve otomobiller aynı 80 mph maksimumu paylaşır; Wyoming ayrı bir daha düşük kamyon sınırı belirlemez","Kamyonlar 65 mph ile sınırlıyken otomobiller 80 mph'e gidebilir","Kamyonlar 75 mph ile sınırlıyken otomobiller 80 mph'e gidebilir"],"explanation":"Wyoming kuralı: Wyoming'in maksimum eyaletler arası hız sınırı (belirlenmiş kırsal kesimlerde 80 mph'e kadar) ticari kamyonlar ve binek otomobiller için eşit olarak uygulanır. Bazı eyaletlerden farklı olarak, Wyoming ayrı, daha düşük bir yasal kamyon hız sınırı belirlemez. Kaynak: Wyoming Statute 31-5-301; WYDOT 80 mph koridor tanımlamaları."},"66":{"q":"Wyoming, I-80'in dağlık kesimlerinde kademeli bir zincir yasasını devreye sokar. Daha şiddetli LEVEL 2 (son derece tehlikeli) altında, ticari bir araç neye güvenebilir?","options":["Sadece çekiş aksında kar lastikleri","Standart karayolu lastikleriyle önden çekiş","Lastik zincirleri veya M+S ya da her mevsim dereceli lastiklerle donatılmış AWD (tek başına kar lastikleri yeterli değildir)","Yalnızca düşürülmüş hız, ekipman gereksinimi olmadan"],"explanation":"Wyoming kuralı: Level 1 altında bir CMV zincir, yeterli kar lastiği veya AWD kullanabilir; Level 2 (son derece tehlikeli) altında tek başına kar lastikleri yetersizdir ve araç lastik zincirleri ya da M+S veya her mevsim dereceli lastiklerle donatılmış AWD kullanmalıdır. Kaynak: WYDOT Wyoming zincir yasası seviyeleri (genellikle I-80 'Three Sisters' kesiminde uygulanır)."},"67":{"q":"Aşırı kuvvetli rüzgar olayı sırasında Wyoming, I-80 ve I-25'in bölümlerini önce hangi araçlara kapatır?","options":["Yalnızca binek otomobiller ve motosikletler","Hafif, yüksek profilli ticari araçlar (boş veya hafif yüklü vanlar gibi)","Yalnızca sıvı taşıyan tamamen yüklü tankerler","Yalnızca yolcu taşıyan otobüsler"],"explanation":"Wyoming kuralı: Sık görülen devrilme kazaları nedeniyle, WYDOT I-80 ve I-25'in bölümlerini hafif, yüksek profilli araçlara (ve en kötü koşullarda tüm ticari araçlara) kısıtlar ve kapatır. Kapanmalar wyoroad.info / Wyoming 511 üzerinde ilan edilir. Kaynak: WYDOT kuvvetli rüzgar / devrilme kısıtlamaları."},"68":{"q":"Bir ticari aracın, gabari fazlası izni OLMADAN Wyoming karayollarında seyahat edebileceği maksimum genişlik nedir?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"Wyoming kuralı: İzin olmadan yasal maksimum araç genişliği 8 feet 6 inches'tir (102 inches); daha geniş olan herhangi bir şey WYDOT'tan bir gabari fazlası izni gerektirir. Kaynak: Wyoming Statute 31-18-802 / WYDOT gabari fazlası izin düzenlemeleri."},"69":{"q":"İzin olmadan, Wyoming karayollarında maksimum yasal araç YÜKSEKLİĞİ nedir?","options":["14 feet","13 feet 6 inches","13 feet","15 feet"],"explanation":"Wyoming kuralı: İzin olmadan yasal maksimum araç yüksekliği 14 feet'tir; bunu aşan yükler bir gabari fazlası izni gerektirir. Kaynak: Wyoming Statute 31-18-802 / WYDOT gabari fazlası düzenlemeleri."},"70":{"q":"Bir Wyoming taşıyıcısı, bir gabari genişliği aşan taşıma için WYDOT'tan tek seferlik bir gabari fazlası iznine ihtiyaç duyar. Temel tek seferlik gabari fazlası izin ücreti nedir?","options":["$10.00","$50.00","$100.00","$25.00"],"explanation":"Wyoming kuralı: Tek seferlik bir gabari fazlası izninin ücreti $25.00'dır; 15 feet genişlik, 15 feet yükseklik veya 75 feet uzunluğu aşan yükler için ek mesafe bazlı ücretler uygulanır. Kaynak: Wyoming Statute 31-18-804 / WYDOT gabari fazlası izin ücret tarifesi."},"71":{"q":"Bir Wyoming çekici-yarı römork kombinasyonunda, izin olmadan yarı römorkun kendisi için izin verilen maksimum uzunluk nedir?","options":["60 feet","48 feet","53 feet","57 feet"],"explanation":"Wyoming kuralı: Bir kamyon-çekici yarı römork kombinasyonunda, yarı römork uzunlukta 60 feet'i aşamaz (Wyoming, dikkat çekici şekilde, yaygın 53 feet römorktan daha uzun tek bir yarı römorka izin verir). Kaynak: Wyoming Statute 31-18-802 (boyut ve ağırlık sınırları)."},"72":{"q":"Wyoming'de bir dizi demiryolu rayını geçerken, CDL kılavuzu manuel şanzımanlı bir CMV sürücüsüne ne yapmasını talimat verir?","options":["Aracın herhangi bir kısmı raylar üzerindeyken vites değiştirmeyin","Maksimum çekiş için yarı yolda en düşük vitese düşürün","Boşa alıp rayların üzerinden kayarak geçin","Rayları mümkün olduğunca hızlı geçmek için bir vites yükseltin"],"explanation":"Wyoming kuralı: Kılavuz, demiryolu raylarını geçerken vites değiştirmemenizi yönlendirir, çünkü vites değiştirmek raylar üzerinde stop etme riski taşır; başlamadan önce sizi tamamen karşıya geçirecek bir vites seçin. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), Bölüm 2.15 - Demiryolu/Karayolu Geçitleri."},"73":{"q":"Wyoming'de bir demiryolu geçidine yaklaşırken, bir okul otobüsü, yolcu otobüsü veya plakartlı araç, raylara yaklaşırken ışıklarıyla hangi eylemi gerçekleştirmelidir?","options":["Tren ekiplerini şaşırtmamak için tüm dış ışıkları kapatmak","Karşıya geçene kadar uzun farları sürekli olarak yakıp söndürmek","En yakın rayın yönünde sinyal lambasını yakmak","Yaklaşırken dörtlü (tehlike) flaşörleri etkinleştirmek ve rayları geçtikten sonra kapatmak"],"explanation":"Wyoming kuralı: Bir otobüs, okul otobüsü veya plakartlı araç, geçide yaklaşırken dörtlü flaşörleri etkinleştirmeli, en yakın raydan 50 feet içinde ama 15 feet'ten az olmamak üzere durmalı, bakıp dinlemeli, ardından geçtikten sonra flaşörleri kapatmalıdır. Kaynak: 2024 Wyoming Commercial Driver License Manual (WYDOT), demiryolu geçidi yol sınavı prosedürleri."},"74":{"q":"Hangi Wyoming kurumu, eyalette sürüş kayıtlarını yönetir ve tüm sınıflardaki ticari sürücü belgelerini (CDL'ler) düzenler?","options":["Wyoming Department of Transportation (WYDOT), Driver Services Program","Bağımsız bir kurum olan Wyoming Department of Motor Vehicles","Wyoming Highway Patrol, Ruhsat Bölümü","Başvuru sahibinin ikamet ettiği ilçedeki ilçe kâtibi ofisi"],"explanation":"Wyoming'de, WYDOT'un Driver Services Program'ı sürüş kayıt sistemini yönetir ve tüm sınıflardaki sürücü ve ticari sürücü belgelerini sınar, düzenler ve işler. Wyoming'in ayrı bir 'DMV' kurumu yoktur. Kaynak: WYDOT Driver Services / Commercial License sayfası."},"75":{"q":"WYDOT bir CDL beceri sınavı uygulayabilmeden önce, ilk Class A veya Class B CDL için giriş seviyesi bir başvuru sahibi hangi gereksinimi tamamlamalıdır?","options":["FMCSA Training Provider Registry'de yer alan bir sağlayıcıdan Entry-Level Driver Training (ELDT)","Wyoming Highway Patrol tarafından onaylanmış 40 saatlik bir savunmacı sürüş kursu","İki yıllık belgelenmiş eyalet içi sürüş deneyimi","WYDOT tarafından uygulanan bir tıbbi yeterlilik değerlendirmesi"],"explanation":"Wyoming'de uygulanan federal ELDT kuralları, giriş seviyesi sürücülerin beceri sınavına girmeden önce FMCSA Training Provider Registry'de (TPR) listelenmiş bir sağlayıcıdan teorik ve direksiyon başı eğitimi tamamlamasını gerektirir. WYDOT, CDL beceri sınavlarının yalnızca ELDT'yi tamamlamış veya bir grandfather muafiyetine sahip olanlara verilebileceğini belirtir. Kaynak: WYDOT CDL Testing sayfası; 49 CFR Part 380 Subpart F."},"76":{"q":"Wyoming CDL beceri sınavı, sırayla uygulanan hangi üç bölümden oluşur?","options":["Yola çıkış öncesi (araç) muayenesi, temel kontrol becerileri ve yolda sürüş","Yazılı bilgi sınavı, görme taraması ve yolda sürüş","Hava freni sınavı, bağlama sınavı ve gece sürüşü","Savunmacı sürüş, temel kontrol becerileri ve bir hazmat elleçleme gösterisi"],"explanation":"Wyoming'in CDL beceri sınavı, bir araç yola çıkış öncesi muayenesinden, bir temel kontrol becerileri sınavından ve bir yolda (on-road) sürüş sınavından oluşur. Kaynak: WYDOT CDL Testing sayfası; Wyoming tarafından benimsenen AAMVA CDL beceri standartları."},"77":{"q":"Bir Wyoming CDL başvuru sahibi, yaptığı ticari sürüş türünü beyan ederken hangi dört öz-sertifikasyon kategorisinden seçim yapmalıdır?","options":["Muaf olmayan eyaletler arası, muaf eyaletler arası, muaf olmayan eyalet içi, muaf eyalet içi","Yerel, bölgesel, uzun yol ve mevsimlik","Class A, Class B, Class C ve yalnızca onay","Kiralık, özel, tarımsal ve acil durum"],"explanation":"Wyoming, her CDL sahibinin dört kategoriden birine öz-sertifikasyon yapmasını gerektirir: muaf olmayan eyaletler arası (NI), muaf eyaletler arası (EI), muaf olmayan eyalet içi (NA) ve muaf eyalet içi (EA). Kaynak: WYDOT Driver Certification sayfası; 49 CFR 383.71(b)."},"78":{"q":"Wyoming'de uygulanan federal commercial learner's permit (CLP) kuralı kapsamında, bir başvuru sahibi CDL beceri sınavına girmesine izin verilmeden önce bir CLP'yi ne kadar süre tutmalıdır?","options":["En az 14 days","En az 30 days","En az 7 days","En az 60 days"],"explanation":"Bir Wyoming CLP sahibi, CDL beceri sınavına girmeden önce CLP düzenlendikten sonra en az 14 days beklemelidir. Kaynak: 49 CFR 383.25(a)(3), WYDOT Driver Services tarafından uygulanır."},"79":{"q":"Bir Wyoming CDL sahibi, kendisini 'muaf olmayan eyaletler arası' (NI) olarak öz-sertifiye eder. WYDOT'ta hangi ek belgeyi güncel tutmalıdır?","options":["National Registry'de kayıtlı bir muayene görevlisinden geçerli bir DOT medical examiner's certificate","FMCSA'dan yıllık bir eyaletler arası işletme yetkisi mektubu","Yalnızca eyalet içi işletmeye dair noter tasdikli bir beyanname","Wyoming tarafından düzenlenmiş bir tehlikeli madde geçmiş kontrolü onayı"],"explanation":"Kendilerini muaf olmayan eyaletler arası (NI) veya muaf olmayan eyalet içi (NA) olarak öz-sertifiye eden sürücüler tıbbi olarak yeterli olmalı ve güncel bir DOT medical certificate'i dosyada tutmalıdır. Muaf (EI/EA) sürücüler tutmaz. Muayene görevlisi FMCSA National Registry'de olmalıdır. Kaynak: WYDOT Driver Certification / DOT Medical Certificate sayfaları; 49 CFR 383.71(h)."},"80":{"q":"Bir Wyoming CDL sahibinin, gerekli DOT medical certificate'inin süresinin dolmasına izin vermesi ve 'sertifikasız' hale gelmesi durumunda CDL'ye ne olur?","options":["CDL, ticari olmayan bir sürücü belgesine düşürülmeye tabi olur","CDL, yeniden geçerli kılınma yolu olmadan derhal ve kalıcı olarak iptal edilir","CDL, hiçbir işlem gerekmeden otomatik olarak muaf eyalet içi statüsüne dönüşür","CDL tam olarak 90 gün askıya alınır, ardından otomatik olarak yeniden geçerli kılınır"],"explanation":"Bir Wyoming CDL sahibi dosyada güncel bir tıbbi sertifika tutmazsa, 'sertifikasız' hale gelir ve CDL, ticari olmayan bir belgeye düşürülmeye tabi olur. Kaynak: WYDOT Driver Certification / DOT Medical Certificate sayfaları; 49 CFR 383.73(o)."},"81":{"q":"Wyoming, her CDL bilgi (yazılı) sınavında hangi minimum geçme puanını gerektirir?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Wyoming CDL bilgi sınavları çoktan seçmelidir ve geçmek için en az %80 doğru gerektirir; başvuru sahipleri yalnızca başarısız oldukları sınavları yeniden alır. Kaynak: WYDOT CDL Testing sayfası."},"82":{"q":"Ticari sürüş ayrıcalıklarını korumak için bir Wyoming CDL ne sıklıkla yenilenmelidir?","options":["Her 4 yılda bir","Her 5 yılda bir","Her 8 yılda bir","Her 2 yılda bir"],"explanation":"Wyoming CDL'leri 4 yıllık bir yenileme döngüsünde düzenlenir. Kaynak: WYDOT Driver License yenileme bilgileri."},"83":{"q":"Wyoming, FMCSA National Registry II (NRII) sürecini uygularken, bir sürücünün DOT tıbbi sertifikasyonu normalde WYDOT'a nasıl sağlanır?","options":["Sertifikalı tıbbi muayene görevlisi, sonuçları FMCSA National Registry aracılığıyla elektronik olarak eyalet sürüş kaydına iletir","Sürücü, kâğıt sertifikanın bir fotokopisini ilçe kâtibine posta ile gönderir","İşveren, sertifikayı Wyoming Highway Patrol'a faks ile gönderir","Sürücü, taranmış bir görüntüyü kişisel bir FMCSA sürücü hesabına yükler"],"explanation":"FMCSA'nın National Registry II kuralı kapsamında (23 Haziran 2025'te yürürlüğe girer), sertifikalı tıbbi muayene görevlisi tıbbi sertifikasyon sonuçlarını National Registry aracılığıyla doğrudan State Driver Licensing Agency kaydına elektronik olarak iletir; muayene görevlisinin sonuçları girmek için bir sonraki takvim gününün gece yarısına kadar süresi vardır. Kaynak: WYDOT DOT Medical Certificate sayfası; FMCSA NRII kuralı."},"84":{"q":"Bir Wyoming CDL için DOT tıbbi yeterliliğini belgelemek amacıyla kullanılan federal Medical Examiner's Certificate'in form numarası nedir?","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"explanation":"Medical Examiner's Certificate, FMCSA Form MCSA-5876'dır (daha uzun Medical Examination Report ise MCSA-5875'tir). Kaynak: FMCSA tıbbi formları; WYDOT DOT Medical Certificate sayfası."},"85":{"q":"Wyoming'de kendini 'muaf eyalet içi' (EA) olarak öz-sertifiye eden bir sürücü, işletmesi hakkında hangi beyanı yapmaktadır?","options":["Yalnızca Wyoming içinde işletme yaparlar ve federal DOT tıbbi kart gereksinimlerini karşılamak zorunda değildirler","Eyalet sınırlarını aşarak işletme yaparlar ve federal bir DOT tıbbi kartı bulundurmaları gerekir","Yalnızca tehlikeli madde taşırlar ve ayrı bir tıbbi muafiyete ihtiyaç duyarlar","Yalnızca ruhsattan muaf, devlete ait araçları kullanırlar"],"explanation":"Muaf eyalet içi (EA), sürücünün yalnızca eyalet içi ticarette işletme yaptığı ve federal DOT tıbbi sertifika gereksiniminden muaf olduğu anlamına gelir. Kaynak: WYDOT Driver Certification sayfası; 49 CFR 383.71(b)."},"86":{"q":"İlk kez bir Wyoming CDL veya CLP için başvururken, kimliği kanıtlamak için tipik olarak hangi belge gereklidir?","options":["Onaylı bir doğum belgesi veya geçerli bir U.S. passport","Güncel bir işveren kimlik kartı","İmzalı bir CDL onay feragat formu","Başvuru sahibinin adına bir araç tescil kartı"],"explanation":"Wyoming, başvuru için onaylı bir doğum belgesi (veya bunun yerine U.S. passport) gibi bir kimlik kanıtının yanı sıra Social Security numarası ve Wyoming ikamet kanıtını gerektirir. Kaynak: WYDOT Driver Services; Wyoming CDL başvuru gereksinimleri."},"87":{"q":"Wyoming, CDL beceri sınavını hangi randevu düzenlemesi kapsamında uygular?","options":["Yalnızca tüm gerekli yazılı sınavlar geçildikten sonra, sadece randevu ile","Eyalet genelindeki herhangi bir DMV kiosk'ta sırada bekleyerek","Yalnızca her bahar tek bir yıllık sınav haftasında","Uzaktan gözetimli bir video oturumu aracılığıyla çevrimiçi"],"explanation":"Wyoming beceri sınavları yalnızca randevu ile ve yalnızca başvuru sahibi tüm gerekli yazılı (bilgi) sınavlarını geçtikten sonra verilir. WYDOT, eyalet genelinde sınırlı sayıda yerde beceri sınavı sunar. Kaynak: WYDOT CDL Testing sayfası."},"88":{"q":"Wyoming CDL beceri sınavı için, uygun sınıfta temsili bir araç sağlamaktan kim sorumludur?","options":["Başvuru sahibi, sınava girilen sınıf/tipi temsil eden bir araç sağlamalıdır","WYDOT her başvuru sahibi için eyalete ait bir sınav aracı sağlar","Sertifikalı tıbbi muayene görevlisi sınav aracını sağlar","Wyoming Highway Patrol ücretsiz olarak bir araç ödünç verir"],"explanation":"Başvuru sahipleri, talep edilen CDL'nin sınıfını ve tipini temsil eden kendi araçlarını temin etmelidir; örneğin bir tank aracı bir N onayı ve boşaltma belgesi taşımalıdır ve sınav sırasında plakartlı hazmat yükleri kullanılamaz. Kaynak: WYDOT CDL Testing sayfası."},"89":{"q":"Wyoming'de, tehlikeli madde (H) onayı almak hangi eğitim/sınav sırasını gerektirir?","options":["Hazmat ELDT teorik eğitimini tamamlayın, ardından hazmat bilgi sınavını geçin (artı bir TSA geçmiş kontrolü)","Tankerlere özel ek bir yolda beceri sınavını geçin","200 saat direksiyon başı hazmat sürüşü tamamlayın","Herhangi bir sınavdan önce ilçe tarafından düzenlenen bir tehlikeli kargo izni alın"],"explanation":"İlk kez bir hazmat (H) onayı için, hazmat bilgi sınavına girmeden önce ELDT hazmat teorik eğitimi tamamlanmalıdır; ayrıca bir TSA güvenlik tehdit değerlendirmesi (geçmiş kontrolü) de gereklidir. Ayrı bir hazmat beceri sınavı yoktur. Kaynak: WYDOT CDL Testing/Commercial License sayfaları; 49 CFR Part 380 Subpart B."},"90":{"q":"Eyalet içi (Wyoming içinde) ticari sürüş için bir Wyoming CDL'sinin düzenlenebilmesi için minimum yaş nedir?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Bir Wyoming CDL, eyalet içi işletme için 18 yaşında düzenlenebilir; bir sürücünün eyaletler arası ticarette işletme yapması, plakart gerektiren tehlikeli madde taşıması veya eyalet sınırlarını aşarak yolcu taşıması için 21 yaşında olması gerekir. Kaynak: WYDOT Commercial Learner's Permit / Commercial License sayfaları."},"91":{"q":"WYDOT'a göre bir Wyoming commercial learner's permit (CLP) ne kadar süre geçerli kalır?","options":["365 days","30 days","60 days","10 years"],"explanation":"WYDOT'a göre, bir Wyoming CLP 365 days geçerlidir. (Federal kurallar, sahibinin beceri sınavına girmeden önce düzenlenmesinden sonra en az 14 days beklemesini gerektirir.) Kaynak: WYDOT Commercial Learner's Permit sayfası."},"92":{"q":"Bir Wyoming sürücüsü bir CDL'nin süresinin dolmasına izin verir ve eyaletin ek süre döneminde (yaklaşık iki yıl) yenilemezse, tekrar bir CDL almak için genellikle ne gerekir?","options":["Yeni bir CLP alarak ve gerekli bilgi ve beceri sınavlarını yeniden alarak baştan başlamak","Sabit bir gecikme ücreti ödemek ve CDL sınav olmadan yeniden geçerli kılınır","CDL'yi geri yüklemek için yalnızca yeni bir DOT tıbbi sertifikası sunmak","Herhangi bir yeniden başvuruya izin verilmeden önce beş ek yıl beklemek"],"explanation":"Wyoming, süresi dolmuş bir CDL'nin yaklaşık iki yıllık bir ek süre dönemi içinde yeniden sınava girmeden yenilenmesine izin verir; bunun ötesinde, sürücü yeni bir CLP ile baştan başlamalı ve gerekli bilgi ve beceri sınavlarını yeniden almalıdır. Kaynak: WYDOT Driver License yenileme bilgileri."},"93":{"q":"Bir Wyoming CLP'sinin geçerlilik süresi boyunca CDL bilgi (yazılı) sınav sonuçlarının nasıl ele alındığını en iyi hangi ifade tanımlar?","options":["Geçilen bilgi sınavları CLP süresi boyunca geçerli kalır, bu nedenle yalnızca başarısız olunan sınavların yeniden alınması gerekir","Tüm bilgi sınavları, beceri sınavıyla aynı gün yeniden geçilmelidir","Bilgi sınavı sonuçları sınav tarihinden 7 gün sonra geçerliliğini yitirir","Bilgi sınavlarının yalnızca bir kez geçilmesi gerekir ve bir CLP olmadan bile asla geçerliliğini yitirmez"],"explanation":"Wyoming'de, bilgi sınavları CLP'ye bağlıdır: geçilen sınavlar iznin süresi boyunca geçerli kalır ve bir başvuru sahibi yalnızca başarısız olduğu sınavları yeniden alır. Kaynak: WYDOT CDL Testing sayfası."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal para la mayoría de los vehículos comerciales en las carreteras de Wyoming sin un permiso de dimensiones excedidas?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","10 pies (120 pulgadas)"],"explanation":"Wyoming limita el ancho del vehículo a 8 pies 6 pulgadas (102 pulgadas) en sus carreteras, lo que coincide con el estándar federal. Cualquier vehículo más ancho requiere un permiso de dimensiones excedidas. Fuente: W.S. 31-18-802; reglas de tamaño y peso para transportistas comerciales de la Wyoming Highway Patrol."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo en las carreteras de Wyoming sin un permiso?","options":["13 pies","13 pies 6 pulgadas","14 pies","15 pies"],"explanation":"Wyoming permite una altura máxima del vehículo de 14 pies en todas las carreteras antes de que se necesite un permiso de dimensiones excedidas. Fuente: W.S. 31-18-802; reglas para transportistas comerciales de la Wyoming Highway Patrol."},"2":{"q":"En las carreteras de Wyoming, ¿cuál es la carga máxima que un eje simple puede transportar legalmente sin un permiso de sobrepeso?","options":["18,000 libras","20,000 libras","22,000 libras","24,000 libras"],"explanation":"Wyoming limita un eje simple a 20,000 libras, lo mismo que el límite federal de eje simple. Fuente: W.S. 31-18-805; límites de peso para transportistas comerciales de la Wyoming Highway Patrol."},"3":{"q":"¿Cuál es el peso máximo legal para un eje tándem (dos ejes ubicados muy juntos) en las carreteras de Wyoming sin un permiso?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Wyoming permite que un eje tándem transporte hasta 36,000 libras sin un permiso de sobrepeso. Fuente: W.S. 31-18-805; límites de peso para transportistas comerciales de la Wyoming Highway Patrol."},"4":{"q":"¿Cuál es el peso bruto vehicular máximo básico permitido en las carreteras de Wyoming antes de que apliquen permisos especiales o disposiciones de fórmula?","options":["73,280 libras","76,000 libras","80,000 libras","84,000 libras"],"explanation":"El peso bruto vehicular máximo de referencia de Wyoming es de 80,000 libras, en consonancia con el límite federal. Los pesos mayores se rigen por las tablas de peso de la fórmula de puentes (bridge formula). Fuente: W.S. 31-18-805; reglas para transportistas comerciales de la Wyoming Highway Patrol."},"5":{"q":"Antes de que se requiera cualquier permiso de dimensiones excedidas, ¿cuánto peso puede transportar legalmente cada rueda en Wyoming?","options":["8,000 libras","9,000 libras","10,000 libras","12,000 libras"],"explanation":"Wyoming limita cada rueda a 10,000 libras. Este tope por rueda complementa los límites de eje simple y eje tándem. Fuente: límites de peso para transportistas comerciales de la Wyoming Highway Patrol; W.S. 31-18-805."},"6":{"q":"¿Cuál es la longitud total máxima permitida en Wyoming para una combinación de vehículos distinta a un tractocamión-semirremolque o a una combinación doble reconocida?","options":["75 pies","81 pies","85 pies","97 pies"],"explanation":"Para cualquier otra combinación de vehículos, Wyoming establece un límite de longitud total de 85 pies. Fuente: W.S. 31-18-802 Requisitos Generales."},"7":{"q":"En un tractocamión de Wyoming con dos remolques, la longitud combinada de las unidades remolcadas (incluidos los mecanismos de conexión) no puede exceder ¿qué valor?","options":["75 pies","81 pies","85 pies","88 pies"],"explanation":"Wyoming limita la longitud combinada del semirremolque y el remolque (o de dos semirremolques), incluidos los mecanismos de conexión, a 81 pies, con el primer remolque de no más de 48 pies y el segundo de no más de 40 pies. Fuente: W.S. 31-18-802."},"8":{"q":"¿Cuál es el peso máximo legal para un grupo de ejes trídem (tres ejes consecutivos) en las carreteras de Wyoming sin un permiso?","options":["38,000 libras","40,000 libras","42,000 libras","48,000 libras"],"explanation":"Wyoming permite hasta 42,000 libras en un grupo de ejes trídem (tres ejes consecutivos) antes de que se requiera un permiso de sobrepeso. Fuente: W.S. 31-18-805; límites de peso para transportistas comerciales de la Wyoming Highway Patrol."},"9":{"q":"En Wyoming, en una combinación de un solo remolque, el segundo remolque o segundo semirremolque no puede exceder ¿qué longitud?","options":["28 pies","33 pies","40 pies","48 pies"],"explanation":"Wyoming limita el remolque o segundo semirremolque en una combinación doble a 40 pies (sin contar el mecanismo de conexión). Fuente: W.S. 31-18-802 Requisitos Generales."},"10":{"q":"¿Para qué se utiliza la fórmula federal de puentes (bridge formula), tal como se aplica en Wyoming?","options":["Para determinar el ancho máximo de una carga que puede cruzar un puente","Para determinar el peso bruto permitido sobre un grupo de ejes según la cantidad de ejes y su separación","Para determinar el peaje cobrado a camiones pesados que cruzan los puentes del estado","Para determinar la presión mínima de neumáticos requerida en los puentes de la Interestatal"],"explanation":"Wyoming aplica la fórmula federal de puentes (W = 500[LN/(N-1) + 12N + 36]) para establecer el peso bruto permitido sobre cualquier grupo de dos o más ejes consecutivos según la cantidad de ejes (N) y la distancia (L) entre los extremos. Fuente: tablas de peso de Wyoming; W.S. 31-18-805."},"11":{"q":"Según las tablas de peso de la fórmula de puentes de Wyoming, ¿cuál es el peso bruto máximo que puede autorizarse en el sistema Interestatal mediante la Tabla I (la tabla de la fórmula de puente interior)?","options":["80,000 libras","105,500 libras","117,000 libras","129,000 libras"],"explanation":"Usando la Tabla I de Wyoming (la fórmula de puente interior que verifica todos los grupos de ejes consecutivos), se pueden transportar pesos brutos de hasta 117,000 libras en carreteras Interestatales, primarias y secundarias cuando se cumplen los límites de ejes y de puente. Fuente: tablas de peso para transportistas comerciales de la Wyoming Highway Patrol; WYDOT."},"12":{"q":"En Wyoming, ¿cuándo puede una carga divisible exceder las 80,000 libras de peso bruto sin un permiso de sobrepeso?","options":["Solo durante las horas del día en las carreteras Interestatales","Cuando es legal en todos los pesos de ejes y de puente y está registrado/matriculado para al menos ese peso bruto","Solo si la carga es agrícola y se traslada dentro de 50 millas","Nunca, porque cualquier carga de más de 80,000 libras siempre requiere un permiso"],"explanation":"Wyoming permite que una carga divisible exceda las 80,000 libras en carreteras estatales e Interestatales sin un permiso, siempre que sea legal en cada peso de eje y bajo la fórmula de puentes y que el vehículo esté matriculado (registrado) para al menos su peso bruto real. Fuente: reglas para transportistas comerciales de la Wyoming Highway Patrol; WYDOT."},"13":{"q":"Un transportista quiere mover una carga más ancha de 8 pies 6 pulgadas en una carretera de Wyoming. ¿Qué debe hacer primero?","options":["Nada, siempre que la carga tenga menos de 10 pies de ancho","Obtener un permiso de dimensiones excedidas (o autorización) antes de operar en la carretera","Simplemente viajar solo de noche con luces de emergencia","Reducir la presión de los neumáticos y notificar a la policía local"],"explanation":"Cualquier vehículo o carga que exceda el tamaño o el peso legal en Wyoming debe obtener un permiso o autorización antes de operar en una carretera estatal de Wyoming. Fuente: reglas para transportistas comerciales de la Wyoming Highway Patrol; Permisos de WYDOT."},"14":{"q":"¿Qué oficina de Wyoming gestiona los permisos de sobrepeso/dimensiones excedidas que superan los límites que un Puerto de Entrada (Port of Entry) o un taller de carreteras puede emitir?","options":["La oficina del alguacil (sheriff) del condado en cada condado de viaje","La Oficina de Cargas con Sobrepeso (Overweight Loads Office) en Cheyenne (WYDOT)","La oficina regional de la Federal Highway Administration","El Departamento de Caza y Pesca de Wyoming (Wyoming Game and Fish Department)"],"explanation":"Los permisos que superan los umbrales rutinarios del Puerto de Entrada/taller de carreteras se emiten a través de la Oficina de Cargas con Sobrepeso (Overweight Loads Office) de WYDOT en Cheyenne (307-777-4376). Los puertos de entrada y los talleres de carreteras pueden emitir permisos hasta ciertos límites establecidos por debajo de ese. Fuente: transportistas comerciales de la Wyoming Highway Patrol; WYDOT."},"15":{"q":"¿Cuál es el horario de viaje generalmente permitido en Wyoming para una carga de dimensiones excedidas que requiere escoltas?","options":["Solo de la medianoche a las 6:00 a.m.","Desde media hora antes del amanecer hasta media hora después del atardecer","Solo de lunes a viernes, de 9:00 a.m. a 5:00 p.m.","Las 24 horas del día sin restricción"],"explanation":"Los traslados de dimensiones excedidas en Wyoming están generalmente restringidos a las horas de luz del día, desde media hora antes del amanecer hasta media hora después del atardecer, incluidos los fines de semana; el viaje nocturno limitado solo se permite para cargas más angostas en las Interestatales con la iluminación adecuada. Fuente: condiciones de los permisos de dimensiones excedidas de WYDOT."},"16":{"q":"¿Cuál es el número máximo de vehículos individuales permitidos en cualquier combinación de vehículos en las carreteras de Wyoming?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"El estatuto de Wyoming establece que ninguna combinación de vehículos podrá constar de más de tres vehículos individuales. Fuente: W.S. 31-18-802 Requisitos Generales."},"17":{"q":"En Wyoming, ¿qué clase de CDL se requiere para operar un vehículo en combinación con una clasificación de peso bruto combinado (GCWR) de 26,001 lbs o más, donde la unidad remolcada tiene un GVWR de más de 10,000 lbs?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Wyoming sigue la clasificación federal de CDL (49 CFR 383.91): una CDL Clase A cubre cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que la(s) unidad(es) remolcada(s) tenga(n) un GVWR de más de 10,000 lbs. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.91."},"18":{"q":"Según las reglas de Wyoming, un vehículo individual con un GVWR de 26,001 lbs o más (o un vehículo de ese tipo que remolque una unidad de no más de 10,000 lbs) requiere ¿qué clase de CDL?","options":["Clase C","Clase B","Clase A","Clase M"],"explanation":"Wyoming utiliza las definiciones federales: una CDL Clase B cubre un vehículo individual con un GVWR de 26,001 lbs o más, o cualquier vehículo de ese tipo que remolque una unidad con un GVWR que no exceda las 10,000 lbs. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.91."},"19":{"q":"Un vehículo de Wyoming que no cumple con los umbrales de peso de Clase A o B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos con carteles (placarded) requiere ¿qué clase de CDL?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"Wyoming sigue la definición federal: una CDL Clase C cubre un vehículo que no cumple con los criterios de Clase A o B pero que está diseñado para transportar 16 o más personas (incluido el conductor) o se usa para transportar materiales peligrosos que requieren carteles (placards). Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.91."},"20":{"q":"¿Qué código de aval (endorsement) coloca Wyoming en una CDL que autoriza al conductor a operar vehículos cisterna (tanques)?","options":["T","N","H","X"],"explanation":"El aval de vehículo cisterna es el código N en Wyoming, en consonancia con los códigos de aval federales. (El código X denota un aval combinado de cisterna/HazMat.) Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.153."},"21":{"q":"En Wyoming, ¿qué aval (endorsement) se requiere para arrastrar remolques dobles o triples?","options":["Aval N","Aval P","Aval T","Aval S"],"explanation":"El aval T (Dobles/Triples) se requiere en Wyoming para operar una combinación que remolca más de un remolque. Se obtiene aprobando el examen de conocimientos de dobles/triples. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.153."},"22":{"q":"¿Cuál es la edad mínima para obtener una CDL de Wyoming restringida ÚNICAMENTE a conducción comercial INTRAESTATAL (dentro del estado)?","options":["16 años","18 años","19 años","21 años"],"explanation":"Wyoming permite una CDL a los 18 años de edad solo para operación intraestatal; la operación interestatal requiere tener 21 años. Fuente: Manual de CDL de Wyoming (WYDOT) / W.S. Título 31 y 49 CFR 391.11."},"23":{"q":"¿Cuál es la edad mínima para tener una CDL de Wyoming que autoriza la conducción comercial INTERESTATAL?","options":["18 años","19 años","21 años","23 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un CMV en comercio interestatal; los conductores de 18 a 20 años están limitados a la conducción intraestatal en Wyoming. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 391.11."},"24":{"q":"Antes de presentar el examen de habilidades (de manejo) de la CDL en Wyoming, ¿durante cuánto tiempo debe haber tenido el solicitante el Permiso de Aprendiz Comercial (CLP)?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Un CLP debe tenerse durante un mínimo de 14 días después de su emisión antes de que el titular sea elegible para presentar el examen de habilidades de la CDL. Esta espera federal aplica en Wyoming. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.25."},"25":{"q":"Al operar un CMV con un CLP de Wyoming, el titular del permiso siempre debe estar acompañado por una persona que tenga una CDL válida para ese vehículo. ¿Dónde debe estar ubicado ese titular de la CDL?","options":["En el asiento directamente detrás del conductor","En cualquier lugar dentro de la cabina del vehículo","En el asiento delantero del pasajero junto al titular del CLP","Siguiéndolo en un vehículo separado"],"explanation":"Un titular de CLP debe estar acompañado en todo momento por un titular de CDL debidamente licenciado sentado en el asiento delantero junto al conductor, brindando supervisión directa. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.25."},"26":{"q":"¿Qué restricción aplica a un vehículo cisterna cuando lo opera un titular de CLP de Wyoming que tiene la categoría N (cisterna) en el permiso?","options":["La cisterna puede cargarse hasta el 50% de su capacidad","La cisterna debe estar vacía (sin carga líquida ni gaseosa)","Solo se puede transportar agua","No se permite ninguna operación de cisterna con un CLP"],"explanation":"Un titular de CLP con autorización de cisterna (N) solo puede operar un vehículo cisterna que esté vacío de toda carga líquida o gaseosa; las cisternas cargadas están prohibidas hasta que se emita la CDL. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.25."},"27":{"q":"En Wyoming, ¿qué base de datos federal debe usar un conductor para completar la Capacitación Obligatoria para Conductores Principiantes (ELDT) antes del examen de la CDL o de un aval cubierto?","options":["El National Driver Register","El FMCSA Training Provider Registry (TPR)","El portal eDriver de WYDOT de Wyoming","El sistema CDLIS clearinghouse"],"explanation":"La ELDT debe completarse con un proveedor que figure en el FMCSA Training Provider Registry (TPR), que registra la finalización del aprendiz para que el estado lo verifique. Fuente: Manual de CDL de Wyoming (WYDOT) / regla ELDT de FMCSA, 49 CFR Parte 380."},"28":{"q":"¿Qué solicitantes están obligados a completar la ELDT antes de presentar el examen en Wyoming?","options":["Solo conductores menores de 21 años","Solicitantes de Clase A o B por primera vez, ascensos de Clase B a A, y solicitantes por primera vez de los avales P, S o H","Solo solicitantes del aval HazMat (H)","Todos los solicitantes de renovación de CDL"],"explanation":"La ELDT federal (vigente desde el 7 de feb. de 2022) aplica a los solicitantes de Clase A/B por primera vez, a los conductores que ascienden de Clase B a Clase A, y a los solicitantes por primera vez de los avales P, S o H. No es retroactiva. Fuente: regla ELDT de FMCSA, 49 CFR Parte 380 / WYDOT."},"29":{"q":"Además de aprobar el examen de conocimientos, ¿qué requiere Wyoming para un aval HazMat (H)?","options":["Una evaluación de amenaza a la seguridad de la TSA que incluye toma de huellas dactilares","Una entrevista separada con la Wyoming Highway Patrol","Un segundo examen físico","Una carta de patrocinio del empleador notariada"],"explanation":"Wyoming exige que los solicitantes del aval H aprueben una evaluación de amenaza a la seguridad de la Transportation Security Administration (TSA), que incluye toma de huellas dactilares y una verificación de antecedentes penales/migratorios, además del examen de conocimientos de HazMat y la capacitación teórica de la ELDT. Fuente: página de Evaluación de Materiales Peligrosos de WYDOT / 49 CFR 1572."},"30":{"q":"¿Con qué frecuencia debe un conductor de Wyoming renovar la evaluación de amenaza a la seguridad de la TSA para mantener el aval HazMat (H)?","options":["Cada año","Cada 2 años","Cada 5 años","Cada 8 años"],"explanation":"La evaluación de amenaza a la seguridad de la TSA para el aval HazMat es válida por cinco años y debe renovarse (con una nueva verificación de antecedentes y examen de conocimientos) para conservar el aval H; no puede renovarse por correo. Fuente: página de Evaluación de Materiales Peligrosos de WYDOT / 49 CFR 1572."},"31":{"q":"En Wyoming, antes de que un conductor pueda tener un aval S (Autobús Escolar), ¿qué otro aval también debe obtenerse?","options":["H (HazMat)","N (Cisterna)","P (Pasajeros)","T (Dobles/Triples)"],"explanation":"El aval S (Autobús Escolar) requiere que el conductor primero califique para el aval P (Pasajeros), ya que un autobús escolar es un vehículo de transporte de pasajeros. Aplican tanto el examen de conocimientos como el de habilidades. Fuente: Manual de CDL de Wyoming (WYDOT) / 49 CFR 383.123."},"32":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL de Wyoming a la agencia emisora (WYDOT Driver Services)?","options":["Solo una licencia de conducir vigente de Wyoming con fotografía","Prueba de identidad/presencia legal, número de Seguro Social y residencia en Wyoming","Solo un pasaporte y una carta del empleador","Un certificado de nacimiento y un título de propiedad de vehículo"],"explanation":"Wyoming exige que los solicitantes de CDL prueben su identidad y presencia legal en los EE. UU., proporcionen un número de Seguro Social y muestren prueba de residencia en Wyoming (generalmente dos documentos). Fuente: requisitos de documentos de WYDOT Driver Services."},"33":{"q":"En la autocertificación de la CDL de Wyoming, un conductor que opera cruzando líneas estatales y que NO está exento de la calificación física federal debe seleccionar ¿qué categoría?","options":["Interestatal Exceptuado (EI)","Interestatal No Exceptuado (NI)","Intraestatal Exceptuado (EA)","Intraestatal No Exceptuado (NA)"],"explanation":"Un conductor en comercio interestatal que no está exento de las reglas médicas federales se autocertifica como Interestatal No Exceptuado (NI) y debe mantener archivado un certificado médico válido del examinador del DOT. Fuente: autocertificación de CDL de WYDOT / 49 CFR 383.71."},"34":{"q":"¿Qué categoría de autocertificación de la CDL de Wyoming NO requiere que el conductor mantenga un certificado médico federal (DOT) del examinador?","options":["Interestatal No Exceptuado (NI)","Intraestatal No Exceptuado (NA)","Interestatal Exceptuado (EI)","Tanto NI como NA"],"explanation":"Los conductores Interestatales Exceptuados (EI) e Intraestatales Exceptuados (EA) están exentos de mantener una tarjeta médica del DOT; solo los conductores No Exceptuados (NI y NA) deben mantener un certificado médico vigente del examinador. Fuente: autocertificación de CDL de WYDOT / 49 CFR 383.71 y 390.3."},"35":{"q":"¿Cuál es la concentración máxima de alcohol en la sangre (BAC) con la que un conductor puede operar legalmente un vehículo motorizado comercial (CMV) en Wyoming?","options":["0.04 por ciento","0.08 por ciento","0.02 por ciento","0.10 por ciento"],"explanation":"Wyoming sigue el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 para los conductores comunes. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"36":{"q":"Bajo la ley de consentimiento implícito de Wyoming, al conducir o estar en control físico real de un vehículo en el estado, ¿a qué se considera que un conductor ha dado su consentimiento?","options":["A una prueba química de sangre, aliento u orina cuando se solicite legalmente","A un registro del vehículo en cualquier punto de control","A tratamiento obligatorio contra las drogas después de cualquier detención","A una prueba de sobriedad en campo que no puede rechazarse"],"explanation":"El estatuto de consentimiento implícito de Wyoming establece que cualquier persona que conduzca o esté en control físico real de un vehículo en el estado consiente automáticamente a una prueba química de sangre, aliento u orina cuando un oficial la solicite legalmente. Fuente: Manual de CDL de Wyoming; W.S. 31-6-102 (consentimiento implícito)."},"37":{"q":"Por una primera infracción grave (obligatoria), como conducir un CMV con un BAC de 0.04 o más, ¿por cuánto tiempo queda descalificado un titular de CDL de Wyoming (sin HazMat)?","options":["1 año","6 meses","90 días","3 años"],"explanation":"Una primera condena por una infracción grave resulta en una descalificación de la CDL de 1 año en Wyoming. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"38":{"q":"Si un conductor comete una primera infracción grave mientras opera un CMV que tiene carteles (placards) de materiales peligrosos, el período de descalificación de Wyoming aumenta a ¿cuánto?","options":["3 años","2 años","18 meses","5 años"],"explanation":"Una primera infracción grave cometida mientras se transportan materiales peligrosos con carteles (placarded) eleva la descalificación de 1 año a 3 años. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"39":{"q":"¿Cuál es el período de descalificación de la CDL de Wyoming por una segunda infracción grave (obligatoria)?","options":["De por vida","10 años","5 años","3 años"],"explanation":"Una segunda condena por cualquier infracción grave resulta en una descalificación de la CDL de por vida. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"40":{"q":"Un titular de CDL de Wyoming rechaza una prueba química solicitada legalmente mientras opera un CMV. ¿Cuál es el período mínimo de descalificación por este rechazo?","options":["1 año","90 días","6 meses","60 días"],"explanation":"Rechazar la prueba química requerida se trata como una infracción grave, lo que resulta en al menos una descalificación de 1 año (3 años si tiene carteles de HazMat). Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"41":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Wyoming?","options":["Exceder el límite de velocidad por 15 mph o más","Exceder el límite de velocidad por 5 mph","Una infracción de estacionamiento","Una calcomanía de registro vencida"],"explanation":"Las infracciones de tránsito graves incluyen exceder el límite de velocidad por 15 mph o más, conducción imprudente, seguir demasiado de cerca, cambios de carril erráticos/indebidos, y enviar mensajes de texto o usar el teléfono de mano mientras se conduce un CMV. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"42":{"q":"Un titular de CDL de Wyoming es condenado por dos infracciones de tránsito graves que surgen de incidentes separados dentro de un período de 3 años. ¿Cuál es la descalificación?","options":["60 días","30 días","120 días","90 días"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación de 60 días. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"43":{"q":"¿Por cuánto tiempo queda descalificado un titular de CDL de Wyoming por tres infracciones de tránsito graves de incidentes separados dentro de un período de 3 años?","options":["120 días","60 días","1 año","90 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años resultan en una descalificación de 120 días. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"44":{"q":"¿Qué titulares de avales de CDL están obligados a DETENERSE en cada cruce a nivel de ferrocarril y carretera mientras operan un CMV en Wyoming?","options":["Conductores de vehículos de pasajeros y de materiales peligrosos (con carteles)","Solo conductores con un aval de cisterna","Todos los conductores de CMV sin excepción","Solo conductores de autobús escolar menores de 21 años"],"explanation":"Los conductores que transportan pasajeros o materiales peligrosos con carteles (placarded) deben detenerse en todos los cruces de ferrocarril; los demás CMV deben reducir la velocidad y verificar. Fuente: Manual de CDL de Wyoming; 49 CFR 392.10 / 383.51."},"45":{"q":"¿Cuál es la descalificación mínima de Wyoming por una PRIMERA infracción en un cruce a nivel de ferrocarril y carretera en un CMV?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce de ferrocarril resulta en una descalificación de no menos de 60 días. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51 Tabla 3."},"46":{"q":"Un conductor comete una SEGUNDA infracción en un cruce a nivel de ferrocarril dentro de 3 años. ¿Cuál es la descalificación mínima?","options":["120 días","60 días","90 días","1 año"],"explanation":"Una segunda infracción en un cruce de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 120 días. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51 Tabla 3."},"47":{"q":"¿Cuál es la descalificación mínima por una TERCERA infracción en un cruce a nivel de ferrocarril dentro de un período de 3 años?","options":["1 año","120 días","60 días","De por vida"],"explanation":"Una tercera infracción o subsiguiente en un cruce de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 1 año. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51 Tabla 3."},"48":{"q":"¿Cuál es la descalificación mínima por la PRIMERA condena de un conductor de CDL por violar una orden de fuera de servicio (OOS) mientras opera un CMV?","options":["De 180 días a 1 año","De 30 a 60 días","De 2 a 5 años","De 60 a 120 días"],"explanation":"Una primera violación de una orden OOS resulta en una descalificación de no menos de 180 días y no más de 1 año. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51 Tabla 4."},"49":{"q":"¿Cuál es el rango de descalificación por una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 años (sin HazMat/sin pasajeros)?","options":["De 2 a 5 años","De 180 días a 1 año","De 1 a 2 años","De 3 a 5 años"],"explanation":"Una segunda violación de una orden OOS dentro de 10 años resulta en una descalificación de no menos de 2 años y no más de 5 años. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51 Tabla 4."},"50":{"q":"Un conductor que transporta materiales peligrosos con carteles o 16 o más pasajeros comete una PRIMERA violación de una orden de fuera de servicio. ¿Cuál es el rango de descalificación?","options":["De 180 días a 2 años","De 60 a 120 días","De 1 a 3 años","De 3 a 5 años"],"explanation":"Una primera violación de una orden OOS mientras se transporta HazMat con carteles (placarded) o se llevan 16 o más pasajeros resulta en una descalificación de no menos de 180 días y no más de 2 años. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51 Tabla 4."},"51":{"q":"Enviar mensajes de texto o usar un teléfono móvil de mano mientras se conduce un CMV en Wyoming se trata como ¿qué tipo de infracción de CDL?","options":["Una infracción de tránsito grave que cuenta para la descalificación de 60/120 días","Una infracción menor no reportable","Una descalificación automática de por vida","Una infracción de cruce de ferrocarril"],"explanation":"Enviar mensajes de texto y usar el teléfono de mano mientras se conduce un CMV son infracciones de tránsito graves; dos dentro de 3 años conllevan una descalificación de 60 días, y tres, de 120 días. Fuente: Manual de CDL de Wyoming; 49 CFR 383.51; 49 CFR 392.80/392.82."},"52":{"q":"¿Cuál es la sanción civil federal máxima que puede enfrentar un conductor de CMV en Wyoming por una sola infracción de enviar mensajes de texto o usar el teléfono de mano mientras conduce?","options":["Hasta $2,750","Hasta $250","Hasta $11,000","Hasta $500"],"explanation":"Un conductor de CMV puede ser multado con hasta $2,750 por infracción de mensajes de texto/teléfono de mano; el transportista motorizado empleador puede ser multado con hasta $11,000 por permitirlo. Fuente: reglas de Teléfono Móvil / No Enviar Mensajes de Texto de FMCSA; 49 CFR 392.80-392.82, aplicables en Wyoming."},"53":{"q":"Después de una descalificación de la CDL de por vida, ¿cuándo (si acaso) puede un conductor de Wyoming volverse elegible para solicitar la reinstauración bajo la disposición de reinstauración limitada?","options":["Después de al menos 10 años, con condiciones (HazMat sigue siendo no elegible)","Después de 5 años automáticamente","Nunca bajo ninguna circunstancia","Después de 3 años con un historial limpio"],"explanation":"Un conductor descalificado de por vida puede, después de un mínimo de 10 años y cumpliendo con las condiciones de reinstauración, ser considerado para la reinstauración; la elegibilidad para HazMat no se restaura. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"54":{"q":"Las infracciones graves descalificantes como el DUI o usar un vehículo para cometer un delito grave aplican a un titular de CDL de Wyoming incluso cuando la infracción ocurre en ¿qué tipo de vehículo?","options":["Cualquier vehículo motorizado, incluido el automóvil personal del conductor","Solo un CMV de HazMat con carteles","Solo un vehículo propiedad del empleador","Solo un vehículo de más de 26,001 lbs de GVWR"],"explanation":"Las infracciones graves como el DUI cuentan contra la CDL independientemente del tipo de vehículo; un titular de CDL condenado por DUI en un automóvil personal sigue estando descalificado. Fuente: Manual de CDL de Wyoming; W.S. 31-7-305; 49 CFR 383.51."},"55":{"q":"En Wyoming, un conductor con CDL que transporta materiales peligrosos con placas (placarded) se aproxima a un cruce a nivel de ferrocarril y carretera. ¿Dónde debe detenerse el vehículo?","options":["No más cerca de 5 pies ni más lejos de 25 pies del riel más cercano","No más cerca de 50 pies ni más lejos de 100 pies del riel más cercano","Al menos 10 pies pero no más de 30 pies del riel más cercano","No más cerca de 15 pies ni más lejos de 50 pies del riel más cercano"],"explanation":"Regla de Wyoming: Un vehículo que lleva placas de materiales peligrosos (o que transporta cualquier cantidad de cloro o que lleva tanques de carga de HazMat cargados o vacíos) debe detenerse entre 15 y 50 pies del riel más cercano y continuar solo cuando no se aproxime ningún tren. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 9 - Materiales Peligrosos, disposición sobre cruces de ferrocarril."},"56":{"q":"Un conductor de autobús de Wyoming que transporta pasajeros debe detenerse en un cruce de ferrocarril. ¿Cuál es la zona de detención requerida antes del cruce?","options":["Entre 20 y 60 pies antes del cruce","Entre 15 y 50 pies antes del cruce","Entre 10 y 40 pies antes del cruce","Entre 25 y 75 pies antes del cruce"],"explanation":"Regla de Wyoming: Los conductores de autobús deben detener el autobús entre 15 y 50 pies antes de los cruces de ferrocarril, y luego mirar y escuchar en ambas direcciones para detectar trenes antes de cruzar. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 4 - Transporte de Pasajeros (Cruces de Ferrocarril y Carretera y Paradas)."},"57":{"q":"Conforme a la ley Move Over (apártese) de Wyoming, un conductor con CDL en una interestatal u otra carretera con dos o más carriles en su dirección se aproxima a un vehículo de emergencia detenido que muestra señales visuales. ¿Qué debe hacer el conductor, cuando sea seguro?","options":["Detenerse por completo hasta que el vehículo de emergencia se retire","Tocar la bocina y continuar a la velocidad indicada en el mismo carril","Cambiarse a un carril que no esté contiguo al vehículo de emergencia (el carril más alejado de este)","Orillarse al acotamiento derecho y esperar a que un oficial le indique seguir"],"explanation":"Regla de Wyoming: En una carretera con dos o más carriles en la dirección de marcha, un conductor que se aproxima a un vehículo de emergencia autorizado y detenido que usa señales visuales debe cambiarse a un carril que no esté contiguo a ese vehículo (el carril más alejado) cuando sea seguro; si el cambio de carril no es seguro, debe reducir la velocidad y proceder con precaución. Fuente: Estatuto de Wyoming 31-5-224; Manual CDL de Wyoming 2024 (leyes Move Over)."},"58":{"q":"Conforme a la ley Move Over de Wyoming, en una carretera de DOS CARRILES señalizada a 45 mph o más, un conductor que pasa junto a un vehículo de emergencia o de remolque detenido y que no puede cambiar de carril con seguridad debe reducir la velocidad a qué nivel?","options":["20 mph menos que el límite de velocidad indicado","10 mph menos que el límite de velocidad indicado","15 mph menos que el límite de velocidad indicado","Exactamente 25 mph sin importar el límite indicado"],"explanation":"Regla de Wyoming: En una carretera de dos carriles con un límite de velocidad indicado de 45 mph o más, un conductor debe reducir la velocidad a un nivel de 20 mph menos que el límite de velocidad indicado al pasar junto a un vehículo de emergencia, de servicios públicos, de mantenimiento o de remolque detenido que usa señales visuales. Fuente: Estatuto de Wyoming 31-5-224."},"59":{"q":"La ley Move Over de Wyoming (W.S. 31-5-224) protege a más que solo a la policía y las ambulancias. ¿Cuál de los siguientes está TAMBIÉN cubierto expresamente?","options":["Cualquier automóvil de pasajeros estacionado en el acotamiento con sus luces intermitentes de emergencia encendidas","Una grúa o camión de remolque en el lugar de un vehículo averiado que muestra una luz roja intermitente o roja y azul","Un autobús escolar detenido para recoger niños","Un camión de reparto estacionado en doble fila en una calle de la ciudad"],"explanation":"Regla de Wyoming: La ley Move Over cubre a los vehículos de emergencia autorizados, los vehículos municipales/de servicios públicos/de construcción o mantenimiento de carreteras, y las grúas o camiones de remolque en el lugar de un vehículo chocado, averiado o parado cuando están equipados con al menos una luz roja intermitente o roja y azul visible a 500 pies por delante y por detrás. Fuente: Estatuto de Wyoming 31-5-224."},"60":{"q":"En una carretera de Wyoming de dos carriles y doble sentido, un autobús escolar se detiene con sus luces rojas intermitentes encendidas y el brazo de pare extendido. ¿Qué debe hacer un conductor con CDL que se aproxima desde la dirección CONTRARIA?","options":["Reducir a 15 mph y pasar con precaución","Detenerse antes de llegar al autobús y permanecer detenido hasta que las luces dejen de parpadear o el autobús se mueva","Continuar a la velocidad indicada porque el tráfico en sentido contrario está exento","Detenerse solo si hay niños visiblemente cruzando la carretera"],"explanation":"Regla de Wyoming: Al encontrar o alcanzar desde cualquier dirección a un autobús escolar detenido que muestra luces rojas intermitentes, un conductor debe detenerse antes de llegar al autobús y no continuar hasta que el autobús se mueva o las luces rojas dejen de parpadear. Fuente: Estatuto de Wyoming 31-5-507."},"61":{"q":"La ley de detención para autobuses escolares de Wyoming tiene una excepción para carreteras divididas. ¿Cuándo NO está obligado un conductor a detenerse ante un autobús escolar que muestra luces rojas intermitentes?","options":["Solo cuando hay una línea central pintada entre las direcciones de marcha","Siempre que el conductor esté a más de dos carriles del autobús","Siempre que la carretera tenga un límite de velocidad indicado superior a 55 mph","Cuando el autobús está en una calzada distinta de una carretera con calzadas separadas"],"explanation":"Regla de Wyoming: Un conductor en una carretera con calzadas separadas no necesita detenerse al encontrar o pasar a un autobús escolar que está en una calzada DISTINTA, o cuando está en una carretera de acceso controlado y el autobús está detenido en una zona de carga donde no se permite cruzar a los peatones. Una línea pintada por sí sola no califica. Fuente: Estatuto de Wyoming 31-5-507."},"62":{"q":"Un conductor con CDL de Wyoming debe detener el vehículo en el acotamiento de una carretera de un solo sentido o dividida. ¿Dentro de cuánto tiempo deben colocarse los dispositivos de advertencia de emergencia, y dónde?","options":["Dentro de 30 minutos, a 25 pies, 100 pies y 250 pies hacia el tráfico que se aproxima","Dentro de 10 minutos, a 50 pies, 150 pies y 300 pies hacia el tráfico que se aproxima","Dentro de 10 minutos, a 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima","Dentro de 5 minutos, a 10 pies, 50 pies y 100 pies hacia el tráfico que se aproxima"],"explanation":"Regla de Wyoming: Si se detiene sobre o junto a una carretera de un solo sentido o dividida, coloque los dispositivos de advertencia dentro de 10 minutos a 10 pies, 100 pies y 200 pies del vehículo hacia el tráfico que se aproxima. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 2 - Conducir con Seguridad (dispositivos de advertencia para vehículos detenidos)."},"63":{"q":"Un conductor con CDL de Wyoming se detiene en una carretera de dos carriles que lleva tráfico en ambas direcciones. ¿Cómo deben colocarse los tres triángulos reflectantes?","options":["Dentro de 10 pies, 100 pies y 200 pies, todos únicamente detrás del vehículo","A 25 pies, 100 pies y 200 pies por delante del vehículo únicamente","Dentro de 10 pies del vehículo, más 100 pies detrás y 100 pies por delante del vehículo","Dentro de 10 pies, 50 pies y 150 pies hacia la parte trasera del vehículo"],"explanation":"Regla de Wyoming: En una carretera de dos carriles que lleva tráfico en ambas direcciones (o una carretera no dividida), coloque los dispositivos de advertencia dentro de 10 pies de las esquinas delanteras o traseras para marcar el vehículo, y 100 pies detrás y 100 pies por delante del vehículo. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 2 - Conducir con Seguridad."},"64":{"q":"Si una colina o curva bloquea la vista de un vehículo con CDL detenido en una carretera de Wyoming, ¿qué indica el manual hacer con el triángulo de advertencia más alejado (el trasero)?","options":["Moverlo más atrás por la carretera para que la advertencia se proporcione más allá del obstáculo, hasta 500 pies","Dejar todos los triángulos en el espaciamiento estándar de 10/100/200 pies","Colocarlo directamente sobre el obstáculo mismo para máxima visibilidad","Retirarlo por completo y depender únicamente de las luces intermitentes de cuatro vías"],"explanation":"Regla de Wyoming: Si la línea de visión está obstruida por una colina, curva u otro obstáculo, mueva el triángulo más atrás por la carretera (más allá del obstáculo, de modo que el vehículo pueda verse a 500 pies) para dar la advertencia adecuada. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 2 - Conducir con Seguridad."},"65":{"q":"En las carreteras interestatales rurales de Wyoming señalizadas a 80 mph, ¿cómo se aplica el límite de velocidad a un tractocamión con remolque en comparación con un automóvil de pasajeros?","options":["Los camiones están limitados a 70 mph mientras que los automóviles pueden ir a 80 mph","Los camiones y los automóviles comparten el mismo máximo de 80 mph; Wyoming no establece un límite más bajo separado para camiones","Los camiones están limitados a 65 mph mientras que los automóviles pueden ir a 80 mph","Los camiones están limitados a 75 mph mientras que los automóviles pueden ir a 80 mph"],"explanation":"Regla de Wyoming: El límite máximo de velocidad interestatal de Wyoming (hasta 80 mph en tramos rurales designados) se aplica por igual a los camiones comerciales y a los automóviles de pasajeros. A diferencia de algunos estados, Wyoming no establece un límite de velocidad legal separado y más bajo para camiones. Fuente: Estatuto de Wyoming 31-5-301; designaciones del corredor de 80 mph de WYDOT."},"66":{"q":"Wyoming activa una ley de cadenas escalonada en tramos montañosos de la I-80. Bajo el NIVEL 2 más severo (extremadamente peligroso), ¿de qué puede depender un vehículo comercial?","options":["Solo neumáticos de nieve en el eje de tracción","Tracción delantera con neumáticos estándar de carretera","Cadenas para neumáticos, o AWD (tracción total) equipado con neumáticos con clasificación M+S o para toda estación (los neumáticos de nieve por sí solos no bastan)","Solo velocidad reducida, sin requisito de equipo"],"explanation":"Regla de Wyoming: Bajo el Nivel 1, un CMV puede usar cadenas, neumáticos de nieve adecuados o AWD; bajo el Nivel 2 (extremadamente peligroso), los neumáticos de nieve por sí solos son insuficientes y el vehículo debe usar cadenas para neumáticos, o AWD equipado con neumáticos con clasificación M+S o para toda estación. Fuente: niveles de la ley de cadenas de Wyoming de WYDOT (comúnmente aplicada en el tramo 'Three Sisters' de la I-80)."},"67":{"q":"Durante un evento de vientos extremadamente fuertes, Wyoming cierra tramos de la I-80 y la I-25 ¿a qué vehículos primero?","options":["Solo a automóviles de pasajeros y motocicletas","A vehículos comerciales ligeros de perfil alto (como furgonetas vacías o ligeramente cargadas)","Solo a cisternas completamente cargadas que transportan líquidos","Solo a autobuses que transportan pasajeros"],"explanation":"Regla de Wyoming: Debido a los frecuentes accidentes por volcadura, WYDOT restringe y cierra tramos de la I-80 y la I-25 a vehículos ligeros de perfil alto (y, en las peores condiciones, a todos los vehículos comerciales). Los cierres se publican en wyoroad.info / Wyoming 511. Fuente: restricciones de WYDOT por vientos fuertes / volcaduras."},"68":{"q":"¿Cuál es el ancho máximo de un vehículo comercial que puede circular por las carreteras de Wyoming SIN un permiso de sobredimensión?","options":["8 pies 0 pulgadas","9 pies 0 pulgadas","8 pies 6 pulgadas","10 pies 0 pulgadas"],"explanation":"Regla de Wyoming: El ancho máximo legal del vehículo sin permiso es de 8 pies 6 pulgadas (102 pulgadas); cualquier cosa más ancha requiere un permiso de sobredimensión de WYDOT. Fuente: Estatuto de Wyoming 31-18-802 / reglamentos de permisos de sobredimensión de WYDOT."},"69":{"q":"Sin permiso, ¿cuál es la ALTURA máxima legal del vehículo en las carreteras de Wyoming?","options":["14 pies","13 pies 6 pulgadas","13 pies","15 pies"],"explanation":"Regla de Wyoming: La altura máxima legal del vehículo sin permiso es de 14 pies; las cargas que excedan esto requieren un permiso de sobredimensión. Fuente: Estatuto de Wyoming 31-18-802 / reglamentos de sobredimensión de WYDOT."},"70":{"q":"Un transportista de Wyoming necesita un permiso de sobredimensión de un solo viaje de WYDOT para un movimiento de ancho excesivo. ¿Cuál es la tarifa base del permiso de sobredimensión de un solo viaje?","options":["$10.00","$50.00","$100.00","$25.00"],"explanation":"Regla de Wyoming: La tarifa de un permiso de sobredimensión de un solo viaje es de $25.00, con cargos adicionales basados en el millaje para cargas que excedan 15 pies de ancho, 15 pies de alto o 75 pies de largo. Fuente: Estatuto de Wyoming 31-18-804 / tabla de tarifas de permisos de sobredimensión de WYDOT."},"71":{"q":"En una combinación de tractocamión y semirremolque de Wyoming, ¿cuál es la longitud máxima permitida para el semirremolque en sí sin un permiso?","options":["60 pies","48 pies","53 pies","57 pies"],"explanation":"Regla de Wyoming: En una combinación de tractocamión con semirremolque, el semirremolque no puede exceder los 60 pies de longitud (notablemente, Wyoming permite un semirremolque individual más largo que el común de 53 pies). Fuente: Estatuto de Wyoming 31-18-802 (límites de tamaño y peso)."},"72":{"q":"Al cruzar un conjunto de vías de ferrocarril en Wyoming, ¿qué indica el manual de CDL hacer a un conductor de un CMV con transmisión manual?","options":["No cambiar de marcha mientras alguna parte del vehículo esté sobre las vías","Reducir a la marcha más baja a la mitad del cruce para máxima tracción","Poner en neutro y cruzar las vías por inercia","Subir una marcha para librar las vías lo más rápido posible"],"explanation":"Regla de Wyoming: El manual indica que no cambie de marcha mientras cruza las vías de ferrocarril, porque cambiar de marcha conlleva el riesgo de calarse sobre las vías; seleccione una marcha que le permita cruzar por completo antes de comenzar. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), Sección 2.15 - Cruces de Ferrocarril/Carretera."},"73":{"q":"Al aproximarse a un cruce de ferrocarril en Wyoming, un autobús escolar, autobús de pasajeros o vehículo con placas (placarded) debe tomar qué acción con sus luces al acercarse a las vías?","options":["Apagar todas las luces exteriores para evitar confundir a las tripulaciones del tren","Encender las luces altas de forma continua hasta cruzar las vías","Activar la direccional hacia el riel más cercano","Activar las luces intermitentes de cuatro vías (de emergencia) en la aproximación, y desactivarlas después de librar las vías"],"explanation":"Regla de Wyoming: Un autobús, autobús escolar o vehículo con placas debe activar las luces intermitentes de cuatro vías al aproximarse al cruce, detenerse dentro de 50 pies pero no menos de 15 pies del riel más cercano, mirar y escuchar, y luego desactivar las luces intermitentes después de cruzar. Fuente: Manual de Licencia de Conducir Comercial de Wyoming 2024 (WYDOT), procedimientos del examen vial sobre cruces de ferrocarril."},"74":{"q":"¿Qué agencia de Wyoming administra los registros de conducción y emite todas las clases de licencias de conducir comerciales (CDL) en el estado?","options":["El Departamento de Transporte de Wyoming (WYDOT), Programa de Servicios al Conductor","El Departamento de Vehículos Motorizados de Wyoming, una agencia independiente","La Patrulla de Caminos de Wyoming, División de Licencias","La oficina del secretario del condado en el condado de residencia del solicitante"],"explanation":"En Wyoming, el Programa de Servicios al Conductor de WYDOT administra el sistema de registros de conducción y exámenes, y emite y procesa todas las clases de licencias de conducir y de conducir comerciales. Wyoming no tiene una agencia 'DMV' separada. Fuente: página de Servicios al Conductor / Licencia Comercial de WYDOT."},"75":{"q":"Antes de que WYDOT pueda aplicar un examen de habilidades de CDL, un solicitante de nivel inicial de una primera CDL Clase A o Clase B debe completar qué requisito?","options":["Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA","Un curso de manejo defensivo de 40 horas aprobado por la Patrulla de Caminos de Wyoming","Dos años de experiencia documentada de conducción intraestatal","Una evaluación de aptitud médica administrada por WYDOT"],"explanation":"Las reglas federales de ELDT, aplicadas en Wyoming, requieren que los conductores de nivel inicial completen capacitación teórica y práctica detrás del volante de un proveedor que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA antes de tomar el examen de habilidades. WYDOT establece que los exámenes de habilidades de CDL solo pueden aplicarse a quienes completaron el ELDT o tienen una exención por derechos adquiridos (grandfather). Fuente: página de Exámenes CDL de WYDOT; 49 CFR Part 380 Subpart F."},"76":{"q":"El examen de habilidades de CDL de Wyoming se compone de cuáles tres partes, administradas en orden?","options":["Inspección (del vehículo) previa al viaje, habilidades básicas de control y conducción en carretera","Examen escrito de conocimientos, prueba de visión y conducción en carretera","Prueba de frenos de aire, prueba de acoplamiento y conducción nocturna","Manejo defensivo, habilidades básicas de control y una demostración de manejo de materiales peligrosos"],"explanation":"El examen de habilidades de CDL de Wyoming consta de una inspección del vehículo previa al viaje, una prueba de habilidades básicas de control y una prueba de conducción en carretera (on-road). Fuente: página de Exámenes CDL de WYDOT; estándares de habilidades CDL de AAMVA adoptados por Wyoming."},"77":{"q":"¿De cuáles cuatro categorías de autocertificación debe elegir un solicitante de CDL de Wyoming al declarar el tipo de conducción comercial que realiza?","options":["Interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada, intraestatal exceptuada","Local, regional, de larga distancia (over-the-road) y de temporada","Clase A, Clase B, Clase C y solo endoso","De alquiler (for-hire), privada, agrícola y de emergencia"],"explanation":"Wyoming requiere que cada titular de CDL se autocertifique en una de cuatro categorías: interestatal no exceptuada (NI), interestatal exceptuada (EI), intraestatal no exceptuada (NA) e intraestatal exceptuada (EA). Fuente: página de Certificación del Conductor de WYDOT; 49 CFR 383.71(b)."},"78":{"q":"Conforme a la regla federal del permiso de aprendiz comercial (CLP) aplicada en Wyoming, ¿por cuánto tiempo debe un solicitante tener un CLP antes de que se le permita tomar el examen de habilidades de CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Un titular de CLP de Wyoming debe esperar al menos 14 días después de la emisión del CLP antes de tomar el examen de habilidades de CDL. Fuente: 49 CFR 383.25(a)(3), aplicado por los Servicios al Conductor de WYDOT."},"79":{"q":"Un titular de CDL de Wyoming se autocertifica como 'interestatal no exceptuada' (NI). ¿Qué documentación adicional debe mantener vigente con WYDOT?","options":["Un certificado médico válido de examinador del DOT emitido por un examinador del National Registry","Una carta anual de autoridad operativa interestatal de la FMCSA","Una declaración jurada y notariada de operación solo intraestatal","Una autorización de antecedentes de materiales peligrosos emitida por Wyoming"],"explanation":"Los conductores que se autocertifican como interestatal no exceptuada (NI) o intraestatal no exceptuada (NA) deben estar médicamente calificados y mantener un certificado médico del DOT vigente en el expediente. Los conductores exceptuados (EI/EA) no. El examinador debe estar en el National Registry de la FMCSA. Fuente: páginas de Certificación del Conductor / Certificado Médico del DOT de WYDOT; 49 CFR 383.71(h)."},"80":{"q":"¿Qué le sucede a una CDL de Wyoming si el titular permite que su certificado médico del DOT requerido caduque y pasa a estar 'no certificado'?","options":["La CDL queda sujeta a ser degradada a una licencia de conducir no comercial","La CDL se revoca de inmediato y de forma permanente sin posibilidad de reinstauración","La CDL se convierte automáticamente a estatus de intraestatal exceptuada sin necesidad de acción","La CDL se suspende por exactamente 90 días y luego se reinstaura automáticamente"],"explanation":"Si un titular de CDL de Wyoming no mantiene un certificado médico vigente en el expediente, pasa a estar 'no certificado' y la CDL queda sujeta a ser degradada a una licencia no comercial. Fuente: páginas de Certificación del Conductor / Certificado Médico del DOT de WYDOT; 49 CFR 383.73(o)."},"81":{"q":"¿Qué puntaje mínimo de aprobación requiere Wyoming en cada examen de conocimientos (escrito) de CDL?","options":["80 por ciento","70 por ciento","75 por ciento","90 por ciento"],"explanation":"Los exámenes de conocimientos de CDL de Wyoming son de opción múltiple y requieren al menos 80% de respuestas correctas para aprobar; los solicitantes solo vuelven a tomar los exámenes que reprueban. Fuente: página de Exámenes CDL de WYDOT."},"82":{"q":"¿Con qué frecuencia debe renovarse una CDL de Wyoming para conservar los privilegios de conducción comercial?","options":["Cada 4 años","Cada 5 años","Cada 8 años","Cada 2 años"],"explanation":"Las CDL de Wyoming se emiten en un ciclo de renovación de 4 años. Fuente: información de renovación de licencias de conducir de WYDOT."},"83":{"q":"A medida que Wyoming implementa el proceso del National Registry II (NRII) de la FMCSA, ¿cómo se proporciona normalmente a WYDOT la certificación médica del DOT de un conductor?","options":["El examinador médico certificado transmite los resultados electrónicamente a través del National Registry de la FMCSA al registro de conducción estatal","El conductor envía por correo una fotocopia del certificado en papel al secretario del condado","El empleador envía por fax el certificado a la Patrulla de Caminos de Wyoming","El conductor sube una imagen escaneada a una cuenta personal de conductor de la FMCSA"],"explanation":"Conforme a la regla del National Registry II (NRII) de la FMCSA (vigente desde el 23 de junio de 2025), el examinador médico certificado transmite electrónicamente los resultados de la certificación médica a través del National Registry directamente al registro de la Agencia Estatal de Licencias de Conducir; el examinador tiene hasta la medianoche del siguiente día calendario para ingresar los resultados. Fuente: página de Certificado Médico del DOT de WYDOT; regla NRII de la FMCSA."},"84":{"q":"¿Cuál es el número de formulario del Certificado de Examinador Médico federal que se usa para documentar la calificación médica del DOT para una CDL de Wyoming?","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"explanation":"El Certificado de Examinador Médico es el Formulario MCSA-5876 de la FMCSA (el Informe de Examen Médico más extenso es el MCSA-5875). Fuente: formularios médicos de la FMCSA; página de Certificado Médico del DOT de WYDOT."},"85":{"q":"Un conductor que se autocertifica como 'intraestatal exceptuada' (EA) en Wyoming está haciendo cuál afirmación sobre su operación?","options":["Opera únicamente dentro de Wyoming y no está obligado a cumplir con los requisitos federales de tarjeta médica del DOT","Opera a través de líneas estatales y debe tener una tarjeta médica federal del DOT","Transporta únicamente materiales peligrosos y necesita una exención médica separada","Conduce únicamente vehículos de propiedad gubernamental exentos de licencia"],"explanation":"Intraestatal exceptuada (EA) significa que el conductor opera únicamente en comercio intraestatal y está exceptuado del requisito federal de certificado médico del DOT. Fuente: página de Certificación del Conductor de WYDOT; 49 CFR 383.71(b)."},"86":{"q":"Al solicitar por primera vez una CDL o CLP de Wyoming, ¿qué documento se requiere típicamente para comprobar la identidad?","options":["Un acta de nacimiento certificada o un pasaporte estadounidense válido","Una credencial vigente de identificación del empleador","Un formulario firmado de exención de endoso de CDL","Una tarjeta de registro de vehículo a nombre del solicitante"],"explanation":"Wyoming requiere comprobante de identidad, como un acta de nacimiento certificada (o un pasaporte estadounidense en su lugar), junto con comprobante del número de Seguro Social y de residencia en Wyoming, para solicitar. Fuente: Servicios al Conductor de WYDOT; requisitos de solicitud de CDL de Wyoming."},"87":{"q":"Wyoming administra los exámenes de habilidades de CDL ¿bajo qué modalidad de programación?","options":["Solo con cita previa, después de aprobar todos los exámenes escritos requeridos","Sin cita previa en cualquier quiosco del DMV en todo el estado","Únicamente durante una sola semana anual de exámenes cada primavera","En línea mediante una sesión de video supervisada de forma remota"],"explanation":"Los exámenes de habilidades de Wyoming se aplican solo con cita previa y únicamente después de que el solicitante haya aprobado todos los exámenes escritos (de conocimientos) requeridos. WYDOT ofrece exámenes de habilidades en un número limitado de ubicaciones en todo el estado. Fuente: página de Exámenes CDL de WYDOT."},"88":{"q":"Para el examen de habilidades de CDL de Wyoming, ¿quién es responsable de proporcionar un vehículo representativo de la clase apropiada?","options":["El solicitante debe suministrar un vehículo representativo de la clase/tipo que se está examinando","WYDOT proporciona un vehículo de prueba propiedad del estado a cada solicitante","El examinador médico certificado proporciona el vehículo de prueba","La Patrulla de Caminos de Wyoming presta un vehículo sin costo"],"explanation":"Los solicitantes deben aportar su propio vehículo representativo de la clase y tipo de CDL que buscan; por ejemplo, un vehículo cisterna debe llevar un endoso N y documentación de purga, y no pueden usarse cargas de materiales peligrosos con placas durante el examen. Fuente: página de Exámenes CDL de WYDOT."},"89":{"q":"En Wyoming, obtener un endoso de materiales peligrosos (H) requiere cuál secuencia de capacitación/examen?","options":["Completar la capacitación teórica ELDT de materiales peligrosos, luego aprobar el examen de conocimientos de materiales peligrosos (más una verificación de antecedentes de la TSA)","Aprobar un examen de habilidades en carretera adicional específico para cisternas","Completar 200 horas de conducción de materiales peligrosos detrás del volante","Obtener un permiso de carga peligrosa emitido por el condado antes de cualquier examen"],"explanation":"Para un endoso de materiales peligrosos (H) por primera vez, debe completarse la capacitación teórica ELDT de materiales peligrosos antes de tomar el examen de conocimientos de materiales peligrosos; también se requiere una evaluación de amenazas de seguridad (verificación de antecedentes) de la TSA. No hay un examen de habilidades separado para materiales peligrosos. Fuente: páginas de Exámenes CDL/Licencia Comercial de WYDOT; 49 CFR Part 380 Subpart B."},"90":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Wyoming para conducción comercial intraestatal (dentro de Wyoming)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Una CDL de Wyoming puede emitirse a los 18 años para operación intraestatal; un conductor debe tener 21 años para operar en comercio interestatal, transportar materiales peligrosos que requieran placas o transportar pasajeros a través de líneas estatales. Fuente: páginas de Permiso de Aprendiz Comercial / Licencia Comercial de WYDOT."},"91":{"q":"¿Por cuánto tiempo permanece válido un permiso de aprendiz comercial (CLP) de Wyoming según WYDOT?","options":["365 días","30 días","60 días","10 años"],"explanation":"Según WYDOT, un CLP de Wyoming es válido por 365 días. (Las reglas federales requieren que el titular espere al menos 14 días después de la emisión antes de tomar el examen de habilidades.) Fuente: página de Permiso de Aprendiz Comercial de WYDOT."},"92":{"q":"Si un conductor de Wyoming deja que una CDL caduque y no la renueva dentro del período de gracia del estado (aproximadamente dos años), ¿qué se requiere generalmente para obtener una CDL de nuevo?","options":["Empezar de cero obteniendo un nuevo CLP y volviendo a tomar los exámenes de conocimientos y de habilidades requeridos","Pagar una tarifa fija por mora y la CDL se reinstaura sin exámenes","Presentar únicamente un nuevo certificado médico del DOT para restaurar la CDL","Esperar cinco años adicionales antes de que se permita cualquier nueva solicitud"],"explanation":"Wyoming permite la renovación de una CDL caducada dentro de un período de gracia de aproximadamente dos años sin volver a examinarse; pasado ese plazo, el conductor debe empezar de cero con un nuevo CLP y volver a tomar los exámenes de conocimientos y de habilidades requeridos. Fuente: información de renovación de licencias de conducir de WYDOT."},"93":{"q":"¿Cuál afirmación describe mejor cómo se tratan los resultados de los exámenes de conocimientos (escritos) de CDL durante la vigencia de un CLP de Wyoming?","options":["Los exámenes de conocimientos aprobados permanecen válidos durante la vigencia del CLP, por lo que solo deben volver a tomarse los exámenes reprobados","Todos los exámenes de conocimientos deben volver a aprobarse el mismo día que el examen de habilidades","Los resultados de los exámenes de conocimientos caducan 7 días después de la fecha del examen","Los exámenes de conocimientos solo deben aprobarse una vez y nunca caducan, incluso sin un CLP"],"explanation":"En Wyoming, los exámenes de conocimientos están vinculados al CLP: los exámenes aprobados permanecen válidos durante la vigencia del permiso, y el solicitante vuelve a tomar solo los exámenes que reprobó. Fuente: página de Exámenes CDL de WYDOT."}},"hi":{"0":{"q":"ओवरसाइज़ परमिट के बिना व्योमिंग राजमार्गों पर अधिकांश वाणिज्यिक वाहनों के लिए अधिकतम कानूनी चौड़ाई क्या है?","options":["8 फीट (96 इंच)","8 फीट 6 इंच (102 इंच)","9 फीट (108 इंच)","10 फीट (120 इंच)"],"explanation":"व्योमिंग अपने राजमार्गों पर वाहन की चौड़ाई 8 फीट 6 इंच (102 इंच) तक सीमित करता है, जो संघीय मानक से मेल खाता है। इससे अधिक चौड़ी किसी भी चीज़ के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: W.S. 31-18-802; Wyoming Highway Patrol Commercial Carrier आकार और वज़न नियम।"},"1":{"q":"परमिट के बिना व्योमिंग राजमार्गों पर अधिकतम कानूनी वाहन ऊँचाई क्या है?","options":["13 फीट","13 फीट 6 इंच","14 फीट","15 फीट"],"explanation":"ओवरसाइज़ परमिट की आवश्यकता होने से पहले व्योमिंग सभी राजमार्गों पर अधिकतम वाहन ऊँचाई 14 फीट की अनुमति देता है। स्रोत: W.S. 31-18-802; Wyoming Highway Patrol Commercial Carrier नियम।"},"2":{"q":"व्योमिंग राजमार्गों पर, ओवरवेट परमिट के बिना एक सिंगल एक्सल कानूनी रूप से अधिकतम कितना भार वहन कर सकता है?","options":["18,000 पाउंड","20,000 पाउंड","22,000 पाउंड","24,000 पाउंड"],"explanation":"व्योमिंग एक सिंगल एक्सल को 20,000 पाउंड तक सीमित करता है, जो संघीय सिंगल-एक्सल सीमा के समान है। स्रोत: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier वज़न सीमाएँ।"},"3":{"q":"परमिट के बिना व्योमिंग राजमार्गों पर एक टैंडेम एक्सल (एक-दूसरे के पास रखे गए दो एक्सल) के लिए अधिकतम कानूनी वज़न क्या है?","options":["32,000 पाउंड","34,000 पाउंड","36,000 पाउंड","40,000 पाउंड"],"explanation":"व्योमिंग एक टैंडेम एक्सल को ओवरवेट परमिट के बिना 36,000 पाउंड तक वहन करने की अनुमति देता है। स्रोत: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier वज़न सीमाएँ।"},"4":{"q":"विशेष परमिटिंग या फ़ॉर्मूला प्रावधान लागू होने से पहले व्योमिंग राजमार्गों पर अनुमत मूल अधिकतम सकल वाहन वज़न (gross vehicle weight) क्या है?","options":["73,280 पाउंड","76,000 पाउंड","80,000 पाउंड","84,000 पाउंड"],"explanation":"व्योमिंग का आधारभूत अधिकतम सकल वाहन वज़न 80,000 पाउंड है, जो संघीय सीमा के अनुरूप है। इससे अधिक वज़न ब्रिज-फ़ॉर्मूला वज़न तालिकाओं द्वारा नियंत्रित होते हैं। स्रोत: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier नियम।"},"5":{"q":"किसी भी ओवरसाइज़ परमिट की आवश्यकता होने से पहले, व्योमिंग में प्रत्येक पहिया कानूनी रूप से कितना वज़न वहन कर सकता है?","options":["8,000 पाउंड","9,000 पाउंड","10,000 पाउंड","12,000 पाउंड"],"explanation":"व्योमिंग प्रत्येक पहिये को 10,000 पाउंड तक सीमित करता है। यह प्रति-पहिया सीमा सिंगल- और टैंडेम-एक्सल सीमाओं की पूरक है। स्रोत: Wyoming Highway Patrol Commercial Carrier वज़न सीमाएँ; W.S. 31-18-805।"},"6":{"q":"ट्रैक्टर-सेमीट्रेलर या मान्यता प्राप्त डबल संयोजन के अलावा वाहनों के संयोजन के लिए व्योमिंग में अनुमत अधिकतम कुल लंबाई क्या है?","options":["75 फीट","81 फीट","85 फीट","97 फीट"],"explanation":"किसी भी अन्य वाहनों के संयोजन के लिए, व्योमिंग 85 फीट की कुल लंबाई सीमा निर्धारित करता है। स्रोत: W.S. 31-18-802 General Requirements।"},"7":{"q":"दो ट्रेलरों वाले व्योमिंग ट्रक-ट्रैक्टर में, पीछे चलने वाली इकाइयों की संयुक्त लंबाई (जोड़ने वाले तंत्र सहित) कितने से अधिक नहीं हो सकती?","options":["75 फीट","81 फीट","85 फीट","88 फीट"],"explanation":"व्योमिंग सेमीट्रेलर और ट्रेलर (या दो सेमीट्रेलर) की संयुक्त लंबाई को, जोड़ने वाले तंत्र सहित, 81 फीट तक सीमित करता है, जिसमें पहला ट्रेलर 48 फीट से अधिक नहीं और दूसरा 40 फीट से अधिक नहीं होना चाहिए। स्रोत: W.S. 31-18-802।"},"8":{"q":"परमिट के बिना व्योमिंग राजमार्गों पर एक ट्राइडेम एक्सल समूह (तीन क्रमागत एक्सल) के लिए अधिकतम कानूनी वज़न क्या है?","options":["38,000 पाउंड","40,000 पाउंड","42,000 पाउंड","48,000 पाउंड"],"explanation":"व्योमिंग ओवरवेट परमिट की आवश्यकता होने से पहले एक ट्राइडेम (तीन क्रमागत) एक्सल समूह पर 42,000 पाउंड तक की अनुमति देता है। स्रोत: W.S. 31-18-805; Wyoming Highway Patrol Commercial Carrier वज़न सीमाएँ।"},"9":{"q":"व्योमिंग में, एकल ट्रेलर संयोजन में, दूसरा ट्रेलर या दूसरा सेमीट्रेलर कितनी लंबाई से अधिक नहीं हो सकता?","options":["28 फीट","33 फीट","40 फीट","48 फीट"],"explanation":"व्योमिंग एक डबल संयोजन में ट्रेलर या दूसरे सेमीट्रेलर को 40 फीट तक सीमित करता है (जोड़ने वाले तंत्र की गिनती नहीं की जाती)। स्रोत: W.S. 31-18-802 General Requirements।"},"10":{"q":"व्योमिंग में लागू संघीय ब्रिज फ़ॉर्मूला किस चीज़ का निर्धारण करने के लिए उपयोग किया जाता है?","options":["किसी पुल को पार करने वाले भार की अधिकतम चौड़ाई","एक्सल की संख्या और दूरी के आधार पर एक्सल के समूह पर अनुमेय सकल वज़न","राज्य के पुलों को पार करने वाले भारी ट्रकों पर लगाया जाने वाला टोल","इंटरस्टेट पुलों पर आवश्यक न्यूनतम टायर दबाव"],"explanation":"व्योमिंग संघीय ब्रिज फ़ॉर्मूला (W = 500[LN/(N-1) + 12N + 36]) को लागू करता है ताकि एक्सल की संख्या (N) और सिरों के बीच की दूरी (L) के आधार पर दो या अधिक क्रमागत एक्सल के किसी भी समूह पर अनुमेय सकल वज़न निर्धारित किया जा सके। स्रोत: Wyoming वज़न तालिकाएँ; W.S. 31-18-805।"},"11":{"q":"व्योमिंग की ब्रिज-फ़ॉर्मूला वज़न तालिकाओं के तहत, Table I (इनर-ब्रिज फ़ॉर्मूला तालिका) द्वारा इंटरस्टेट प्रणाली पर अधिकतम कितना सकल वज़न अधिकृत किया जा सकता है?","options":["80,000 पाउंड","105,500 पाउंड","117,000 पाउंड","129,000 पाउंड"],"explanation":"व्योमिंग की Table I (इनर-ब्रिज फ़ॉर्मूला जो सभी क्रमागत एक्सल समूहों की जाँच करती है) का उपयोग करते हुए, जब एक्सल और ब्रिज सीमाएँ पूरी होती हैं तो इंटरस्टेट, प्राइमरी और सेकंडरी राजमार्गों पर 117,000 पाउंड तक का सकल वज़न वहन किया जा सकता है। स्रोत: Wyoming Highway Patrol Commercial Carrier वज़न तालिकाएँ; WYDOT।"},"12":{"q":"व्योमिंग में, एक विभाज्य भार (divisible load) ओवरवेट परमिट के बिना 80,000 पाउंड सकल वज़न से कब अधिक हो सकता है?","options":["केवल इंटरस्टेट राजमार्गों पर दिन के उजाले के घंटों के दौरान","जब सभी एक्सल और ब्रिज वज़नों पर कानूनी हो और कम से कम उस सकल वज़न के लिए पंजीकृत/लाइसेंस प्राप्त हो","केवल यदि भार कृषि संबंधी हो और 50 मील के भीतर ले जाया जाए","कभी नहीं, क्योंकि 80,000 पाउंड से अधिक के किसी भी भार के लिए हमेशा परमिट की आवश्यकता होती है"],"explanation":"व्योमिंग एक विभाज्य भार को राज्य और इंटरस्टेट राजमार्गों पर बिना परमिट के 80,000 पाउंड से अधिक होने की अनुमति देता है, बशर्ते वह प्रत्येक एक्सल वज़न पर और ब्रिज फ़ॉर्मूला के तहत कानूनी हो और वाहन कम से कम अपने वास्तविक सकल वज़न के लिए लाइसेंस प्राप्त (पंजीकृत) हो। स्रोत: Wyoming Highway Patrol Commercial Carrier नियम; WYDOT।"},"13":{"q":"एक कैरियर व्योमिंग राजमार्ग पर 8 फीट 6 इंच से अधिक चौड़ा भार ले जाना चाहता है। उसे पहले क्या करना चाहिए?","options":["कुछ नहीं, जब तक भार 10 फीट से कम चौड़ा है","राजमार्ग पर संचालन से पहले एक ओवरसाइज़ परमिट (या अनुमति) प्राप्त करें","बस केवल रात में हज़ार्ड लाइट के साथ यात्रा करें","टायर का दबाव कम करें और स्थानीय पुलिस को सूचित करें"],"explanation":"व्योमिंग में कानूनी आकार या वज़न से अधिक किसी भी वाहन या भार को व्योमिंग राज्य राजमार्ग पर संचालन से पहले परमिट या अनुमति प्राप्त करनी होगी। स्रोत: Wyoming Highway Patrol Commercial Carrier नियम; WYDOT Permitting।"},"14":{"q":"कौन सा व्योमिंग कार्यालय उन ओवरवेट/ओवरसाइज़ परमिटों को संभालता है जो किसी पोर्ट ऑफ़ एंट्री या हाईवे शॉप द्वारा जारी की जा सकने वाली सीमाओं से अधिक होते हैं?","options":["यात्रा के प्रत्येक काउंटी में काउंटी शेरिफ़ का कार्यालय","शायेन (Cheyenne) में Overweight Loads Office (WYDOT)","Federal Highway Administration का क्षेत्रीय कार्यालय","Wyoming Game and Fish Department"],"explanation":"नियमित पोर्ट ऑफ़ एंट्री/हाईवे-शॉप सीमाओं से परे परमिट WYDOT के शायेन (Cheyenne) स्थित Overweight Loads Office (307-777-4376) के माध्यम से जारी किए जाते हैं। पोर्ट ऑफ़ एंट्री और हाईवे शॉप उससे नीचे की निर्धारित सीमाओं तक परमिट जारी कर सकते हैं। स्रोत: Wyoming Highway Patrol Commercial Carrier; WYDOT।"},"15":{"q":"एस्कॉर्ट की आवश्यकता वाले एक ओवरसाइज़ भार के लिए व्योमिंग में सामान्य अनुमत यात्रा खिड़की (travel window) क्या है?","options":["केवल मध्यरात्रि से सुबह 6:00 बजे तक","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक","केवल सोमवार से शुक्रवार, सुबह 9:00 बजे से शाम 5:00 बजे तक","बिना किसी प्रतिबंध के दिन में 24 घंटे"],"explanation":"व्योमिंग में ओवरसाइज़ संचलन आम तौर पर दिन के उजाले तक सीमित होते हैं, सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक, जिसमें सप्ताहांत भी शामिल हैं; सीमित रात्रि यात्रा केवल उचित प्रकाश व्यवस्था के साथ इंटरस्टेट पर संकरे भारों के लिए अनुमत है। स्रोत: WYDOT ओवरसाइज़ परमिट शर्तें।"},"16":{"q":"व्योमिंग राजमार्गों पर वाहनों के किसी एक संयोजन में अनुमत एकल वाहनों की अधिकतम संख्या क्या है?","options":["दो","तीन","चार","पाँच"],"explanation":"व्योमिंग का क़ानून प्रावधान करता है कि वाहनों के किसी भी संयोजन में तीन से अधिक एकल वाहन नहीं होंगे। स्रोत: W.S. 31-18-802 General Requirements।"},"17":{"q":"व्योमिंग में, 26,001 lbs या उससे अधिक के सकल संयोजन वज़न रेटिंग (GCWR) वाले संयोजन वाहन को संचालित करने के लिए कौन सी CDL श्रेणी आवश्यक है, जहाँ खींची जाने वाली इकाई का GVWR 10,000 lbs से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"व्योमिंग संघीय CDL वर्गीकरण (49 CFR 383.91) का पालन करता है: एक Class A CDL किसी भी वाहनों के संयोजन को कवर करता है जिसका GCWR 26,001 lbs या उससे अधिक हो, बशर्ते खींची जाने वाली इकाई(याँ) का GVWR 10,000 lbs से अधिक हो। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91।"},"18":{"q":"व्योमिंग नियमों के तहत, 26,001 lbs या उससे अधिक GVWR वाला एक एकल वाहन (या ऐसा वाहन जो 10,000 lbs से अधिक न होने वाली इकाई को खींच रहा हो) के लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class C","Class B","Class A","Class M"],"explanation":"व्योमिंग संघीय परिभाषाओं का उपयोग करता है: एक Class B CDL 26,001 lbs या उससे अधिक GVWR वाले एकल वाहन को, या ऐसे किसी वाहन को कवर करता है जो 10,000 lbs से अधिक न होने वाले GVWR वाली इकाई को खींच रहा हो। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91।"},"19":{"q":"एक व्योमिंग वाहन जो Class A या B वज़न सीमाओं को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लेकार्ड वाले खतरनाक पदार्थ ले जाता है, के लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"व्योमिंग संघीय परिभाषा का पालन करता है: एक Class C CDL ऐसे वाहन को कवर करता है जो Class A या B मानदंडों को पूरा नहीं करता लेकिन या तो 16 या अधिक लोगों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लेकार्ड की आवश्यकता वाले खतरनाक पदार्थों को ले जाने के लिए उपयोग किया जाता है। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.91।"},"20":{"q":"व्योमिंग किसी CDL पर कौन सा एंडोर्समेंट कोड लगाता है जो ड्राइवर को टैंक वाहन संचालित करने के लिए अधिकृत करता है?","options":["T","N","H","X"],"explanation":"व्योमिंग में टैंक वाहन एंडोर्समेंट कोड N है, जो संघीय एंडोर्समेंट कोड के अनुरूप है। (कोड X एक संयुक्त टैंक/HazMat एंडोर्समेंट को दर्शाता है।) स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153।"},"21":{"q":"व्योमिंग में, डबल या ट्रिपल ट्रेलरों को खींचने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["N एंडोर्समेंट","P एंडोर्समेंट","T एंडोर्समेंट","S एंडोर्समेंट"],"explanation":"व्योमिंग में एक से अधिक ट्रेलर खींचने वाले संयोजन को संचालित करने के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है। यह डबल/ट्रिपल ज्ञान परीक्षण पास करके प्राप्त किया जाता है। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.153।"},"22":{"q":"केवल INTRASTATE (राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित व्योमिंग CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"व्योमिंग केवल इंट्रास्टेट संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; इंटरस्टेट संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Wyoming CDL Manual (WYDOT) / W.S. Title 31 और 49 CFR 391.11।"},"23":{"q":"INTERSTATE वाणिज्यिक ड्राइविंग को अधिकृत करने वाला व्योमिंग CDL रखने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","23 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में CMV संचालित करने के लिए ड्राइवर का कम से कम 21 वर्ष का होना आवश्यक है; 18-20 वर्ष की आयु के ड्राइवर व्योमिंग में इंट्रास्टेट ड्राइविंग तक सीमित हैं। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 391.11।"},"24":{"q":"व्योमिंग में CDL कौशल (सड़क) परीक्षण देने से पहले, एक आवेदक को Commercial Learner Permit (CLP) कितने समय तक रखना आवश्यक है?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"धारक के CDL कौशल परीक्षण देने के पात्र होने से पहले CLP को जारी होने के बाद कम से कम 14 दिनों तक रखा जाना चाहिए। यह संघीय प्रतीक्षा अवधि व्योमिंग में लागू होती है। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25।"},"25":{"q":"व्योमिंग CLP पर CMV संचालित करते समय, परमिट धारक के साथ हमेशा एक ऐसा व्यक्ति होना चाहिए जिसके पास उस वाहन के लिए वैध CDL हो। उस CDL धारक को कहाँ स्थित होना चाहिए?","options":["ड्राइवर के ठीक पीछे की सीट पर","वाहन के केबिन के अंदर कहीं भी","CLP धारक के बगल में आगे की यात्री सीट पर","एक अलग वाहन में पीछे चलते हुए"],"explanation":"एक CLP धारक के साथ हर समय एक उचित रूप से लाइसेंस प्राप्त CDL धारक होना चाहिए जो ड्राइवर के बगल में आगे की सीट पर बैठा हो और सीधी निगरानी प्रदान करे। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25।"},"26":{"q":"व्योमिंग CLP धारक द्वारा टैंक वाहन संचालित करते समय कौन सी पाबंदी लागू होती है, जिसके परमिट पर N (टैंक) क्षेत्र हो?","options":["टैंक को 50% क्षमता तक भरा जा सकता है","टैंक खाली होना चाहिए (कोई तरल या गैस कार्गो नहीं)","केवल पानी ले जाया जा सकता है","CLP पर बिल्कुल भी टैंक संचालन की अनुमति नहीं है"],"explanation":"टैंक (N) प्राधिकरण वाला एक CLP धारक केवल ऐसे टैंक वाहन को संचालित कर सकता है जो सभी तरल या गैसीय कार्गो से खाली हो; CDL जारी होने तक भरे हुए टैंक प्रतिबंधित हैं। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.25।"},"27":{"q":"व्योमिंग में, CDL या कवर किए गए एंडोर्समेंट परीक्षण से पहले आवश्यक Entry-Level Driver Training (ELDT) पूरा करने के लिए ड्राइवर को किस संघीय डेटाबेस का उपयोग करना चाहिए?","options":["The National Driver Register","The FMCSA Training Provider Registry (TPR)","The Wyoming WYDOT eDriver portal","The CDLIS clearinghouse"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता के साथ पूरा किया जाना चाहिए, जो राज्य द्वारा सत्यापन के लिए प्रशिक्षु के पूरा होने को दर्ज करता है। स्रोत: Wyoming CDL Manual (WYDOT) / FMCSA ELDT नियम, 49 CFR Part 380।"},"28":{"q":"व्योमिंग में परीक्षण से पहले किन आवेदकों को ELDT पूरा करना आवश्यक है?","options":["केवल 21 वर्ष से कम आयु के ड्राइवर","पहली बार Class A या B आवेदक, Class B-से-A अपग्रेड, और पहली बार P, S, या H एंडोर्समेंट आवेदक","केवल HazMat (H) एंडोर्समेंट आवेदक","सभी CDL नवीनीकरण आवेदक"],"explanation":"संघीय ELDT (7 फ़रवरी 2022 से प्रभावी) पहली बार Class A/B आवेदकों, Class B से Class A में अपग्रेड करने वाले ड्राइवरों, और P, S, या H एंडोर्समेंट के पहली बार आवेदकों पर लागू होता है। यह पूर्वव्यापी (retroactive) नहीं है। स्रोत: FMCSA ELDT नियम, 49 CFR Part 380 / WYDOT।"},"29":{"q":"ज्ञान परीक्षण पास करने के अलावा, व्योमिंग HazMat (H) एंडोर्समेंट के लिए क्या आवश्यक करता है?","options":["फ़िंगरप्रिंटिंग सहित एक TSA सुरक्षा खतरा आकलन","एक अलग Wyoming Highway Patrol साक्षात्कार","एक दूसरी शारीरिक परीक्षा","एक नोटरीकृत नियोक्ता प्रायोजन पत्र"],"explanation":"व्योमिंग H एंडोर्समेंट के आवेदकों को HazMat ज्ञान परीक्षण और ELDT सैद्धांतिक प्रशिक्षण के अलावा एक Transportation Security Administration (TSA) सुरक्षा खतरा आकलन पास करने की आवश्यकता रखता है, जिसमें फ़िंगरप्रिंटिंग और एक आपराधिक/आव्रजन पृष्ठभूमि जाँच शामिल है। स्रोत: WYDOT Hazardous Materials Assessment पेज / 49 CFR 1572।"},"30":{"q":"HazMat (H) एंडोर्समेंट बनाए रखने के लिए व्योमिंग ड्राइवर को TSA सुरक्षा खतरा आकलन कितनी बार नवीनीकृत करना चाहिए?","options":["हर साल","हर 2 वर्ष","हर 5 वर्ष","हर 8 वर्ष"],"explanation":"HazMat एंडोर्समेंट के लिए TSA सुरक्षा खतरा आकलन पाँच वर्षों के लिए वैध होता है और H एंडोर्समेंट बनाए रखने के लिए इसे (नई पृष्ठभूमि जाँच और ज्ञान परीक्षण के साथ) नवीनीकृत किया जाना चाहिए; इसे डाक द्वारा नवीनीकृत नहीं किया जा सकता। स्रोत: WYDOT Hazardous Materials Assessment पेज / 49 CFR 1572।"},"31":{"q":"व्योमिंग में, किसी ड्राइवर के S (School Bus) एंडोर्समेंट रखने से पहले, कौन सा अन्य एंडोर्समेंट भी प्राप्त करना आवश्यक है?","options":["H (HazMat)","N (Tank)","P (Passenger)","T (Doubles/Triples)"],"explanation":"S (School Bus) एंडोर्समेंट के लिए ड्राइवर को पहले P (Passenger) एंडोर्समेंट के लिए योग्य होना आवश्यक है, क्योंकि स्कूल बस एक यात्री-वहन वाहन है। ज्ञान और कौशल दोनों परीक्षण लागू होते हैं। स्रोत: Wyoming CDL Manual (WYDOT) / 49 CFR 383.123।"},"32":{"q":"एक व्योमिंग CDL आवेदक को जारीकर्ता एजेंसी (WYDOT Driver Services) को कौन सा दस्तावेज़ समूह प्रस्तुत करना चाहिए?","options":["केवल एक वर्तमान Wyoming फ़ोटो ड्राइवर लाइसेंस","पहचान/वैध उपस्थिति का प्रमाण, Social Security नंबर, और Wyoming निवास","केवल एक पासपोर्ट और एक नियोक्ता पत्र","एक जन्म प्रमाण पत्र और एक वाहन शीर्षक"],"explanation":"व्योमिंग CDL आवेदकों से अमेरिका में पहचान और वैध उपस्थिति साबित करने, एक Social Security नंबर प्रदान करने, और Wyoming निवास का प्रमाण (आमतौर पर दो दस्तावेज़) दिखाने की आवश्यकता रखता है। स्रोत: WYDOT Driver Services दस्तावेज़ आवश्यकताएँ।"},"33":{"q":"व्योमिंग CDL स्व-प्रमाणन (self-certification) पर, एक ड्राइवर जो राज्य की सीमाओं के पार संचालन करता है और संघीय शारीरिक योग्यता से छूट प्राप्त नहीं है, उसे कौन सी श्रेणी चुननी चाहिए?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"इंटरस्टेट वाणिज्य में एक ड्राइवर जो संघीय चिकित्सा नियमों से छूट प्राप्त नहीं है, वह Non-Excepted Interstate (NI) के रूप में स्व-प्रमाणित करता है और उसे फ़ाइल पर एक वैध DOT चिकित्सा परीक्षक प्रमाण पत्र बनाए रखना चाहिए। स्रोत: WYDOT CDL self-certification / 49 CFR 383.71।"},"34":{"q":"कौन सी व्योमिंग CDL स्व-प्रमाणन श्रेणी में ड्राइवर को संघीय (DOT) चिकित्सा परीक्षक प्रमाण पत्र बनाए रखने की आवश्यकता नहीं होती?","options":["Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Interstate (EI)","NI और NA दोनों"],"explanation":"Excepted Interstate (EI) और Excepted Intrastate (EA) ड्राइवरों को DOT चिकित्सा कार्ड बनाए रखने से छूट है; केवल Non-Excepted ड्राइवरों (NI और NA) को एक वर्तमान चिकित्सा परीक्षक प्रमाण पत्र रखना चाहिए। स्रोत: WYDOT CDL self-certification / 49 CFR 383.71 और 390.3।"},"35":{"q":"वह अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर एक ड्राइवर व्योमिंग में एक वाणिज्यिक मोटर वाहन (CMV) को कानूनी रूप से संचालित कर सकता है?","options":["0.04 प्रतिशत","0.08 प्रतिशत","0.02 प्रतिशत","0.10 प्रतिशत"],"explanation":"व्योमिंग संघीय CMV मानक का पालन करता है: 0.04 प्रतिशत या उससे अधिक BAC के साथ CMV संचालित करना गैरकानूनी है, जो नियमित ड्राइवरों के लिए 0.08 सीमा का आधा है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"36":{"q":"व्योमिंग के अंतर्निहित सहमति (implied consent) कानून के तहत, राज्य में किसी वाहन को चलाने या उसके वास्तविक भौतिक नियंत्रण में होने से, एक ड्राइवर को किस बात के लिए सहमति देने वाला माना जाता है?","options":["कानूनी रूप से अनुरोध किए जाने पर रक्त, साँस या मूत्र का रासायनिक परीक्षण","किसी भी चेकपॉइंट पर वाहन की तलाशी","किसी भी स्टॉप के बाद अनिवार्य नशा उपचार","एक फ़ील्ड सोब्रायटी परीक्षण जिसे अस्वीकार नहीं किया जा सकता"],"explanation":"व्योमिंग का अंतर्निहित सहमति क़ानून प्रावधान करता है कि राज्य में किसी वाहन को चलाने या उसके वास्तविक भौतिक नियंत्रण में रहने वाला कोई भी व्यक्ति, किसी अधिकारी द्वारा कानूनी रूप से अनुरोध किए जाने पर रक्त, साँस या मूत्र के रासायनिक परीक्षण के लिए स्वतः सहमति देता है। स्रोत: Wyoming CDL Manual; W.S. 31-6-102 (implied consent)।"},"37":{"q":"0.04 या उससे अधिक BAC के साथ CMV चलाने जैसे पहले प्रमुख (अनिवार्य) अपराध के लिए, एक व्योमिंग CDL धारक कितने समय के लिए अयोग्य (disqualified) होता है (गैर-HazMat)?","options":["1 वर्ष","6 महीने","90 दिन","3 वर्ष"],"explanation":"किसी प्रमुख अपराध के लिए पहली दोषसिद्धि के परिणामस्वरूप व्योमिंग में 1-वर्ष की CDL अयोग्यता होती है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"38":{"q":"यदि कोई ड्राइवर प्लेकार्ड वाले खतरनाक पदार्थों के लिए प्लेकार्ड वाले CMV को संचालित करते समय पहला प्रमुख अपराध करता है, तो व्योमिंग अयोग्यता अवधि बढ़कर कितनी हो जाती है?","options":["3 वर्ष","2 वर्ष","18 महीने","5 वर्ष"],"explanation":"प्लेकार्ड वाले खतरनाक पदार्थों का परिवहन करते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 वर्ष से बढ़ाकर 3 वर्ष कर देता है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"39":{"q":"दूसरे प्रमुख (अनिवार्य) अपराध के लिए व्योमिंग CDL अयोग्यता अवधि क्या है?","options":["आजीवन","10 वर्ष","5 वर्ष","3 वर्ष"],"explanation":"किसी भी प्रमुख अपराध के लिए दूसरी दोषसिद्धि के परिणामस्वरूप आजीवन CDL अयोग्यता होती है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"40":{"q":"एक व्योमिंग CDL धारक CMV संचालित करते समय कानूनी रूप से अनुरोध किए गए रासायनिक परीक्षण को अस्वीकार करता है। इस अस्वीकृति के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["1 वर्ष","90 दिन","6 महीने","60 दिन"],"explanation":"आवश्यक रासायनिक परीक्षण को अस्वीकार करना एक प्रमुख अपराध माना जाता है, जिसके परिणामस्वरूप कम से कम 1-वर्ष की अयोग्यता होती है (HazMat के लिए प्लेकार्ड होने पर 3 वर्ष)। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"41":{"q":"निम्नलिखित में से कौन सा एक व्योमिंग CDL धारक के लिए 'गंभीर यातायात उल्लंघन' (serious traffic violation) के रूप में वर्गीकृत है?","options":["सीमा से 15 mph या उससे अधिक गति","सीमा से 5 mph अधिक गति","एक पार्किंग उल्लंघन","एक समाप्त पंजीकरण स्टिकर"],"explanation":"गंभीर यातायात उल्लंघनों में सीमा से 15 mph या उससे अधिक की गति, लापरवाह ड्राइविंग, बहुत पास से पीछा करना, अनियमित/अनुचित लेन परिवर्तन, और CMV चलाते समय टेक्स्टिंग या हैंडहेल्ड फ़ोन का उपयोग शामिल हैं। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"42":{"q":"एक व्योमिंग CDL धारक को 3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["60 दिन","30 दिन","120 दिन","90 दिन"],"explanation":"3 वर्षों के भीतर दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-दिन की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"43":{"q":"3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं से तीन गंभीर यातायात उल्लंघनों के लिए एक व्योमिंग CDL धारक कितने समय के लिए अयोग्य होता है?","options":["120 दिन","60 दिन","1 वर्ष","90 दिन"],"explanation":"3 वर्षों के भीतर तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप 120-दिन की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"44":{"q":"व्योमिंग में CMV संचालित करते समय किन CDL एंडोर्समेंट धारकों को हर रेलरोड-राजमार्ग ग्रेड क्रॉसिंग पर रुकना आवश्यक है?","options":["यात्री और खतरनाक पदार्थ (प्लेकार्ड वाले) वाहन ड्राइवर","केवल टैंकर एंडोर्समेंट वाले ड्राइवर","बिना किसी अपवाद के सभी CMV ड्राइवर","केवल 21 वर्ष से कम आयु के स्कूल बस ड्राइवर"],"explanation":"यात्रियों या प्लेकार्ड वाले खतरनाक पदार्थों को ले जाने वाले ड्राइवरों को सभी रेलरोड क्रॉसिंग पर रुकना चाहिए; अन्य CMV को धीमा होकर जाँच करनी चाहिए। स्रोत: Wyoming CDL Manual; 49 CFR 392.10 / 383.51।"},"45":{"q":"CMV में पहली बार रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम व्योमिंग अयोग्यता क्या है?","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"पहले रेलरोड-क्रॉसिंग उल्लंघन के परिणामस्वरूप 60 दिनों से कम नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51 Table 3।"},"46":{"q":"एक ड्राइवर 3 वर्षों के भीतर दूसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["120 दिन","60 दिन","90 दिन","1 वर्ष"],"explanation":"3 वर्षों के भीतर दूसरे रेलरोड-क्रॉसिंग उल्लंघन के परिणामस्वरूप 120 दिनों से कम नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; 49 CFR 383.51 Table 3।"},"47":{"q":"3-वर्ष की अवधि के भीतर तीसरे रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["1 वर्ष","120 दिन","60 दिन","आजीवन"],"explanation":"3 वर्षों के भीतर तीसरे या उसके बाद के रेलरोड-क्रॉसिंग उल्लंघन के परिणामस्वरूप 1 वर्ष से कम नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; 49 CFR 383.51 Table 3।"},"48":{"q":"CMV संचालित करते समय आउट-ऑफ़-सर्विस (OOS) आदेश का उल्लंघन करने की किसी CDL ड्राइवर की पहली दोषसिद्धि के लिए न्यूनतम अयोग्यता क्या है?","options":["180 दिन से 1 वर्ष","30 से 60 दिन","2 से 5 वर्ष","60 से 120 दिन"],"explanation":"पहले OOS-आदेश उल्लंघन के परिणामस्वरूप 180 दिनों से कम नहीं और 1 वर्ष से अधिक नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; 49 CFR 383.51 Table 4।"},"49":{"q":"10-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ़-सर्विस आदेश उल्लंघन के लिए अयोग्यता सीमा क्या है (गैर-HazMat/गैर-यात्री)?","options":["2 से 5 वर्ष","180 दिन से 1 वर्ष","1 से 2 वर्ष","3 से 5 वर्ष"],"explanation":"10 वर्षों के भीतर दूसरे OOS-आदेश उल्लंघन के परिणामस्वरूप 2 वर्षों से कम नहीं और 5 वर्षों से अधिक नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; 49 CFR 383.51 Table 4।"},"50":{"q":"प्लेकार्ड वाले खतरनाक पदार्थों या 16-या-अधिक यात्रियों का परिवहन करने वाला एक ड्राइवर पहला आउट-ऑफ़-सर्विस आदेश उल्लंघन करता है। अयोग्यता सीमा क्या है?","options":["180 दिन से 2 वर्ष","60 से 120 दिन","1 से 3 वर्ष","3 से 5 वर्ष"],"explanation":"प्लेकार्ड वाले HazMat को ढोते समय या 16+ यात्रियों को ले जाते समय पहले OOS-आदेश उल्लंघन के परिणामस्वरूप 180 दिनों से कम नहीं और 2 वर्षों से अधिक नहीं की अयोग्यता होती है। स्रोत: Wyoming CDL Manual; 49 CFR 383.51 Table 4।"},"51":{"q":"व्योमिंग में CMV चलाते समय टेक्स्टिंग करना या हैंडहेल्ड मोबाइल फ़ोन का उपयोग करना किस प्रकार के CDL उल्लंघन के रूप में माना जाता है?","options":["एक गंभीर यातायात उल्लंघन जो 60/120-दिन की अयोग्यता की ओर गिना जाता है","एक गैर-रिपोर्ट करने योग्य मामूली उल्लंघन","एक स्वचालित आजीवन अयोग्यता","एक रेलरोड-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग और हैंडहेल्ड फ़ोन का उपयोग गंभीर यातायात उल्लंघन हैं; 3 वर्षों के भीतर दो उल्लंघन 60-दिन की और तीन उल्लंघन 120-दिन की अयोग्यता लाते हैं। स्रोत: Wyoming CDL Manual; 49 CFR 383.51; 49 CFR 392.80/392.82।"},"52":{"q":"व्योमिंग में एक CMV ड्राइवर को एक ही टेक्स्टिंग-या-हैंडहेल्ड-फ़ोन-चलाते-समय अपराध के लिए अधिकतम कितना संघीय सिविल दंड भुगतना पड़ सकता है?","options":["$2,750 तक","$250 तक","$11,000 तक","$500 तक"],"explanation":"एक CMV ड्राइवर पर प्रति टेक्स्टिंग/हैंडहेल्ड-फ़ोन अपराध के लिए $2,750 तक का जुर्माना लगाया जा सकता है; इसकी अनुमति देने के लिए नियोक्ता मोटर कैरियर पर $11,000 तक का जुर्माना लगाया जा सकता है। स्रोत: FMCSA Mobile Phone / No-Texting नियम; 49 CFR 392.80-392.82, व्योमिंग में लागू।"},"53":{"q":"आजीवन CDL अयोग्यता के बाद, सीमित पुनर्बहाली प्रावधान के तहत एक व्योमिंग ड्राइवर कब (यदि बिल्कुल भी) पुनर्बहाली के लिए आवेदन करने के पात्र हो सकता है?","options":["कम से कम 10 वर्षों के बाद, शर्तों के साथ (HazMat अपात्र रहता है)","5 वर्षों के बाद स्वचालित रूप से","किसी भी परिस्थिति में कभी नहीं","स्वच्छ रिकॉर्ड के साथ 3 वर्षों के बाद"],"explanation":"आजीवन के लिए अयोग्य घोषित एक ड्राइवर, कम से कम 10 वर्षों के बाद और पुनर्बहाली शर्तों को पूरा करने पर, पुनर्बहाली के लिए विचार किया जा सकता है; HazMat पात्रता बहाल नहीं की जाती। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"54":{"q":"DUI या किसी अपराध (felony) को अंजाम देने के लिए वाहन का उपयोग करने जैसे अयोग्य करने वाले प्रमुख अपराध एक व्योमिंग CDL धारक पर तब भी लागू होते हैं जब अपराध किस प्रकार के वाहन में होता है?","options":["कोई भी मोटर वाहन, जिसमें ड्राइवर की निजी कार शामिल है","केवल एक प्लेकार्ड वाला HazMat CMV","केवल नियोक्ता के स्वामित्व वाला वाहन","केवल 26,001 lbs GVWR से अधिक का वाहन"],"explanation":"DUI जैसे प्रमुख अपराध वाहन के प्रकार की परवाह किए बिना CDL के विरुद्ध गिने जाते हैं; निजी कार में DUI के लिए दोषी ठहराया गया एक CDL धारक फिर भी अयोग्य हो जाता है। स्रोत: Wyoming CDL Manual; W.S. 31-7-305; 49 CFR 383.51।"},"55":{"q":"व्योमिंग में, प्लेकार्ड वाली खतरनाक सामग्री ढो रहा एक CDL चालक एक रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग के पास पहुंचता है। वाहन को कहां रुकना चाहिए?","options":["निकटतम रेल से 5 feet से अधिक पास नहीं और 25 feet से अधिक दूर नहीं","निकटतम रेल से 50 feet से अधिक पास नहीं और 100 feet से अधिक दूर नहीं","निकटतम रेल से कम से कम 10 feet लेकिन 30 feet से अधिक नहीं","निकटतम रेल से 15 feet से अधिक पास नहीं और 50 feet से अधिक दूर नहीं"],"explanation":"व्योमिंग नियम: ऐसा वाहन जिस पर खतरनाक सामग्री के लिए प्लेकार्ड लगा है (या जो कोई क्लोरीन ढोता है या जिसमें लदे/खाली HazMat कार्गो टैंक हैं) को निकटतम रेल से 15 और 50 feet के बीच रुकना चाहिए और तभी आगे बढ़ना चाहिए जब कोई ट्रेन न आ रही हो। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 9 - Hazardous Materials, रेलमार्ग क्रॉसिंग प्रावधान।"},"56":{"q":"यात्रियों को ढो रहे एक व्योमिंग बस चालक को एक रेलमार्ग क्रॉसिंग पर रुकना चाहिए। क्रॉसिंग से पहले आवश्यक रुकने का क्षेत्र क्या है?","options":["क्रॉसिंग से पहले 20 और 60 feet के बीच","क्रॉसिंग से पहले 15 और 50 feet के बीच","क्रॉसिंग से पहले 10 और 40 feet के बीच","क्रॉसिंग से पहले 25 और 75 feet के बीच"],"explanation":"व्योमिंग नियम: बस चालकों को बस को रेलमार्ग क्रॉसिंग से पहले 15 और 50 feet के बीच रोकना चाहिए, फिर क्रॉस करने से पहले दोनों दिशाओं में ट्रेनों के लिए देखना और सुनना चाहिए। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 4 - Transporting Passengers (Railroad-Highway Crossings and Stops)।"},"57":{"q":"व्योमिंग के Move Over कानून के तहत, अपनी दिशा में दो या अधिक लेन वाले एक इंटरस्टेट या अन्य राजमार्ग पर एक CDL चालक दृश्य संकेत प्रदर्शित कर रहे एक रुके हुए आपातकालीन वाहन के पास पहुंचता है। सुरक्षित होने पर चालक को क्या करना आवश्यक है?","options":["आपातकालीन वाहन के चले जाने तक पूरी तरह रुक जाना","हॉर्न बजाना और उसी लेन में निर्धारित गति पर जारी रखना","आपातकालीन वाहन के बगल वाली लेन के अलावा किसी लेन में विलय करना (उससे सबसे दूर वाली लेन)","दाहिने कंधे पर खींच लेना और एक अधिकारी द्वारा आगे जाने का इशारा करने का इंतजार करना"],"explanation":"व्योमिंग नियम: यात्रा की दिशा में दो या अधिक लेन वाले राजमार्ग पर, दृश्य संकेतों का उपयोग कर रहे एक रुके हुए अधिकृत आपातकालीन वाहन के पास पहुंच रहे चालक को सुरक्षित होने पर उस वाहन से सटी हुई लेन के अलावा किसी लेन में (सबसे दूर वाली लेन में) विलय करना चाहिए; यदि लेन बदलना असुरक्षित है, तो गति धीमी करें और सावधानी से आगे बढ़ें। स्रोत: Wyoming Statute 31-5-224; 2024 Wyoming CDL Manual (Move-Over Laws)।"},"58":{"q":"व्योमिंग के Move Over कानून के तहत, 45 mph या उससे अधिक पर निर्धारित एक दो-लेन सड़क पर, एक रुके हुए आपातकालीन या टो वाहन को पार कर रहे एक चालक को जो सुरक्षित रूप से लेन नहीं बदल सकता, उसे गति को किस स्तर तक कम करना चाहिए?","options":["निर्धारित गति सीमा से 20 mph कम","निर्धारित गति सीमा से 10 mph कम","निर्धारित गति सीमा से 15 mph कम","निर्धारित सीमा की परवाह किए बिना ठीक 25 mph"],"explanation":"व्योमिंग नियम: 45 mph या उससे अधिक की निर्धारित गति सीमा वाली एक दो-लेन सड़क पर, दृश्य संकेतों का उपयोग कर रहे एक रुके हुए आपातकालीन, उपयोगिता, रखरखाव, या टो वाहन को पार करते समय एक चालक को निर्धारित गति सीमा से 20 mph कम गति तक धीमा करना चाहिए। स्रोत: Wyoming Statute 31-5-224।"},"59":{"q":"व्योमिंग का Move Over कानून (W.S. 31-5-224) पुलिस और एम्बुलेंस से अधिक की रक्षा करता है। इनमें से कौन सा भी स्पष्ट रूप से शामिल है?","options":["अपने हैज़र्ड फ्लैशर चालू किए हुए कंधे पर खड़ी कोई यात्री कार","एक खराब-वाहन स्थल पर एक चमकती लाल या लाल-और-नीली लैंप प्रदर्शित कर रहा एक रेकर या टो ट्रक","बच्चों को बैठाने के लिए रुकी हुई एक स्कूल बस","एक शहर की सड़क पर डबल-पार्क की हुई एक डिलीवरी ट्रक"],"explanation":"व्योमिंग नियम: Move Over कानून अधिकृत आपातकालीन वाहनों, नगरपालिका/सार्वजनिक-उपयोगिता/राजमार्ग निर्माण या रखरखाव वाहनों, और एक दुर्घटनाग्रस्त, खराब, या रुके हुए वाहन के स्थल पर रेकर या टो ट्रकों को कवर करता है जब वे आगे और पीछे 500 feet दिखाई देने वाली कम से कम एक चमकती लाल या लाल-और-नीली लैंप से सुसज्जित हों। स्रोत: Wyoming Statute 31-5-224।"},"60":{"q":"एक दो-लेन, दो-तरफा व्योमिंग राजमार्ग पर, एक स्कूल बस अपनी लाल बत्तियां चमकाते और स्टॉप आर्म बढ़ाए हुए रुकती है। विपरीत दिशा से आ रहे एक पास आ रहे CDL चालक को क्या करना चाहिए?","options":["15 mph तक धीमा करें और सावधानी से पार करें","बस तक पहुंचने से पहले रुकें और तब तक रुके रहें जब तक बत्तियां चमकना बंद न कर दें या बस आगे न बढ़ जाए","निर्धारित गति पर जारी रखें क्योंकि आने वाला यातायात छूट प्राप्त है","केवल तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पार कर रहे हों"],"explanation":"व्योमिंग नियम: किसी भी दिशा से चमकती लाल बत्तियां दिखा रही एक रुकी हुई स्कूल बस से मिलने या आगे निकलने पर, एक चालक को बस तक पहुंचने से पहले रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक बस आगे न बढ़ जाए या लाल बत्तियां चमकना बंद न कर दें। स्रोत: Wyoming Statute 31-5-507।"},"61":{"q":"व्योमिंग के स्कूल-बस रुकने के कानून में एक विभाजित-राजमार्ग अपवाद है। चमकती लाल बत्तियां दिखा रही एक स्कूल बस के लिए एक चालक को कब रुकना आवश्यक नहीं है?","options":["केवल तब जब यात्रा की दिशाओं के बीच एक रंगी हुई केंद्र रेखा हो","जब भी चालक बस से दो लेन से अधिक दूर हो","जब भी सड़क की निर्धारित गति सीमा 55 mph से ऊपर हो","जब बस अलग-अलग सड़कों वाले एक राजमार्ग की एक अलग सड़क पर हो"],"explanation":"व्योमिंग नियम: अलग-अलग सड़कों वाले एक राजमार्ग पर एक चालक को एक स्कूल बस से मिलने या उसे पार करते समय रुकने की आवश्यकता नहीं है जो एक अलग सड़क पर है, या जब एक नियंत्रित-पहुंच राजमार्ग पर हो और बस एक लोडिंग ज़ोन में रुकी हो जहां पैदल चलने वालों को पार करने की अनुमति नहीं है। अकेले एक रंगी हुई रेखा योग्य नहीं है। स्रोत: Wyoming Statute 31-5-507।"},"62":{"q":"एक व्योमिंग CDL चालक को एक तरफा या विभाजित राजमार्ग के कंधे पर वाहन रोकना चाहिए। आपातकालीन चेतावनी उपकरणों को कितने समय के भीतर और कहां रखा जाना चाहिए?","options":["30 मिनट के भीतर, आ रहे यातायात की ओर 25 feet, 100 feet, और 250 feet पर","10 मिनट के भीतर, आ रहे यातायात की ओर 50 feet, 150 feet, और 300 feet पर","10 मिनट के भीतर, आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर","5 मिनट के भीतर, आ रहे यातायात की ओर 10 feet, 50 feet, और 100 feet पर"],"explanation":"व्योमिंग नियम: यदि आप एक तरफा या विभाजित राजमार्ग पर या उसके पास रुकते हैं, तो 10 मिनट के भीतर चेतावनी उपकरणों को वाहन से आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखें। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely (रुके हुए वाहनों के लिए चेतावनी उपकरण)।"},"63":{"q":"एक व्योमिंग CDL चालक दोनों दिशाओं में यातायात ले जा रही एक दो-लेन सड़क पर रुकता है। तीन परावर्तक त्रिकोणों को कैसे रखा जाना चाहिए?","options":["10 feet, 100 feet, और 200 feet के भीतर, सभी केवल वाहन के पीछे","केवल वाहन के आगे 25 feet, 100 feet, और 200 feet पर","वाहन के 10 feet के भीतर, साथ ही वाहन के 100 feet पीछे और 100 feet आगे","वाहन के पीछे 10 feet, 50 feet, और 150 feet के भीतर"],"explanation":"व्योमिंग नियम: दोनों दिशाओं में यातायात ले जा रही एक दो-लेन सड़क पर (या एक अविभाजित राजमार्ग पर), वाहन को चिह्नित करने के लिए आगे या पीछे के कोनों के 10 feet के भीतर, और वाहन के 100 feet पीछे और 100 feet आगे चेतावनी उपकरण रखें। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely।"},"64":{"q":"यदि एक पहाड़ी या मोड़ एक व्योमिंग सड़क पर रुके हुए एक CDL वाहन का दृश्य अवरुद्ध करता है, तो मैनुअल सबसे पीछे वाले चेतावनी त्रिकोण के साथ क्या करने को कहता है?","options":["इसे सड़क पर और पीछे ले जाएं ताकि अवरोध से परे चेतावनी प्रदान की जा सके, 500 feet तक","सभी त्रिकोणों को मानक 10/100/200-foot अंतराल पर छोड़ दें","अधिकतम दृश्यता के लिए इसे सीधे अवरोध पर ही रखें","इसे पूरी तरह हटा दें और केवल फोर-वे फ्लैशर पर निर्भर रहें"],"explanation":"व्योमिंग नियम: यदि दृष्टि-रेखा का दृश्य एक पहाड़ी, मोड़, या अन्य अवरोध से बाधित है, तो सबसे पीछे वाले त्रिकोण को सड़क पर और पीछे ले जाएं (अवरोध से परे पीछे ताकि वाहन को 500 feet के भीतर देखा जा सके) ताकि उचित चेतावनी दी जा सके। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2 - Driving Safely।"},"65":{"q":"80 mph पर निर्धारित व्योमिंग के ग्रामीण इंटरस्टेट राजमार्गों पर, एक यात्री कार की तुलना में एक ट्रैक्टर-ट्रेलर पर गति सीमा कैसे लागू होती है?","options":["ट्रकों की सीमा 70 mph है जबकि कारें 80 mph तक जा सकती हैं","ट्रक और कारें समान 80 mph अधिकतम साझा करती हैं; व्योमिंग कोई अलग कम ट्रक सीमा निर्धारित नहीं करता","ट्रकों की सीमा 65 mph है जबकि कारें 80 mph तक जा सकती हैं","ट्रकों की सीमा 75 mph है जबकि कारें 80 mph तक जा सकती हैं"],"explanation":"व्योमिंग नियम: व्योमिंग की अधिकतम इंटरस्टेट गति सीमा (निर्दिष्ट ग्रामीण खंडों पर 80 mph तक) वाणिज्यिक ट्रकों और यात्री कारों पर समान रूप से लागू होती है। कुछ राज्यों के विपरीत, व्योमिंग एक अलग, कम वैधानिक ट्रक गति सीमा निर्धारित नहीं करता। स्रोत: Wyoming Statute 31-5-301; WYDOT 80 mph कॉरिडोर पदनाम।"},"66":{"q":"व्योमिंग I-80 के पर्वतीय खंडों पर एक स्तरीय चेन कानून सक्रिय करता है। अधिक गंभीर LEVEL 2 (अत्यंत खतरनाक) के तहत, एक वाणिज्यिक वाहन किस पर निर्भर हो सकता है?","options":["ड्राइव एक्सल पर केवल स्नो टायर","मानक राजमार्ग टायरों के साथ फ्रंट-व्हील ड्राइव","टायर चेन, या M+S या ऑल-वेदर रेटेड टायरों से सुसज्जित AWD (अकेले स्नो टायर पर्याप्त नहीं हैं)","केवल कम गति, बिना किसी उपकरण आवश्यकता के"],"explanation":"व्योमिंग नियम: Level 1 के तहत, एक CMV चेन, पर्याप्त स्नो टायर, या AWD का उपयोग कर सकता है; Level 2 (अत्यंत खतरनाक) के तहत, अकेले स्नो टायर अपर्याप्त हैं और वाहन को टायर चेन, या M+S या ऑल-वेदर-रेटेड टायरों से सुसज्जित AWD का उपयोग करना चाहिए। स्रोत: WYDOT Wyoming चेन-कानून स्तर (आमतौर पर I-80 'Three Sisters' खंड पर लागू)।"},"67":{"q":"एक अत्यधिक तेज़-हवा की घटना के दौरान, व्योमिंग I-80 और I-25 के हिस्सों को सबसे पहले किन वाहनों के लिए बंद करता है?","options":["केवल यात्री कारें और मोटरसाइकिलें","हल्के, ऊंचे-प्रोफ़ाइल वाले वाणिज्यिक वाहन (जैसे खाली या हल्के लदे वैन)","केवल तरल पदार्थ ढो रहे पूरी तरह लदे टैंकर","केवल यात्रियों को ढो रही बसें"],"explanation":"व्योमिंग नियम: बार-बार होने वाली ब्लो-ओवर दुर्घटनाओं के कारण, WYDOT I-80 और I-25 के खंडों को हल्के, ऊंचे-प्रोफ़ाइल वाहनों के लिए (और, सबसे खराब स्थितियों में, सभी वाणिज्यिक वाहनों के लिए) प्रतिबंधित और बंद करता है। बंदी wyoroad.info / Wyoming 511 पर पोस्ट की जाती हैं। स्रोत: WYDOT तेज़-हवा / ब्लो-ओवर प्रतिबंध।"},"68":{"q":"एक वाणिज्यिक वाहन की अधिकतम चौड़ाई क्या है जो एक ओवरसाइज़ परमिट के बिना व्योमिंग राजमार्गों पर चल सकता है?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"व्योमिंग नियम: परमिट के बिना वैध अधिकतम वाहन चौड़ाई 8 feet 6 inches (102 inches) है; इससे चौड़ी किसी भी चीज़ के लिए WYDOT से एक ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Wyoming Statute 31-18-802 / WYDOT ओवरसाइज़-परमिट विनियम।"},"69":{"q":"परमिट के बिना, व्योमिंग राजमार्गों पर अधिकतम वैध वाहन ऊंचाई क्या है?","options":["14 feet","13 feet 6 inches","13 feet","15 feet"],"explanation":"व्योमिंग नियम: परमिट के बिना वैध अधिकतम वाहन ऊंचाई 14 feet है; इससे अधिक भार के लिए एक ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Wyoming Statute 31-18-802 / WYDOT ओवरसाइज़ विनियम।"},"70":{"q":"एक व्योमिंग वाहक को एक अति-चौड़े मूव के लिए WYDOT से एक सिंगल-ट्रिप ओवरसाइज़ परमिट की आवश्यकता है। बेस सिंगल-ट्रिप ओवरसाइज़ परमिट शुल्क क्या है?","options":["$10.00","$50.00","$100.00","$25.00"],"explanation":"व्योमिंग नियम: एक सिंगल-ट्रिप ओवरसाइज़ परमिट का शुल्क $25.00 है, जिसमें 15 feet चौड़े, 15 feet ऊंचे, या 75 feet लंबे से अधिक भार के लिए अतिरिक्त मीलेज-आधारित शुल्क हैं। स्रोत: Wyoming Statute 31-18-804 / WYDOT ओवरसाइज़-परमिट शुल्क अनुसूची।"},"71":{"q":"एक व्योमिंग ट्रैक्टर-सेमीट्रेलर संयोजन में, परमिट के बिना सेमीट्रेलर के लिए स्वयं की अनुमत अधिकतम लंबाई क्या है?","options":["60 feet","48 feet","53 feet","57 feet"],"explanation":"व्योमिंग नियम: एक ट्रक-ट्रैक्टर सेमीट्रेलर संयोजन में, सेमीट्रेलर की लंबाई 60 feet से अधिक नहीं हो सकती (व्योमिंग उल्लेखनीय रूप से सामान्य 53-foot ट्रेलर से लंबे एकल सेमीट्रेलर की अनुमति देता है)। स्रोत: Wyoming Statute 31-18-802 (आकार और वजन सीमाएं)।"},"72":{"q":"व्योमिंग में रेलमार्ग पटरियों के एक सेट को पार करते समय, CDL मैनुअल एक मैनुअल-ट्रांसमिशन CMV के चालक को क्या करने का निर्देश देता है?","options":["जब वाहन का कोई भी हिस्सा पटरियों पर हो तो गियर न बदलें","अधिकतम कर्षण के लिए बीच में सबसे नीचे गियर में डाउनशिफ्ट करें","न्यूट्रल में शिफ्ट करें और पटरियों के पार कोस्ट करें","पटरियों को जितनी जल्दी हो सके पार करने के लिए एक गियर ऊपर शिफ्ट करें"],"explanation":"व्योमिंग नियम: मैनुअल निर्देश देता है कि रेलमार्ग पटरियों को पार करते समय आप गियर न बदलें, क्योंकि गियर बदलने से पटरियों पर रुक जाने का जोखिम होता है; शुरू करने से पहले एक ऐसा गियर चुनें जो आपको पूरी तरह पार ले जाएगा। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), Section 2.15 - Railroad/Highway Crossings।"},"73":{"q":"व्योमिंग में एक रेलमार्ग क्रॉसिंग के पास पहुंचते समय, एक स्कूल बस, यात्री बस, या प्लेकार्ड वाले वाहन को पटरियों के पास पहुंचते समय अपनी बत्तियों के साथ कौन सी कार्रवाई करनी चाहिए?","options":["ट्रेन क्रू को भ्रमित करने से बचने के लिए सभी बाहरी बत्तियां बंद कर दें","पटरियों के पार होने तक लगातार हाई बीम चमकाएं","निकटतम रेल की दिशा में टर्न सिग्नल सक्रिय करें","पास आते समय फोर-वे (हैज़र्ड) फ्लैशर सक्रिय करें, और पटरियों को पार करने के बाद उन्हें निष्क्रिय कर दें"],"explanation":"व्योमिंग नियम: एक बस, स्कूल बस, या प्लेकार्ड वाले वाहन को क्रॉसिंग के पास पहुंचते समय फोर-वे फ्लैशर सक्रिय करने चाहिए, निकटतम रेल से 50 feet के भीतर लेकिन 15 feet से कम नहीं रुकना चाहिए, देखना और सुनना चाहिए, फिर पार करने के बाद फ्लैशर निष्क्रिय कर देने चाहिए। स्रोत: 2024 Wyoming Commercial Driver License Manual (WYDOT), रेलमार्ग-क्रॉसिंग रोड-टेस्ट प्रक्रियाएं।"},"74":{"q":"कौन सी व्योमिंग एजेंसी राज्य में ड्राइविंग रिकॉर्ड का प्रशासन करती है और सभी वर्गों के कमर्शियल ड्राइवर लाइसेंस (CDLs) जारी करती है?","options":["The Wyoming Department of Transportation (WYDOT), Driver Services Program","The Wyoming Department of Motor Vehicles, एक स्वतंत्र एजेंसी","The Wyoming Highway Patrol, Licensing Division","आवेदक के निवास काउंटी में काउंटी क्लर्क का कार्यालय"],"explanation":"व्योमिंग में, WYDOT का Driver Services Program ड्राइविंग रिकॉर्ड प्रणाली का प्रशासन करता है और सभी वर्गों के ड्राइवर और कमर्शियल ड्राइवर लाइसेंस का परीक्षण, जारीकरण, और प्रसंस्करण करता है। व्योमिंग में कोई अलग 'DMV' एजेंसी नहीं है। स्रोत: WYDOT Driver Services / Commercial License पेज।"},"75":{"q":"इससे पहले कि WYDOT एक CDL कौशल परीक्षण का प्रशासन कर सके, एक पहली Class A या Class B CDL के लिए एक प्रवेश-स्तर के आवेदक को कौन सी आवश्यकता पूरी करनी चाहिए?","options":["FMCSA Training Provider Registry पर एक प्रदाता से Entry-Level Driver Training (ELDT)","Wyoming Highway Patrol द्वारा अनुमोदित एक 40-घंटे का रक्षात्मक-ड्राइविंग पाठ्यक्रम","दो वर्ष का प्रलेखित इंट्रास्टेट ड्राइविंग अनुभव","एक WYDOT-प्रशासित चिकित्सा योग्यता मूल्यांकन"],"explanation":"व्योमिंग में लागू संघीय ELDT नियमों के अनुसार, प्रवेश-स्तर के चालकों को कौशल परीक्षण लेने से पहले FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता से सिद्धांत और व्हील-के-पीछे प्रशिक्षण पूरा करना आवश्यक है। WYDOT कहता है कि CDL कौशल परीक्षण केवल उन्हीं को दिए जा सकते हैं जिन्होंने ELDT पूरा किया है या एक ग्रैंडफादर छूट रखते हैं। स्रोत: WYDOT CDL Testing पेज; 49 CFR Part 380 Subpart F।"},"76":{"q":"व्योमिंग CDL कौशल परीक्षण किन तीन भागों से बना है, जो क्रम में प्रशासित किए जाते हैं?","options":["प्री-ट्रिप (वाहन) निरीक्षण, बुनियादी नियंत्रण कौशल, और ऑन-रोड ड्राइविंग","लिखित ज्ञान परीक्षण, दृष्टि स्क्रीनिंग, और ऑन-रोड ड्राइविंग","एयर-ब्रेक परीक्षण, कपलिंग परीक्षण, और रात्रि ड्राइविंग","रक्षात्मक ड्राइविंग, बुनियादी नियंत्रण कौशल, और एक हैज़मैट हैंडलिंग प्रदर्शन"],"explanation":"व्योमिंग की CDL कौशल परीक्षा में एक वाहन प्री-ट्रिप निरीक्षण, एक बुनियादी नियंत्रण कौशल परीक्षण, और एक ओवर-द-रोड (ऑन-रोड) ड्राइविंग परीक्षण शामिल है। स्रोत: WYDOT CDL Testing पेज; व्योमिंग द्वारा अपनाए गए AAMVA CDL कौशल मानक।"},"77":{"q":"एक व्योमिंग CDL आवेदक को अपने द्वारा किए जाने वाले वाणिज्यिक ड्राइविंग के प्रकार की घोषणा करते समय किन चार स्व-प्रमाणन श्रेणियों में से चुनना चाहिए?","options":["Non-excepted interstate, excepted interstate, non-excepted intrastate, excepted intrastate","Local, regional, over-the-road, और seasonal","Class A, Class B, Class C, और endorsement-only","For-hire, private, agricultural, और emergency"],"explanation":"व्योमिंग को प्रत्येक CDL धारक को चार श्रेणियों में से एक के लिए स्व-प्रमाणित करने की आवश्यकता है: non-excepted interstate (NI), excepted interstate (EI), non-excepted intrastate (NA), और excepted intrastate (EA)। स्रोत: WYDOT Driver Certification पेज; 49 CFR 383.71(b)।"},"78":{"q":"व्योमिंग में लागू संघीय commercial learner's permit (CLP) नियम के तहत, CDL कौशल परीक्षण लेने की अनुमति मिलने से पहले एक आवेदक को कितने समय तक एक CLP रखना चाहिए?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 7 days","कम से कम 60 days"],"explanation":"एक व्योमिंग CLP धारक को CDL कौशल परीक्षण लेने से पहले CLP जारी होने के बाद कम से कम 14 days इंतजार करना चाहिए। स्रोत: 49 CFR 383.25(a)(3), WYDOT Driver Services द्वारा लागू।"},"79":{"q":"एक व्योमिंग CDL धारक 'non-excepted interstate' (NI) के रूप में स्व-प्रमाणित करता है। उन्हें WYDOT के साथ कौन सा अतिरिक्त दस्तावेज़ चालू रखना चाहिए?","options":["एक National Registry परीक्षक से एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र","FMCSA से एक वार्षिक इंटरस्टेट परिचालन प्राधिकरण पत्र","इंट्रास्टेट-केवल संचालन का एक नोटरीकृत शपथपत्र","एक व्योमिंग-जारी खतरनाक सामग्री पृष्ठभूमि मंजूरी"],"explanation":"जो चालक non-excepted interstate (NI) या non-excepted intrastate (NA) के रूप में स्व-प्रमाणित करते हैं, उन्हें चिकित्सकीय रूप से योग्य होना चाहिए और फ़ाइल पर एक चालू DOT चिकित्सा प्रमाणपत्र रखना चाहिए। Excepted (EI/EA) चालक नहीं रखते। परीक्षक को FMCSA National Registry पर होना चाहिए। स्रोत: WYDOT Driver Certification / DOT Medical Certificate पेज; 49 CFR 383.71(h)।"},"80":{"q":"यदि धारक अपने आवश्यक DOT चिकित्सा प्रमाणपत्र को समाप्त होने देता है और 'not-certified' हो जाता है तो एक व्योमिंग CDL का क्या होता है?","options":["CDL को एक गैर-वाणिज्यिक ड्राइवर लाइसेंस में डाउनग्रेड किए जाने के अधीन है","CDL तुरंत और स्थायी रूप से निरस्त कर दिया जाता है जिसमें बहाली का कोई रास्ता नहीं","CDL बिना किसी कार्रवाई की आवश्यकता के स्वचालित रूप से एक excepted-intrastate स्थिति में परिवर्तित हो जाता है","CDL को ठीक 90 दिनों के लिए निलंबित कर दिया जाता है, फिर स्वतः बहाल कर दिया जाता है"],"explanation":"यदि एक व्योमिंग CDL धारक फ़ाइल पर एक चालू चिकित्सा प्रमाणपत्र नहीं रखता, तो वे 'not-certified' हो जाते हैं और CDL को एक गैर-वाणिज्यिक लाइसेंस में डाउनग्रेड किए जाने के अधीन है। स्रोत: WYDOT Driver Certification / DOT Medical Certificate पेज; 49 CFR 383.73(o)।"},"81":{"q":"व्योमिंग प्रत्येक CDL ज्ञान (लिखित) परीक्षण पर किस न्यूनतम उत्तीर्ण अंक की आवश्यकता रखता है?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"व्योमिंग CDL ज्ञान परीक्षण बहुविकल्पीय हैं और उत्तीर्ण होने के लिए कम से कम 80% सही की आवश्यकता है; आवेदक केवल उन्हीं परीक्षणों को फिर से देते हैं जिनमें वे असफल होते हैं। स्रोत: WYDOT CDL Testing पेज।"},"82":{"q":"वाणिज्यिक ड्राइविंग विशेषाधिकार बनाए रखने के लिए एक व्योमिंग CDL को कितनी बार नवीनीकृत किया जाना चाहिए?","options":["हर 4 years","हर 5 years","हर 8 years","हर 2 years"],"explanation":"व्योमिंग CDLs एक 4-year नवीनीकरण चक्र पर जारी किए जाते हैं। स्रोत: WYDOT Driver License नवीनीकरण जानकारी।"},"83":{"q":"जैसे ही व्योमिंग FMCSA National Registry II (NRII) प्रक्रिया लागू करता है, एक चालक का DOT चिकित्सा प्रमाणन सामान्य रूप से WYDOT को कैसे प्रदान किया जाता है?","options":["प्रमाणित चिकित्सा परीक्षक FMCSA National Registry के माध्यम से राज्य ड्राइविंग रिकॉर्ड को परिणामों को इलेक्ट्रॉनिक रूप से प्रसारित करता है","चालक काउंटी क्लर्क को कागज़ी प्रमाणपत्र की एक फोटोकॉपी मेल करता है","नियोक्ता प्रमाणपत्र को Wyoming Highway Patrol को फैक्स करता है","चालक एक स्कैन की गई छवि को एक व्यक्तिगत FMCSA चालक खाते में अपलोड करता है"],"explanation":"FMCSA के National Registry II नियम (23 जून 2025 से प्रभावी) के तहत, प्रमाणित चिकित्सा परीक्षक चिकित्सा प्रमाणन परिणामों को National Registry के माध्यम से सीधे State Driver Licensing Agency रिकॉर्ड को इलेक्ट्रॉनिक रूप से प्रसारित करता है; परीक्षक के पास परिणाम दर्ज करने के लिए अगले कैलेंडर दिन की मध्यरात्रि तक का समय होता है। स्रोत: WYDOT DOT Medical Certificate पेज; FMCSA NRII नियम।"},"84":{"q":"एक व्योमिंग CDL के लिए DOT चिकित्सा योग्यता को प्रलेखित करने के लिए उपयोग किए जाने वाले संघीय Medical Examiner's Certificate का फॉर्म नंबर क्या है?","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"explanation":"Medical Examiner's Certificate FMCSA Form MCSA-5876 है (लंबी Medical Examination Report MCSA-5875 है)। स्रोत: FMCSA चिकित्सा फॉर्म; WYDOT DOT Medical Certificate पेज।"},"85":{"q":"एक चालक जो व्योमिंग में 'excepted intrastate' (EA) के रूप में स्व-प्रमाणित करता है, वह अपने संचालन के बारे में कौन सा कथन दे रहा है?","options":["वे केवल व्योमिंग के भीतर संचालन करते हैं और उन्हें संघीय DOT चिकित्सा-कार्ड आवश्यकताओं को पूरा करने की आवश्यकता नहीं है","वे राज्य की सीमाओं के पार संचालन करते हैं और उन्हें एक संघीय DOT चिकित्सा कार्ड रखना चाहिए","वे केवल खतरनाक सामग्री ढोते हैं और उन्हें एक अलग चिकित्सा छूट की आवश्यकता है","वे केवल लाइसेंसिंग से छूट प्राप्त सरकारी-स्वामित्व वाले वाहन चलाते हैं"],"explanation":"Excepted intrastate (EA) का अर्थ है कि चालक केवल इंट्रास्टेट वाणिज्य में संचालन करता है और संघीय DOT चिकित्सा प्रमाणपत्र आवश्यकता से छूट प्राप्त है। स्रोत: WYDOT Driver Certification पेज; 49 CFR 383.71(b)।"},"86":{"q":"पहली बार एक व्योमिंग CDL या CLP के लिए आवेदन करते समय, पहचान साबित करने के लिए आमतौर पर कौन सा दस्तावेज़ आवश्यक होता है?","options":["एक प्रमाणित जन्म प्रमाणपत्र या एक वैध U.S. पासपोर्ट","एक वर्तमान नियोक्ता ID बैज","एक हस्ताक्षरित CDL endorsement छूट फॉर्म","आवेदक के नाम पर एक वाहन पंजीकरण कार्ड"],"explanation":"व्योमिंग को आवेदन करने के लिए पहचान के प्रमाण जैसे एक प्रमाणित जन्म प्रमाणपत्र (या उसके बदले U.S. पासपोर्ट), साथ ही Social Security नंबर और व्योमिंग निवास के प्रमाण की आवश्यकता है। स्रोत: WYDOT Driver Services; Wyoming CDL आवेदन आवश्यकताएं।"},"87":{"q":"व्योमिंग किस शेड्यूलिंग व्यवस्था के तहत CDL कौशल परीक्षण का प्रशासन करता है?","options":["केवल अपॉइंटमेंट द्वारा, सभी आवश्यक लिखित परीक्षण उत्तीर्ण करने के बाद","राज्य भर में किसी भी DMV कियोस्क पर वॉक-इन आधार पर","केवल हर वसंत में एक एकल वार्षिक परीक्षण सप्ताह के दौरान","एक रिमोट प्रॉक्टर्ड वीडियो सत्र के माध्यम से ऑनलाइन"],"explanation":"व्योमिंग कौशल परीक्षण केवल अपॉइंटमेंट द्वारा और केवल आवेदक द्वारा सभी आवश्यक लिखित (ज्ञान) परीक्षण उत्तीर्ण करने के बाद दिए जाते हैं। WYDOT राज्य भर में सीमित संख्या में स्थानों पर कौशल परीक्षण प्रदान करता है। स्रोत: WYDOT CDL Testing पेज।"},"88":{"q":"व्योमिंग CDL कौशल परीक्षण के लिए, उचित वर्ग का एक प्रतिनिधि वाहन प्रदान करने के लिए कौन ज़िम्मेदार है?","options":["आवेदक को परीक्षण किए जा रहे वर्ग/प्रकार का एक प्रतिनिधि वाहन प्रदान करना चाहिए","WYDOT हर आवेदक के लिए एक राज्य-स्वामित्व वाला परीक्षण वाहन प्रदान करता है","प्रमाणित चिकित्सा परीक्षक परीक्षण वाहन प्रदान करता है","Wyoming Highway Patrol नि:शुल्क एक वाहन उधार देता है"],"explanation":"आवेदकों को मांगे गए CDL के वर्ग और प्रकार का प्रतिनिधि अपना स्वयं का वाहन प्रस्तुत करना चाहिए; उदाहरण के लिए, एक टैंक वाहन में एक N endorsement और पर्ज दस्तावेज़ीकरण होना चाहिए, और परीक्षण के दौरान प्लेकार्ड वाले हैज़मैट भार का उपयोग नहीं किया जा सकता। स्रोत: WYDOT CDL Testing पेज।"},"89":{"q":"व्योमिंग में, एक खतरनाक सामग्री (H) endorsement प्राप्त करने के लिए किस प्रशिक्षण/परीक्षण अनुक्रम की आवश्यकता होती है?","options":["हैज़मैट ELDT सिद्धांत प्रशिक्षण पूरा करें, फिर हैज़मैट ज्ञान परीक्षण उत्तीर्ण करें (साथ ही एक TSA पृष्ठभूमि जांच)","टैंकरों के लिए विशिष्ट एक अतिरिक्त ऑन-रोड कौशल परीक्षण उत्तीर्ण करें","200 घंटे की व्हील-के-पीछे हैज़मैट ड्राइविंग पूरी करें","किसी भी परीक्षण से पहले एक काउंटी-जारी खतरनाक कार्गो परमिट प्राप्त करें"],"explanation":"पहली बार के एक हैज़मैट (H) endorsement के लिए, हैज़मैट ज्ञान परीक्षण लेने से पहले ELDT हैज़मैट सिद्धांत प्रशिक्षण पूरा किया जाना चाहिए; एक TSA सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जांच) भी आवश्यक है। कोई अलग हैज़मैट कौशल परीक्षण नहीं है। स्रोत: WYDOT CDL Testing/Commercial License पेज; 49 CFR Part 380 Subpart B।"},"90":{"q":"इंट्रास्टेट (व्योमिंग के भीतर) वाणिज्यिक ड्राइविंग के लिए एक व्योमिंग CDL जारी किए जाने की न्यूनतम आयु क्या है?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"एक व्योमिंग CDL इंट्रास्टेट संचालन के लिए 18 वर्ष की आयु में जारी किया जा सकता है; एक चालक को इंटरस्टेट वाणिज्य में संचालन करने, प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ढोने, या राज्य की सीमाओं के पार यात्रियों को परिवहन करने के लिए 21 वर्ष का होना चाहिए। स्रोत: WYDOT Commercial Learner's Permit / Commercial License पेज।"},"91":{"q":"WYDOT के अनुसार एक व्योमिंग commercial learner's permit (CLP) कितने समय तक वैध रहता है?","options":["365 days","30 days","60 days","10 years"],"explanation":"WYDOT के अनुसार, एक व्योमिंग CLP 365 days के लिए वैध है। (संघीय नियमों के अनुसार धारक को कौशल परीक्षण लेने से पहले जारी होने के बाद कम से कम 14 days इंतजार करना आवश्यक है।) स्रोत: WYDOT Commercial Learner's Permit पेज।"},"92":{"q":"यदि एक व्योमिंग चालक एक CDL को समाप्त होने देता है और राज्य की रियायती अवधि (लगभग दो वर्ष) के भीतर इसे नवीनीकृत नहीं करता, तो फिर से एक CDL प्राप्त करने के लिए आमतौर पर क्या आवश्यक होता है?","options":["एक नया CLP प्राप्त करके और आवश्यक ज्ञान और कौशल परीक्षण फिर से लेकर शुरुआत से शुरू करें","एक निश्चित विलंब शुल्क का भुगतान करें और CDL बिना परीक्षण के बहाल हो जाता है","CDL को बहाल करने के लिए केवल एक नया DOT चिकित्सा प्रमाणपत्र जमा करें","किसी भी पुनः आवेदन की अनुमति से पहले पांच अतिरिक्त वर्ष इंतजार करें"],"explanation":"व्योमिंग एक समाप्त CDL के नवीनीकरण की अनुमति लगभग दो वर्ष की रियायती अवधि के भीतर बिना पुनः परीक्षण के देता है; उसके बाद, चालक को एक नए CLP के साथ शुरुआत से शुरू करना चाहिए और आवश्यक ज्ञान और कौशल परीक्षण फिर से लेने चाहिए। स्रोत: WYDOT Driver License नवीनीकरण जानकारी।"},"93":{"q":"कौन सा कथन सबसे अच्छी तरह बताता है कि एक व्योमिंग CLP के जीवनकाल के दौरान CDL ज्ञान (लिखित) परीक्षण परिणामों के साथ कैसा व्यवहार किया जाता है?","options":["उत्तीर्ण ज्ञान परीक्षण CLP की अवधि के लिए वैध रहते हैं, इसलिए केवल असफल परीक्षण ही फिर से लेने होते हैं","सभी ज्ञान परीक्षण कौशल परीक्षण के उसी दिन फिर से उत्तीर्ण किए जाने चाहिए","ज्ञान परीक्षण परिणाम परीक्षण तिथि के 7 days बाद समाप्त हो जाते हैं","ज्ञान परीक्षण केवल एक बार उत्तीर्ण करने की आवश्यकता है और कभी समाप्त नहीं होते, यहां तक कि एक CLP के बिना भी"],"explanation":"व्योमिंग में, ज्ञान परीक्षण CLP से बंधे होते हैं: उत्तीर्ण परीक्षण परमिट की अवधि के लिए वैध रहते हैं, और एक आवेदक केवल उन्हीं परीक्षणों को फिर से लेता है जिनमें वे असफल हुए। स्रोत: WYDOT CDL Testing पेज।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض معظم المركبات التجارية على الطرق السريعة في وايومنغ دون الحصول على تصريح للحمولة الزائدة الحجم؟","options":["8 أقدام (96 إنشًا)","8 أقدام و6 إنشات (102 إنش)","9 أقدام (108 إنشات)","10 أقدام (120 إنشًا)"],"explanation":"تحدّ وايومنغ عرض المركبة بـ 8 أقدام و6 إنشات (102 إنش) على طرقها السريعة، بما يتوافق مع المعيار الفيدرالي. وأي عرض يتجاوز ذلك يتطلب تصريحًا للحمولة الزائدة الحجم. المصدر: W.S. 31-18-802؛ قواعد الحجم والوزن للناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة على الطرق السريعة في وايومنغ دون تصريح؟","options":["13 قدمًا","13 قدمًا و6 إنشات","14 قدمًا","15 قدمًا"],"explanation":"تسمح وايومنغ بارتفاع أقصى للمركبة قدره 14 قدمًا على جميع الطرق السريعة قبل أن يصبح تصريح الحمولة الزائدة الحجم لازمًا. المصدر: W.S. 31-18-802؛ قواعد الناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"2":{"q":"على الطرق السريعة في وايومنغ، ما هو الحد الأقصى للحمولة التي يجوز قانونيًا أن يحملها محور واحد (single axle) دون تصريح للحمولة الزائدة الوزن؟","options":["18,000 رطل","20,000 رطل","22,000 رطل","24,000 رطل"],"explanation":"تحدّ وايومنغ المحور الواحد بـ 20,000 رطل، وهو نفس الحد الفيدرالي للمحور الواحد. المصدر: W.S. 31-18-805؛ حدود الوزن للناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"3":{"q":"ما هو الحد الأقصى القانوني لوزن المحور المزدوج (tandem axle، محوران متقاربان) على الطرق السريعة في وايومنغ دون تصريح؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تسمح وايومنغ للمحور المزدوج بحمل ما يصل إلى 36,000 رطل دون تصريح للحمولة الزائدة الوزن. المصدر: W.S. 31-18-805؛ حدود الوزن للناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"4":{"q":"ما هو الحد الأقصى الأساسي للوزن الإجمالي للمركبة المسموح به على الطرق السريعة في وايومنغ قبل أن تنطبق أحكام التصاريح الخاصة أو المعادلات؟","options":["73,280 رطلًا","76,000 رطل","80,000 رطل","84,000 رطل"],"explanation":"الحد الأقصى الأساسي للوزن الإجمالي للمركبة في وايومنغ هو 80,000 رطل، بما يتسق مع الحد الفيدرالي. وتخضع الأوزان الأعلى لجداول الوزن وفق معادلة الجسر (bridge-formula). المصدر: W.S. 31-18-805؛ قواعد الناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"5":{"q":"قبل اشتراط أي تصريح للحمولة الزائدة الحجم، ما مقدار الوزن الذي يجوز قانونيًا أن تحمله كل عجلة في وايومنغ؟","options":["8,000 رطل","9,000 رطل","10,000 رطل","12,000 رطل"],"explanation":"تحدّ وايومنغ كل عجلة بـ 10,000 رطل. وهذا الحد لكل عجلة مكمّل لحدود المحور الواحد والمحور المزدوج. المصدر: حدود الوزن للناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)؛ W.S. 31-18-805."},"6":{"q":"ما هو الحد الأقصى للطول الإجمالي المسموح به في وايومنغ لتركيبة مركبات غير الجرّار ونصف المقطورة أو التركيبة المزدوجة المعترف بها؟","options":["75 قدمًا","81 قدمًا","85 قدمًا","97 قدمًا"],"explanation":"بالنسبة لأي تركيبة مركبات أخرى، تحدّد وايومنغ حدًا للطول الإجمالي قدره 85 قدمًا. المصدر: W.S. 31-18-802 المتطلبات العامة (General Requirements)."},"7":{"q":"في شاحنة جرّارة بمقطورتين في وايومنغ، لا يجوز أن يتجاوز الطول الإجمالي للوحدات المسحوبة (بما في ذلك آليات الوصل) ماذا؟","options":["75 قدمًا","81 قدمًا","85 قدمًا","88 قدمًا"],"explanation":"تحدّ وايومنغ الطول الإجمالي لنصف المقطورة والمقطورة (أو نصفي مقطورتين)، بما في ذلك آليات الوصل، بـ 81 قدمًا، على ألا تتجاوز المقطورة الأولى 48 قدمًا والثانية 40 قدمًا. المصدر: W.S. 31-18-802."},"8":{"q":"ما هو الحد الأقصى القانوني لوزن مجموعة المحاور الثلاثية (tridem axle group، ثلاثة محاور متتالية) على الطرق السريعة في وايومنغ دون تصريح؟","options":["38,000 رطل","40,000 رطل","42,000 رطل","48,000 رطل"],"explanation":"تسمح وايومنغ بما يصل إلى 42,000 رطل على مجموعة المحاور الثلاثية (ثلاثة محاور متتالية) قبل اشتراط تصريح للحمولة الزائدة الوزن. المصدر: W.S. 31-18-805؛ حدود الوزن للناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)."},"9":{"q":"في وايومنغ، في تركيبة المقطورة الواحدة، لا يجوز أن تتجاوز المقطورة الثانية أو نصف المقطورة الثانية أي طول؟","options":["28 قدمًا","33 قدمًا","40 قدمًا","48 قدمًا"],"explanation":"تحدّ وايومنغ المقطورة أو نصف المقطورة الثانية في تركيبة مزدوجة بـ 40 قدمًا (دون احتساب آلية الوصل). المصدر: W.S. 31-18-802 المتطلبات العامة (General Requirements)."},"10":{"q":"ما الغرض من معادلة الجسر الفيدرالية (federal bridge formula)، كما تُطبَّق في وايومنغ؟","options":["تحديد الحد الأقصى لعرض الحمولة التي يمكنها عبور الجسر","تحديد الوزن الإجمالي المسموح به على مجموعة من المحاور استنادًا إلى عدد المحاور والمسافة بينها","تحديد الرسم المفروض على الشاحنات الثقيلة عند عبور جسور الولاية","تحديد الحد الأدنى لضغط الإطارات المطلوب على جسور الطرق السريعة بين الولايات"],"explanation":"تطبّق وايومنغ معادلة الجسر الفيدرالية (W = 500[LN/(N-1) + 12N + 36]) لتحديد الوزن الإجمالي المسموح به على أي مجموعة من محورين متتاليين أو أكثر استنادًا إلى عدد المحاور (N) والمسافة (L) بين الطرفين. المصدر: جداول الوزن في وايومنغ؛ W.S. 31-18-805."},"11":{"q":"بموجب جداول الوزن وفق معادلة الجسر في وايومنغ، ما هو الحد الأقصى للوزن الإجمالي الذي يجوز الترخيص به على شبكة الطرق السريعة بين الولايات (Interstate) بحسب الجدول I (جدول معادلة الجسر الداخلية)؟","options":["80,000 رطل","105,500 رطل","117,000 رطل","129,000 رطل"],"explanation":"باستخدام الجدول I في وايومنغ (معادلة الجسر الداخلية التي تتحقق من جميع مجموعات المحاور المتتالية)، يجوز حمل أوزان إجمالية تصل إلى 117,000 رطل على الطرق السريعة بين الولايات والطرق الرئيسية والثانوية عند استيفاء حدود المحاور والجسر. المصدر: جداول وزن الناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)؛ WYDOT."},"12":{"q":"في وايومنغ، متى يجوز أن تتجاوز الحمولة القابلة للتجزئة (divisible load) وزنًا إجماليًا قدره 80,000 رطل دون تصريح للحمولة الزائدة الوزن؟","options":["فقط خلال ساعات النهار على الطرق السريعة بين الولايات","عندما تكون قانونية على جميع أوزان المحاور والجسر ومسجَّلة/مرخَّصة لهذا الوزن الإجمالي على الأقل","فقط إذا كانت الحمولة زراعية ومنقولة ضمن 50 ميلًا","أبدًا، لأن أي حمولة تتجاوز 80,000 رطل تتطلب دائمًا تصريحًا"],"explanation":"تسمح وايومنغ للحمولة القابلة للتجزئة بتجاوز 80,000 رطل على طرق الولاية والطرق بين الولايات دون تصريح، شريطة أن تكون قانونية على كل وزن محور وتحت معادلة الجسر وأن تكون المركبة مرخَّصة (مسجَّلة) لوزنها الإجمالي الفعلي على الأقل. المصدر: قواعد الناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)؛ WYDOT."},"13":{"q":"يريد ناقل نقل حمولة أعرض من 8 أقدام و6 إنشات على طريق سريع في وايومنغ. ما الذي يجب عليه فعله أولًا؟","options":["لا شيء، طالما أن عرض الحمولة أقل من 10 أقدام","الحصول على تصريح للحمولة الزائدة الحجم (أو إذن) قبل التشغيل على الطريق السريع","السفر ليلًا فقط مع أضواء التحذير","خفض ضغط الإطارات وإبلاغ الشرطة المحلية"],"explanation":"يجب على أي مركبة أو حمولة تتجاوز الحجم أو الوزن القانوني في وايومنغ الحصول على تصريح أو إذن قبل التشغيل على طريق سريع في الولاية. المصدر: قواعد الناقل التجاري الصادرة عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)؛ قسم التصاريح في WYDOT."},"14":{"q":"أي مكتب في وايومنغ يتولى تصاريح الحمولة الزائدة الوزن/الحجم التي تتجاوز الحدود التي يمكن لميناء دخول (Port of Entry) أو ورشة طرق سريعة إصدارها؟","options":["مكتب مأمور المقاطعة (sheriff) في كل مقاطعة يُسافر عبرها","مكتب الحمولات الزائدة الوزن (Overweight Loads Office) في شايان (WYDOT)","المكتب الإقليمي للإدارة الفيدرالية للطرق السريعة","إدارة الصيد والأسماك في وايومنغ"],"explanation":"تُصدَر التصاريح التي تتجاوز حدود ميناء الدخول/ورشة الطرق الروتينية من خلال مكتب الحمولات الزائدة الوزن (Overweight Loads Office) التابع لـ WYDOT في شايان (307-777-4376). ويمكن لموانئ الدخول وورش الطرق السريعة إصدار تصاريح حتى حدود محددة دون ذلك. المصدر: الناقل التجاري الصادر عن شرطة الطرق السريعة في وايومنغ (Wyoming Highway Patrol Commercial Carrier)؛ WYDOT."},"15":{"q":"ما هي نافذة السفر المسموح بها عمومًا في وايومنغ للحمولة الزائدة الحجم التي تتطلب مركبات مرافقة؟","options":["من منتصف الليل حتى الساعة 6:00 صباحًا فقط","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها","فقط من الإثنين إلى الجمعة، من الساعة 9:00 صباحًا حتى 5:00 مساءً","24 ساعة في اليوم دون أي قيد"],"explanation":"تقتصر تحركات الحمولة الزائدة الحجم في وايومنغ عمومًا على ضوء النهار، من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك عطلات نهاية الأسبوع؛ ويُسمح بالسفر الليلي المحدود فقط للحمولات الأضيق على الطرق بين الولايات مع إضاءة مناسبة. المصدر: شروط تصريح الحمولة الزائدة الحجم في WYDOT."},"16":{"q":"ما هو الحد الأقصى لعدد المركبات الفردية المسموح به في أي تركيبة واحدة من المركبات على الطرق السريعة في وايومنغ؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"ينص قانون وايومنغ على أنه لا يجوز أن تتكون أي تركيبة مركبات من أكثر من ثلاث مركبات فردية. المصدر: W.S. 31-18-802 المتطلبات العامة (General Requirements)."},"17":{"q":"في وايومنغ، أي فئة من رخصة CDL مطلوبة لتشغيل مركبة مركّبة بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 رطل أو أكثر، حيث يكون للوحدة المسحوبة تصنيف وزن إجمالي (GVWR) يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تتبع وايومنغ التصنيف الفيدرالي لرخصة CDL (49 CFR 383.91): تغطي رخصة CDL من الفئة A أي تركيبة مركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر، شريطة أن يكون للوحدة (الوحدات) المسحوبة تصنيف GVWR يتجاوز 10,000 رطل. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.91."},"18":{"q":"بموجب قواعد وايومنغ، أي فئة من رخصة CDL تتطلبها مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر (أو مركبة كهذه تسحب وحدة لا تتجاوز 10,000 رطل)؟","options":["الفئة C","الفئة B","الفئة A","الفئة M"],"explanation":"تستخدم وايومنغ التعريفات الفيدرالية: تغطي رخصة CDL من الفئة B مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر، أو أي مركبة كهذه تسحب وحدة بتصنيف GVWR لا يتجاوز 10,000 رطل. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.91."},"19":{"q":"أي فئة من رخصة CDL تتطلبها مركبة في وايومنغ لا تستوفي حدود وزن الفئة A أو B لكنها مصمَّمة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق) أو تنقل مواد خطرة تستلزم لوحات تحذيرية (placarded)؟","options":["الفئة A","الفئة B","الفئة C","لا تُطلب رخصة CDL"],"explanation":"تتبع وايومنغ التعريف الفيدرالي: تغطي رخصة CDL من الفئة C مركبة لا تستوفي معايير الفئة A أو B لكنها إما مصمَّمة لنقل 16 شخصًا أو أكثر (بمن فيهم السائق) أو تُستخدم لنقل مواد خطرة تستلزم لوحات تحذيرية. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.91."},"20":{"q":"أي رمز تظهير (endorsement) تضعه وايومنغ على رخصة CDL يخوّل السائق تشغيل مركبات الصهاريج (tank vehicles)؟","options":["T","N","H","X"],"explanation":"تظهير مركبة الصهريج هو الرمز N في وايومنغ، بما يتسق مع رموز التظهير الفيدرالية. (الرمز X يدل على تظهير مدمج لصهريج/مواد خطرة HazMat.) المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.153."},"21":{"q":"في وايومنغ، أي تظهير مطلوب لسحب مقطورات مزدوجة أو ثلاثية؟","options":["تظهير N","تظهير P","تظهير T","تظهير S"],"explanation":"تظهير T (المزدوجة/الثلاثية) مطلوب في وايومنغ لتشغيل تركيبة تسحب أكثر من مقطورة واحدة. ويُحصَل عليه باجتياز اختبار المعرفة الخاص بالمزدوجة/الثلاثية. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.153."},"22":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في وايومنغ مقيَّدة بالقيادة التجارية داخل الولاية (INTRASTATE) فقط؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"تسمح وايومنغ برخصة CDL في سن 18 عامًا للتشغيل داخل الولاية فقط؛ أما التشغيل بين الولايات فيتطلب سن 21 عامًا. المصدر: دليل CDL في وايومنغ (WYDOT) / W.S. الباب 31 و49 CFR 391.11."},"23":{"q":"ما هو الحد الأدنى للسن لحمل رخصة CDL في وايومنغ تخوّل القيادة التجارية بين الولايات (INTERSTATE)؟","options":["18 عامًا","19 عامًا","21 عامًا","23 عامًا"],"explanation":"يجب أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة تجارية (CMV) في التجارة بين الولايات؛ أما السائقون الذين تتراوح أعمارهم بين 18 و20 عامًا فيقتصرون على القيادة داخل الولاية في وايومنغ. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 391.11."},"24":{"q":"قبل إجراء اختبار المهارات (الطريق) لرخصة CDL في وايومنغ، كم من الوقت يجب أن يكون مقدّم الطلب قد حمل تصريح المتعلّم التجاري (CLP)؟","options":["7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"يجب حمل تصريح CLP لمدة لا تقل عن 14 يومًا بعد إصداره قبل أن يصبح حامله مؤهلًا لإجراء اختبار مهارات CDL. وينطبق هذا الحجز الفيدرالي في وايومنغ. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.25."},"25":{"q":"أثناء تشغيل مركبة تجارية (CMV) بموجب تصريح CLP في وايومنغ، يجب أن يكون حامل التصريح مصحوبًا دائمًا بشخص يحمل رخصة CDL سارية لتلك المركبة. أين يجب أن يكون موقع حامل رخصة CDL هذا؟","options":["في المقعد خلف السائق مباشرة","في أي مكان داخل مقصورة المركبة","في مقعد الراكب الأمامي بجوار حامل CLP","يتبعه في مركبة منفصلة"],"explanation":"يجب أن يكون حامل تصريح CLP مصحوبًا في جميع الأوقات بحامل رخصة CDL مرخَّص حسب الأصول يجلس في المقعد الأمامي بجوار السائق، موفّرًا إشرافًا مباشرًا. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.25."},"26":{"q":"أي قيد ينطبق على مركبة الصهريج عند تشغيلها من قبل حامل تصريح CLP في وايومنغ الذي لديه إذن N (الصهريج) على التصريح؟","options":["يجوز تحميل الصهريج حتى 50% من السعة","يجب أن يكون الصهريج فارغًا (دون حمولة سائلة أو غازية)","لا يجوز نقل سوى الماء","لا يُسمح بأي تشغيل للصهريج على الإطلاق بموجب تصريح CLP"],"explanation":"يجوز لحامل تصريح CLP الحاصل على إذن صهريج (N) تشغيل مركبة صهريج فارغة من كل حمولة سائلة أو غازية فقط؛ وتُحظر الصهاريج المحمَّلة إلى أن تُصدَر رخصة CDL. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.25."},"27":{"q":"في وايومنغ، أي قاعدة بيانات فيدرالية يجب أن يستخدمها السائق لإكمال تدريب السائق المبتدئ المطلوب (ELDT) قبل اختبار CDL أو التظهير المشمول؟","options":["السجل الوطني للسائقين (National Driver Register)","سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","بوابة eDriver التابعة لـ WYDOT في وايومنغ","مقاصة CDLIS"],"explanation":"يجب إكمال تدريب ELDT لدى مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)، الذي يسجّل إكمال المتدرّب كي تتحقق منه الولاية. المصدر: دليل CDL في وايومنغ (WYDOT) / قاعدة ELDT الصادرة عن FMCSA، 49 CFR الجزء 380."},"28":{"q":"أي من مقدّمي الطلبات مطالَبون بإكمال تدريب ELDT قبل الاختبار في وايومنغ؟","options":["السائقون دون سن 21 عامًا فقط","مقدّمو الطلبات للفئة A أو B لأول مرة، وترقية الفئة B إلى A، ومقدّمو طلبات تظهير P أو S أو H لأول مرة","مقدّمو طلب تظهير المواد الخطرة (H) فقط","جميع مقدّمي طلبات تجديد رخصة CDL"],"explanation":"ينطبق تدريب ELDT الفيدرالي (الساري منذ 7 فبراير 2022) على مقدّمي طلبات الفئة A/B لأول مرة، والسائقين الذين يرقّون من الفئة B إلى الفئة A، ومقدّمي طلبات تظهيرات P أو S أو H لأول مرة. وهو غير رجعي الأثر. المصدر: قاعدة ELDT الصادرة عن FMCSA، 49 CFR الجزء 380 / WYDOT."},"29":{"q":"إلى جانب اجتياز اختبار المعرفة، ماذا تشترط وايومنغ لتظهير المواد الخطرة (H)؟","options":["تقييم تهديد أمني من إدارة أمن النقل (TSA) يتضمن أخذ البصمات","مقابلة منفصلة مع شرطة الطرق السريعة في وايومنغ","فحص بدني ثانٍ","خطاب رعاية من صاحب العمل موثّق لدى كاتب عدل"],"explanation":"تشترط وايومنغ على مقدّمي طلب تظهير H اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA)، يتضمن أخذ البصمات وفحص خلفية جنائية/هجرة، بالإضافة إلى اختبار معرفة المواد الخطرة وتدريب ELDT النظري. المصدر: صفحة تقييم المواد الخطرة في WYDOT / 49 CFR 1572."},"30":{"q":"كم مرة يجب على السائق في وايومنغ تجديد تقييم التهديد الأمني الصادر عن TSA للاحتفاظ بتظهير المواد الخطرة (H)؟","options":["كل سنة","كل سنتين","كل 5 سنوات","كل 8 سنوات"],"explanation":"يكون تقييم التهديد الأمني الصادر عن TSA لتظهير المواد الخطرة صالحًا لمدة خمس سنوات ويجب تجديده (مع فحص خلفية جديد واختبار معرفة) للاحتفاظ بتظهير H؛ ولا يمكن تجديده بالبريد. المصدر: صفحة تقييم المواد الخطرة في WYDOT / 49 CFR 1572."},"31":{"q":"في وايومنغ، قبل أن يجوز للسائق حمل تظهير S (الحافلة المدرسية)، أي تظهير آخر يجب الحصول عليه أيضًا؟","options":["H (المواد الخطرة)","N (الصهريج)","P (الركاب)","T (المزدوجة/الثلاثية)"],"explanation":"يتطلب تظهير S (الحافلة المدرسية) أن يكون السائق مؤهلًا أولًا لتظهير P (الركاب)، لأن الحافلة المدرسية مركبة لنقل الركاب. ويسري اختبار المعرفة والمهارات معًا. المصدر: دليل CDL في وايومنغ (WYDOT) / 49 CFR 383.123."},"32":{"q":"أي مجموعة من الوثائق يجب أن يقدّمها مقدّم طلب رخصة CDL في وايومنغ إلى الجهة المُصدِرة (خدمات السائقين في WYDOT)؟","options":["رخصة قيادة وايومنغ ذات صورة سارية فقط","إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي، والإقامة في وايومنغ","جواز سفر وخطاب من صاحب العمل فقط","شهادة ميلاد وسند ملكية مركبة"],"explanation":"تشترط وايومنغ على مقدّمي طلب CDL إثبات الهوية والوجود القانوني في الولايات المتحدة، وتقديم رقم الضمان الاجتماعي، وإظهار إثبات الإقامة في وايومنغ (عادةً وثيقتان). المصدر: متطلبات الوثائق لخدمات السائقين في WYDOT."},"33":{"q":"في الإقرار الذاتي لرخصة CDL في وايومنغ، أي فئة يجب أن يختارها السائق الذي يعمل عبر حدود الولايات وليس معفًى من التأهيل البدني الفيدرالي؟","options":["معفى بين الولايات (Excepted Interstate - EI)","غير معفى بين الولايات (Non-Excepted Interstate - NI)","معفى داخل الولاية (Excepted Intrastate - EA)","غير معفى داخل الولاية (Non-Excepted Intrastate - NA)"],"explanation":"يُقرّ السائق العامل في التجارة بين الولايات وغير المعفى من القواعد الطبية الفيدرالية ذاتيًا بصفته غير معفى بين الولايات (NI) ويجب أن يحتفظ بشهادة فاحص طبي سارية صادرة عن DOT في ملفه. المصدر: الإقرار الذاتي لرخصة CDL في WYDOT / 49 CFR 383.71."},"34":{"q":"أي فئة من الإقرار الذاتي لرخصة CDL في وايومنغ لا تتطلب من السائق الاحتفاظ بشهادة فاحص طبي فيدرالية (DOT)؟","options":["غير معفى بين الولايات (Non-Excepted Interstate - NI)","غير معفى داخل الولاية (Non-Excepted Intrastate - NA)","معفى بين الولايات (Excepted Interstate - EI)","كل من NI وNA"],"explanation":"السائقون المعفون بين الولايات (EI) والمعفون داخل الولاية (EA) معفون من الاحتفاظ ببطاقة طبية صادرة عن DOT؛ ووحدهم السائقون غير المعفين (NI وNA) يجب أن يحتفظوا بشهادة فاحص طبي سارية. المصدر: الإقرار الذاتي لرخصة CDL في WYDOT / 49 CFR 383.71 و390.3."},"35":{"q":"ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للسائق قانونيًا تشغيل مركبة تجارية (CMV) في وايومنغ؟","options":["0.04 بالمئة","0.08 بالمئة","0.02 بالمئة","0.10 بالمئة"],"explanation":"تتبع وايومنغ المعيار الفيدرالي للمركبات التجارية: من غير القانوني تشغيل مركبة تجارية بتركيز كحول في الدم قدره 0.04 بالمئة أو أكثر، أي نصف حد 0.08 المخصص للسائقين العاديين. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"36":{"q":"بموجب قانون الموافقة الضمنية في وايومنغ، يُعتبر السائق بقيادته أو سيطرته الفعلية الفعلية على مركبة في الولاية أنه قد وافق على ماذا؟","options":["فحص كيميائي للدم أو النَّفَس أو البول عند الطلب القانوني","تفتيش المركبة عند أي نقطة تفتيش","علاج إلزامي من المخدرات بعد أي إيقاف","اختبار رصانة ميداني لا يمكن رفضه"],"explanation":"ينص قانون الموافقة الضمنية في وايومنغ على أن أي شخص يقود أو يكون في سيطرة فعلية فعلية على مركبة في الولاية يوافق تلقائيًا على فحص كيميائي للدم أو النَّفَس أو البول عند طلب ضابط ذلك قانونيًا. المصدر: دليل CDL في وايومنغ؛ W.S. 31-6-102 (الموافقة الضمنية)."},"37":{"q":"بالنسبة لأول مخالفة كبرى (إلزامية) مثل قيادة مركبة تجارية بتركيز كحول في الدم قدره 0.04 أو أكثر، كم تبلغ مدة إيقاف رخصة CDL لحاملها في وايومنغ (لغير المواد الخطرة)؟","options":["سنة واحدة","6 أشهر","90 يومًا","3 سنوات"],"explanation":"تؤدي أول إدانة بمخالفة كبرى إلى إيقاف رخصة CDL لمدة سنة واحدة في وايومنغ. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"38":{"q":"إذا ارتكب السائق أول مخالفة كبرى أثناء تشغيل مركبة تجارية تحمل لوحات تحذيرية للمواد الخطرة (placarded)، إلى أي مدة تزيد فترة الإيقاف في وايومنغ؟","options":["3 سنوات","سنتان","18 شهرًا","5 سنوات"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة تحمل لوحات تحذيرية فترة الإيقاف من سنة واحدة إلى 3 سنوات. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"39":{"q":"ما هي فترة إيقاف رخصة CDL في وايومنغ لثاني مخالفة كبرى (إلزامية)؟","options":["مدى الحياة","10 سنوات","5 سنوات","3 سنوات"],"explanation":"تؤدي ثاني إدانة بأي مخالفة كبرى إلى إيقاف رخصة CDL مدى الحياة. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"40":{"q":"يرفض حامل رخصة CDL في وايومنغ فحصًا كيميائيًا مطلوبًا قانونيًا أثناء تشغيل مركبة تجارية. ما هي الحد الأدنى لفترة الإيقاف لهذا الرفض؟","options":["سنة واحدة","90 يومًا","6 أشهر","60 يومًا"],"explanation":"يُعامَل رفض الفحص الكيميائي المطلوب كمخالفة كبرى، مما يؤدي إلى إيقاف لا يقل عن سنة واحدة (3 سنوات إذا كانت تحمل لوحات تحذيرية للمواد الخطرة). المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"41":{"q":"أي مما يلي يُصنَّف بأنه \"مخالفة مرورية خطيرة\" لحامل رخصة CDL في وايومنغ؟","options":["تجاوز السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد","تجاوز السرعة بمقدار 5 أميال في الساعة فوق الحد","مخالفة وقوف","ملصق تسجيل منتهي الصلاحية"],"explanation":"تشمل المخالفات المرورية الخطيرة تجاوز السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد، والقيادة المتهورة، والاقتراب الشديد، وتغيير المسار بشكل متقطع/غير سليم، والمراسلة النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"42":{"q":"يُدان حامل رخصة CDL في وايومنغ بمخالفتين مروريتين خطيرتين ناشئتين عن حادثتين منفصلتين خلال فترة 3 سنوات. ما هو الإيقاف؟","options":["60 يومًا","30 يومًا","120 يومًا","90 يومًا"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى إيقاف لمدة 60 يومًا. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"43":{"q":"كم تبلغ مدة إيقاف حامل رخصة CDL في وايومنغ لثلاث مخالفات مرورية خطيرة من حوادث منفصلة خلال فترة 3 سنوات؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى إيقاف لمدة 120 يومًا. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"44":{"q":"أي حاملي تظهير CDL مطالَبون بالتوقف عند كل تقاطع سكة حديد مع طريق سريع أثناء تشغيل مركبة تجارية في وايومنغ؟","options":["سائقو مركبات الركاب والمواد الخطرة (التي تحمل لوحات تحذيرية)","السائقون الحاصلون على تظهير صهريج فقط","جميع سائقي المركبات التجارية دون استثناء","سائقو الحافلات المدرسية دون سن 21 عامًا فقط"],"explanation":"يجب على السائقين الذين ينقلون ركابًا أو مواد خطرة تحمل لوحات تحذيرية التوقف عند جميع تقاطعات السكك الحديدية؛ أما المركبات التجارية الأخرى فيجب أن تبطئ وتتحقق. المصدر: دليل CDL في وايومنغ؛ 49 CFR 392.10 / 383.51."},"45":{"q":"ما هو الحد الأدنى للإيقاف في وايومنغ لأول مخالفة لتقاطع سكة حديد مع طريق سريع في مركبة تجارية؟","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي أول مخالفة لتقاطع سكة حديد إلى إيقاف لا يقل عن 60 يومًا. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51 الجدول 3."},"46":{"q":"يرتكب سائق ثاني مخالفة لتقاطع سكة حديد مع طريق سريع خلال 3 سنوات. ما هو الحد الأدنى للإيقاف؟","options":["120 يومًا","60 يومًا","90 يومًا","سنة واحدة"],"explanation":"تؤدي ثاني مخالفة لتقاطع سكة حديد خلال 3 سنوات إلى إيقاف لا يقل عن 120 يومًا. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51 الجدول 3."},"47":{"q":"ما هو الحد الأدنى للإيقاف لثالث مخالفة لتقاطع سكة حديد مع طريق سريع خلال فترة 3 سنوات؟","options":["سنة واحدة","120 يومًا","60 يومًا","مدى الحياة"],"explanation":"تؤدي ثالث مخالفة لتقاطع سكة حديد أو ما يليها خلال 3 سنوات إلى إيقاف لا يقل عن سنة واحدة. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51 الجدول 3."},"48":{"q":"ما هو الحد الأدنى للإيقاف لأول إدانة لسائق رخصة CDL بمخالفة أمر إيقاف عن الخدمة (OOS) أثناء تشغيل مركبة تجارية؟","options":["من 180 يومًا إلى سنة واحدة","من 30 إلى 60 يومًا","من سنتين إلى 5 سنوات","من 60 إلى 120 يومًا"],"explanation":"تؤدي أول مخالفة لأمر إيقاف عن الخدمة إلى إيقاف لا يقل عن 180 يومًا ولا يزيد على سنة واحدة. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51 الجدول 4."},"49":{"q":"ما هو نطاق الإيقاف لثاني مخالفة لأمر إيقاف عن الخدمة خلال فترة 10 سنوات (لغير المواد الخطرة/غير نقل الركاب)؟","options":["من سنتين إلى 5 سنوات","من 180 يومًا إلى سنة واحدة","من سنة إلى سنتين","من 3 إلى 5 سنوات"],"explanation":"تؤدي ثاني مخالفة لأمر إيقاف عن الخدمة خلال 10 سنوات إلى إيقاف لا يقل عن سنتين ولا يزيد على 5 سنوات. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51 الجدول 4."},"50":{"q":"يرتكب سائق ينقل مواد خطرة تحمل لوحات تحذيرية أو 16 راكبًا أو أكثر أول مخالفة لأمر إيقاف عن الخدمة. ما هو نطاق الإيقاف؟","options":["من 180 يومًا إلى سنتين","من 60 إلى 120 يومًا","من سنة إلى 3 سنوات","من 3 إلى 5 سنوات"],"explanation":"تؤدي أول مخالفة لأمر إيقاف عن الخدمة أثناء نقل مواد خطرة تحمل لوحات تحذيرية أو نقل 16 راكبًا أو أكثر إلى إيقاف لا يقل عن 180 يومًا ولا يزيد على سنتين. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51 الجدول 4."},"51":{"q":"المراسلة النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية في وايومنغ يُعامَل كأي نوع من مخالفات رخصة CDL؟","options":["مخالفة مرورية خطيرة تُحتسب نحو إيقاف 60/120 يومًا","مخالفة بسيطة غير قابلة للإبلاغ","إيقاف تلقائي مدى الحياة","مخالفة تقاطع سكة حديد"],"explanation":"تُعدّ المراسلة النصية واستخدام الهاتف المحمول باليد أثناء قيادة مركبة تجارية مخالفتين مروريتين خطيرتين؛ ومخالفتان خلال 3 سنوات تؤديان إلى إيقاف 60 يومًا، وثلاث تؤدي إلى إيقاف 120 يومًا. المصدر: دليل CDL في وايومنغ؛ 49 CFR 383.51؛ 49 CFR 392.80/392.82."},"52":{"q":"ما هو الحد الأقصى للغرامة المدنية الفيدرالية التي قد يواجهها سائق مركبة تجارية في وايومنغ عن مخالفة واحدة للمراسلة النصية أو استخدام الهاتف المحمول باليد أثناء القيادة؟","options":["ما يصل إلى 2,750 دولارًا","ما يصل إلى 250 دولارًا","ما يصل إلى 11,000 دولار","ما يصل إلى 500 دولار"],"explanation":"يمكن تغريم سائق المركبة التجارية ما يصل إلى 2,750 دولارًا عن كل مخالفة للمراسلة النصية/الهاتف المحمول باليد؛ ويمكن تغريم الناقل صاحب العمل ما يصل إلى 11,000 دولار للسماح بذلك. المصدر: قواعد الهاتف المحمول / عدم المراسلة النصية الصادرة عن FMCSA؛ 49 CFR 392.80-392.82، السارية في وايومنغ."},"53":{"q":"بعد إيقاف رخصة CDL مدى الحياة، متى (إن وُجد ذلك) قد يصبح السائق في وايومنغ مؤهلًا للتقدم بطلب لإعادة الترخيص بموجب حكم إعادة الترخيص المحدود؟","options":["بعد 10 سنوات على الأقل، مع شروط (تظل المواد الخطرة غير مؤهلة)","بعد 5 سنوات تلقائيًا","أبدًا تحت أي ظرف","بعد 3 سنوات مع سجل نظيف"],"explanation":"يجوز النظر في إعادة ترخيص السائق الموقوف مدى الحياة بعد حد أدنى قدره 10 سنوات واستيفاء شروط إعادة الترخيص؛ ولا تُستعاد أهلية المواد الخطرة. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"54":{"q":"المخالفات الكبرى المؤدية إلى الإيقاف مثل القيادة تحت تأثير الكحول (DUI) أو استخدام مركبة لارتكاب جناية تنطبق على حامل رخصة CDL في وايومنغ حتى عندما تقع المخالفة في أي نوع من المركبات؟","options":["أي مركبة آلية، بما في ذلك السيارة الشخصية للسائق","مركبة تجارية تحمل لوحات تحذيرية للمواد الخطرة فقط","مركبة يملكها صاحب العمل فقط","مركبة يتجاوز تصنيف وزنها الإجمالي 26,001 رطل فقط"],"explanation":"تُحتسب المخالفات الكبرى مثل القيادة تحت تأثير الكحول ضد رخصة CDL بغض النظر عن نوع المركبة؛ وحامل رخصة CDL المُدان بالقيادة تحت تأثير الكحول في سيارة شخصية يظل موقوفًا. المصدر: دليل CDL في وايومنغ؛ W.S. 31-7-305؛ 49 CFR 383.51."},"55":{"q":"في وايومنغ، يقترب سائق CDL ينقل مواد خطرة تحمل لافتات تحذيرية من تقاطع سكة حديد مع طريق سريع. أين يجب أن تتوقف المركبة؟","options":["على مسافة لا تقل عن 5 أقدام ولا تزيد عن 25 قدماً من أقرب قضيب سكة","على مسافة لا تقل عن 50 قدماً ولا تزيد عن 100 قدم من أقرب قضيب سكة","على مسافة لا تقل عن 10 أقدام ولا تزيد عن 30 قدماً من أقرب قضيب سكة","على مسافة لا تقل عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب سكة"],"explanation":"قاعدة وايومنغ: يجب على المركبة التي تحمل لافتات تحذيرية للمواد الخطرة (أو تنقل أي كمية من الكلور أو تحمل صهاريج شحن مواد خطرة محملة/فارغة) أن تتوقف على مسافة بين 15 و50 قدماً من أقرب قضيب سكة وألا تتابع السير إلا عندما لا يكون هناك قطار قادم. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 9 - المواد الخطرة، حكم تقاطع السكك الحديدية."},"56":{"q":"يجب على سائق حافلة في وايومنغ ينقل ركاباً أن يتوقف عند تقاطع سكة حديد. ما هي منطقة التوقف المطلوبة قبل التقاطع؟","options":["بين 20 و60 قدماً قبل التقاطع","بين 15 و50 قدماً قبل التقاطع","بين 10 و40 قدماً قبل التقاطع","بين 25 و75 قدماً قبل التقاطع"],"explanation":"قاعدة وايومنغ: يجب على سائقي الحافلات إيقاف الحافلة على مسافة بين 15 و50 قدماً قبل تقاطعات السكك الحديدية، ثم النظر والإصغاء في كلا الاتجاهين بحثاً عن القطارات قبل العبور. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 4 - نقل الركاب (تقاطعات السكك الحديدية مع الطرق السريعة والتوقفات)."},"57":{"q":"بموجب قانون الإفساح في وايومنغ، يقترب سائق CDL على طريق سريع بين الولايات أو طريق سريع آخر ذي مسارين أو أكثر في اتجاهه من مركبة طوارئ متوقفة تعرض إشارات ضوئية. ماذا يُطلب من السائق أن يفعل، عندما يكون ذلك آمناً؟","options":["التوقف توقفاً تاماً حتى تغادر مركبة الطوارئ","إطلاق صوت البوق ومتابعة السير بالسرعة المحددة في المسار نفسه","الانتقال إلى مسار غير مجاور لمركبة الطوارئ (المسار الأبعد عنها)","الانتقال إلى الكتف الأيمن للطريق والانتظار حتى يشير ضابط بالمرور"],"explanation":"قاعدة وايومنغ: على طريق سريع ذي مسارين أو أكثر في اتجاه السير، يجب على السائق الذي يقترب من مركبة طوارئ مرخصة متوقفة تستخدم إشارات ضوئية أن ينتقل إلى مسار غير مجاور لتلك المركبة (المسار الأبعد) عندما يكون ذلك آمناً؛ وإذا كان تغيير المسار غير آمن، فعليه تخفيف السرعة والمتابعة بحذر. المصدر: قانون وايومنغ 31-5-224؛ دليل CDL في وايومنغ لعام 2024 (قوانين الإفساح)."},"58":{"q":"بموجب قانون الإفساح في وايومنغ، على طريق ذي مسارين بسرعة محددة 45 mph أو أكثر، يجب على السائق الذي يتجاوز مركبة طوارئ أو سحب متوقفة ولا يستطيع تغيير المسار بأمان أن يخفض سرعته إلى أي مستوى؟","options":["20 mph أقل من السرعة القصوى المحددة","10 mph أقل من السرعة القصوى المحددة","15 mph أقل من السرعة القصوى المحددة","بالضبط 25 mph بصرف النظر عن الحد المحدد"],"explanation":"قاعدة وايومنغ: على طريق ذي مسارين بسرعة قصوى محددة 45 mph أو أكثر، يجب على السائق أن يخفف السرعة إلى مستوى يقل بمقدار 20 mph عن السرعة القصوى المحددة عند تجاوز مركبة طوارئ أو مرافق عامة أو صيانة أو سحب متوقفة تستخدم إشارات ضوئية. المصدر: قانون وايومنغ 31-5-224."},"59":{"q":"يحمي قانون الإفساح في وايومنغ (W.S. 31-5-224) أكثر من الشرطة وسيارات الإسعاف. أي من هذه المركبات مشمول صراحةً أيضاً؟","options":["أي سيارة ركاب متوقفة على كتف الطريق مع تشغيل أضواء الخطر","شاحنة قطر أو سحب في موقع مركبة معطلة تعرض مصباحاً وامضاً أحمر أو أحمر وأزرق","حافلة مدرسية متوقفة لتحميل الأطفال","شاحنة توصيل متوقفة بشكل مزدوج في شارع داخل المدينة"],"explanation":"قاعدة وايومنغ: يشمل قانون الإفساح مركبات الطوارئ المرخصة، ومركبات البلدية/المرافق العامة/إنشاء أو صيانة الطرق السريعة، وشاحنات القطر أو السحب في موقع مركبة محطمة أو معطلة أو متوقفة عندما تكون مجهزة بمصباح واحد على الأقل وامض أحمر أو أحمر وأزرق يُرى على مسافة 500 قدم من الأمام والخلف. المصدر: قانون وايومنغ 31-5-224."},"60":{"q":"على طريق سريع في وايومنغ ذي مسارين واتجاهين، تتوقف حافلة مدرسية مع وميض أضوائها الحمراء وامتداد ذراع التوقف. ماذا يجب على سائق CDL مقترب من الاتجاه المعاكس أن يفعل؟","options":["تخفيف السرعة إلى 15 mph والتجاوز بحذر","التوقف قبل الوصول إلى الحافلة والبقاء متوقفاً حتى يتوقف وميض الأضواء أو تتحرك الحافلة","متابعة السير بالسرعة المحددة لأن حركة المرور القادمة من الاتجاه المعاكس معفاة","التوقف فقط إذا كان الأطفال يعبرون الطريق بشكل ظاهر"],"explanation":"قاعدة وايومنغ: عند مقابلة أو تجاوز حافلة مدرسية متوقفة تعرض أضواءً حمراء وامضة من أي اتجاه، يجب على السائق أن يتوقف قبل الوصول إلى الحافلة وألا يتابع السير حتى تتحرك الحافلة أو يتوقف وميض الأضواء الحمراء. المصدر: قانون وايومنغ 31-5-507."},"61":{"q":"ينطوي قانون التوقف للحافلات المدرسية في وايومنغ على استثناء للطريق السريع المقسّم. متى لا يُطلب من السائق التوقف لحافلة مدرسية تعرض أضواءً حمراء وامضة؟","options":["فقط عندما يوجد خط مركزي مرسوم بين اتجاهي السير","كلما كان السائق على بُعد أكثر من مسارين من الحافلة","كلما كان الطريق بسرعة قصوى محددة تفوق 55 mph","عندما تكون الحافلة على طريق مختلف ضمن طريق سريع ذي طرق منفصلة"],"explanation":"قاعدة وايومنغ: لا يحتاج السائق على طريق سريع ذي طرق منفصلة إلى التوقف عند مقابلة أو تجاوز حافلة مدرسية موجودة على طريق مختلف، أو عندما يكون على طريق سريع ذي وصول مقيد وتكون الحافلة متوقفة في منطقة تحميل لا يُسمح فيها للمشاة بالعبور. ووجود خط مرسوم وحده لا يكفي. المصدر: قانون وايومنغ 31-5-507."},"62":{"q":"يجب على سائق CDL في وايومنغ إيقاف المركبة على كتف طريق سريع باتجاه واحد أو مقسّم. خلال أي مدة يجب وضع أجهزة التحذير من الطوارئ، وأين؟","options":["خلال 30 دقيقة، على مسافة 25 قدماً و100 قدم و250 قدماً باتجاه حركة المرور القادمة","خلال 10 دقائق، على مسافة 50 قدماً و150 قدماً و300 قدم باتجاه حركة المرور القادمة","خلال 10 دقائق، على مسافة 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","خلال 5 دقائق، على مسافة 10 أقدام و50 قدماً و100 قدم باتجاه حركة المرور القادمة"],"explanation":"قاعدة وايومنغ: إذا توقفت على طريق سريع باتجاه واحد أو مقسّم أو بجانبه، ضع أجهزة التحذير خلال 10 دقائق على مسافة 10 أقدام و100 قدم و200 قدم من المركبة باتجاه حركة المرور القادمة. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 2 - القيادة بأمان (أجهزة التحذير للمركبات المتوقفة)."},"63":{"q":"يتوقف سائق CDL في وايومنغ على طريق ذي مسارين يحمل حركة مرور في كلا الاتجاهين. كيف ينبغي وضع المثلثات العاكسة الثلاثة؟","options":["على مسافة 10 أقدام و100 قدم و200 قدم، جميعها خلف المركبة فقط","على مسافة 25 قدماً و100 قدم و200 قدم أمام المركبة فقط","على مسافة 10 أقدام من المركبة، بالإضافة إلى 100 قدم خلف المركبة و100 قدم أمامها","على مسافة 10 أقدام و50 قدماً و150 قدماً خلف المركبة"],"explanation":"قاعدة وايومنغ: على طريق ذي مسارين يحمل حركة مرور في كلا الاتجاهين (أو طريق سريع غير مقسّم)، ضع أجهزة التحذير على مسافة 10 أقدام من الزوايا الأمامية أو الخلفية لتحديد موقع المركبة، و100 قدم خلف المركبة و100 قدم أمامها. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 2 - القيادة بأمان."},"64":{"q":"إذا حجب تل أو منعطف الرؤية عن مركبة CDL متوقفة على طريق في وايومنغ، فماذا يوصي الدليل بفعله بشأن مثلث التحذير الخلفي؟","options":["تحريكه إلى الخلف على الطريق لتوفير تحذير بعد العائق، حتى مسافة 500 قدم","ترك جميع المثلثات على التباعد القياسي 10/100/200 قدم","وضعه مباشرة على العائق نفسه لتحقيق أقصى ظهور","إزالته بالكامل والاعتماد فقط على أضواء الطوارئ رباعية الاتجاه"],"explanation":"قاعدة وايومنغ: إذا كانت رؤية خط النظر محجوبة بتل أو منعطف أو عائق آخر، حرّك المثلث الخلفي إلى الخلف على الطريق (إلى ما بعد العائق بحيث يمكن رؤية المركبة ضمن مسافة 500 قدم) لتوفير تحذير مناسب. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 2 - القيادة بأمان."},"65":{"q":"على الطرق السريعة الريفية بين الولايات في وايومنغ المحددة بسرعة 80 mph، كيف يُطبّق حد السرعة على القاطرة بمقطورة مقارنةً بسيارة الركاب؟","options":["تقتصر الشاحنات على 70 mph بينما يجوز للسيارات السير بسرعة 80 mph","تتشارك الشاحنات والسيارات الحد الأقصى نفسه البالغ 80 mph؛ ولا تحدد وايومنغ حداً أدنى منفصلاً للشاحنات","تقتصر الشاحنات على 65 mph بينما يجوز للسيارات السير بسرعة 80 mph","تقتصر الشاحنات على 75 mph بينما يجوز للسيارات السير بسرعة 80 mph"],"explanation":"قاعدة وايومنغ: ينطبق الحد الأقصى لسرعة الطرق بين الولايات في وايومنغ (حتى 80 mph على المقاطع الريفية المحددة) بالتساوي على الشاحنات التجارية وسيارات الركاب. وخلافاً لبعض الولايات، لا تحدد وايومنغ حد سرعة قانونياً منفصلاً وأدنى للشاحنات. المصدر: قانون وايومنغ 31-5-301؛ تحديدات ممر 80 mph لدى WYDOT."},"66":{"q":"تُفعّل وايومنغ قانون سلاسل متدرجاً على المقاطع الجبلية من الطريق I-80. بموجب المستوى 2 الأكثر شدة (خطر بالغ)، على ماذا يجوز للمركبة التجارية الاعتماد؟","options":["إطارات الثلج وحدها على المحور المحرك","الدفع بالعجلات الأمامية مع إطارات طرق سريعة قياسية","سلاسل الإطارات، أو الدفع الرباعي AWD المجهز بإطارات مصنفة M+S أو لجميع الأحوال الجوية (إطارات الثلج وحدها لا تكفي)","تخفيف السرعة فقط، دون أي متطلبات للمعدات"],"explanation":"قاعدة وايومنغ: بموجب المستوى 1، يجوز للمركبة التجارية استخدام السلاسل أو إطارات ثلج ملائمة أو الدفع الرباعي AWD؛ وبموجب المستوى 2 (خطر بالغ)، لا تكفي إطارات الثلج وحدها ويجب على المركبة استخدام سلاسل الإطارات، أو الدفع الرباعي AWD المجهز بإطارات مصنفة M+S أو لجميع الأحوال الجوية. المصدر: مستويات قانون السلاسل في وايومنغ لدى WYDOT (يُطبّق عادةً على مقطع \"الأخوات الثلاث\" في الطريق I-80)."},"67":{"q":"خلال حدث رياح شديدة، تغلق وايومنغ مقاطع من الطريقين I-80 وI-25 أمام أي مركبات أولاً؟","options":["سيارات الركاب والدراجات النارية فقط","المركبات التجارية الخفيفة عالية الواجهة (مثل الشاحنات الفارغة أو المحملة قليلاً)","الصهاريج المحملة بالكامل التي تنقل سوائل فقط","الحافلات التي تنقل ركاباً فقط"],"explanation":"قاعدة وايومنغ: بسبب حوادث الانقلاب المتكررة بفعل الرياح، تقيّد WYDOT وتغلق مقاطع من الطريقين I-80 وI-25 أمام المركبات الخفيفة عالية الواجهة (وفي أسوأ الظروف، أمام جميع المركبات التجارية). تُنشر الإغلاقات على wyoroad.info / Wyoming 511. المصدر: قيود الرياح الشديدة/الانقلاب لدى WYDOT."},"68":{"q":"ما الحد الأقصى لعرض المركبة التجارية التي يجوز لها السير على الطرق السريعة في وايومنغ دون تصريح للحمولة الزائدة الحجم؟","options":["8 أقدام و0 بوصة","9 أقدام و0 بوصة","8 أقدام و6 بوصات","10 أقدام و0 بوصة"],"explanation":"قاعدة وايومنغ: الحد الأقصى القانوني لعرض المركبة دون تصريح هو 8 أقدام و6 بوصات (102 inches)؛ وأي عرض أكبر من ذلك يتطلب تصريح حمولة زائدة الحجم من WYDOT. المصدر: قانون وايومنغ 31-18-802 / لوائح تصاريح الحمولة الزائدة الحجم لدى WYDOT."},"69":{"q":"دون تصريح، ما الحد الأقصى القانوني لارتفاع المركبة على الطرق السريعة في وايومنغ؟","options":["14 feet","13'6\"","13 feet","15 feet"],"explanation":"قاعدة وايومنغ: الحد الأقصى القانوني لارتفاع المركبة دون تصريح هو 14 feet؛ والحمولات التي تتجاوز ذلك تتطلب تصريح حمولة زائدة الحجم. المصدر: قانون وايومنغ 31-18-802 / لوائح الحمولة الزائدة الحجم لدى WYDOT."},"70":{"q":"يحتاج ناقل في وايومنغ إلى تصريح حمولة زائدة الحجم لرحلة واحدة من WYDOT لنقل واحد زائد العرض. ما الرسم الأساسي لتصريح الحمولة الزائدة الحجم لرحلة واحدة؟","options":["$10.00","$50.00","$100.00","$25.00"],"explanation":"قاعدة وايومنغ: رسم تصريح الحمولة الزائدة الحجم لرحلة واحدة هو $25.00، مع رسوم إضافية مبنية على المسافة للحمولات التي تتجاوز 15 feet عرضاً أو 15 feet ارتفاعاً أو 75 feet طولاً. المصدر: قانون وايومنغ 31-18-804 / جدول رسوم تصاريح الحمولة الزائدة الحجم لدى WYDOT."},"71":{"q":"في تركيبة قاطرة ونصف مقطورة في وايومنغ، ما الحد الأقصى للطول المسموح به لنصف المقطورة نفسها دون تصريح؟","options":["60 feet","48 feet","53 feet","57 feet"],"explanation":"قاعدة وايومنغ: في تركيبة قاطرة شاحنة مع نصف مقطورة، لا يجوز أن يتجاوز طول نصف المقطورة 60 feet (تسمح وايومنغ على نحو لافت بنصف مقطورة مفردة أطول من المقطورة الشائعة بطول 53-foot). المصدر: قانون وايومنغ 31-18-802 (حدود الحجم والوزن)."},"72":{"q":"أثناء عبور مجموعة من قضبان السكك الحديدية في وايومنغ، ماذا يوجّه دليل CDL سائق المركبة التجارية ذات ناقل الحركة اليدوي أن يفعل؟","options":["عدم تبديل التروس أثناء وجود أي جزء من المركبة على القضبان","التحويل إلى أدنى ترس في منتصف العبور لتحقيق أقصى تماسك","التحويل إلى الوضع المحايد والانزلاق عبر القضبان","رفع ترس واحد لاجتياز القضبان بأسرع ما يمكن"],"explanation":"قاعدة وايومنغ: يوجّه الدليل بعدم تبديل التروس أثناء عبور قضبان السكك الحديدية، لأن تغيير التروس يخاطر بتوقف المحرك على القضبان؛ اختر ترساً يأخذك عبر القضبان بالكامل قبل البدء. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، القسم 2.15 - تقاطعات السكك الحديدية/الطرق السريعة."},"73":{"q":"عند الاقتراب من تقاطع سكة حديد في وايومنغ، ما الإجراء الذي ينبغي أن تتخذه حافلة مدرسية أو حافلة ركاب أو مركبة تحمل لافتات تحذيرية بشأن أضوائها وهي تقترب من القضبان؟","options":["إطفاء جميع الأضواء الخارجية لتجنب إرباك طاقم القطار","وميض الأضواء العالية باستمرار حتى عبور القضبان","تشغيل إشارة الانعطاف في اتجاه أقرب قضيب سكة","تشغيل أضواء الطوارئ رباعية الاتجاه عند الاقتراب، وإطفاؤها بعد اجتياز القضبان"],"explanation":"قاعدة وايومنغ: ينبغي للحافلة أو الحافلة المدرسية أو المركبة التي تحمل لافتات تحذيرية تشغيل أضواء الطوارئ رباعية الاتجاه عند اقترابها من التقاطع، والتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب سكة، والنظر والإصغاء، ثم إطفاء الأضواء بعد العبور. المصدر: دليل رخصة القيادة التجارية في وايومنغ لعام 2024 (WYDOT)، إجراءات اختبار الطريق لتقاطعات السكك الحديدية."},"74":{"q":"أي جهة في وايومنغ تدير سجلات القيادة وتصدر جميع فئات رخص القيادة التجارية (CDLs) في الولاية؟","options":["وزارة النقل في وايومنغ (WYDOT)، برنامج خدمات السائقين","إدارة المركبات الآلية في وايومنغ، وهي جهة مستقلة","دورية الطرق السريعة في وايومنغ، شعبة الترخيص","مكتب كاتب المقاطعة في مقاطعة إقامة مقدم الطلب"],"explanation":"في وايومنغ، يدير برنامج خدمات السائقين التابع لـ WYDOT نظام سجلات القيادة والاختبارات، ويصدر ويعالج جميع فئات رخص القيادة ورخص القيادة التجارية. ولا توجد في وايومنغ جهة \"DMV\" منفصلة. المصدر: صفحة خدمات السائقين/الرخصة التجارية لدى WYDOT."},"75":{"q":"قبل أن تتمكن WYDOT من إجراء اختبار مهارات CDL، ما المتطلب الذي يجب على مقدم الطلب المبتدئ لأول رخصة CDL من الفئة A أو الفئة B إكماله؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مدرج في سجل مزودي التدريب التابع لـ FMCSA","دورة قيادة دفاعية مدتها 40 ساعة معتمدة من دورية الطرق السريعة في وايومنغ","سنتان من الخبرة الموثقة في القيادة داخل الولاية","تقييم كفاءة طبية تجريه WYDOT"],"explanation":"تتطلب قواعد ELDT الفيدرالية، المطبقة في وايومنغ، من السائقين المبتدئين إكمال التدريب النظري والتدريب العملي خلف المقود من مزوّد مدرج في سجل مزودي التدريب (TPR) التابع لـ FMCSA قبل خوض اختبار المهارات. وتنص WYDOT على أنه لا يجوز إجراء اختبارات مهارات CDL إلا لمن أكملوا ELDT أو يحملون إعفاء الحقوق المكتسبة. المصدر: صفحة اختبار CDL لدى WYDOT؛ 49 CFR Part 380 Subpart F."},"76":{"q":"يتكوّن اختبار مهارات CDL في وايومنغ من أي ثلاثة أجزاء، تُجرى بالترتيب؟","options":["فحص ما قبل الرحلة (المركبة)، ومهارات التحكم الأساسية، والقيادة على الطريق","اختبار المعرفة الكتابي، وفحص النظر، والقيادة على الطريق","اختبار المكابح الهوائية، واختبار الوصل، والقيادة الليلية","القيادة الدفاعية، ومهارات التحكم الأساسية، وعرض توضيحي لمناولة المواد الخطرة"],"explanation":"يتكوّن اختبار مهارات CDL في وايومنغ من فحص ما قبل الرحلة للمركبة، واختبار مهارات التحكم الأساسية، واختبار القيادة على الطريق. المصدر: صفحة اختبار CDL لدى WYDOT؛ معايير مهارات CDL الصادرة عن AAMVA والمعتمدة في وايومنغ."},"77":{"q":"ما هي فئات التصديق الذاتي الأربع التي يجب على مقدم طلب CDL في وايومنغ الاختيار من بينها عند إقرار نوع القيادة التجارية التي يمارسها؟","options":["بين الولايات غير معفاة، بين الولايات معفاة، داخل الولاية غير معفاة، داخل الولاية معفاة","محلية، إقليمية، عبر الطرق الطويلة، وموسمية","الفئة A، الفئة B، الفئة C، والمصادقات فقط","للأجر، خاصة، زراعية، وطوارئ"],"explanation":"تتطلب وايومنغ من كل حامل CDL التصديق الذاتي على إحدى أربع فئات: بين الولايات غير معفاة (NI)، وبين الولايات معفاة (EI)، وداخل الولاية غير معفاة (NA)، وداخل الولاية معفاة (EA). المصدر: صفحة تصديق السائق لدى WYDOT؛ 49 CFR 383.71(b)."},"78":{"q":"بموجب قاعدة رخصة المتعلم التجارية (CLP) الفيدرالية المطبقة في وايومنغ، كم يجب أن يحمل مقدم الطلب رخصة CLP قبل السماح له بخوض اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","7 أيام على الأقل","60 يوماً على الأقل"],"explanation":"يجب على حامل CLP في وايومنغ الانتظار 14 يوماً على الأقل بعد إصدار CLP قبل خوض اختبار مهارات CDL. المصدر: 49 CFR 383.25(a)(3)، المطبق من قبل خدمات السائقين لدى WYDOT."},"79":{"q":"يصدّق حامل CDL في وايومنغ ذاتياً على أنه \"بين الولايات غير معفى\" (NI). ما الوثيقة الإضافية التي يجب عليه إبقاؤها سارية لدى WYDOT؟","options":["شهادة طبية سارية من فاحص طبي معتمد لدى DOT مدرج في السجل الوطني","خطاب صلاحية تشغيل بين الولايات سنوي من FMCSA","إقرار موثّق بالتشغيل داخل الولاية فقط","تصريح أمني للمواد الخطرة صادر عن وايومنغ"],"explanation":"يجب على السائقين الذين يصدّقون ذاتياً على أنهم بين الولايات غير معفيين (NI) أو داخل الولاية غير معفيين (NA) أن يكونوا مؤهلين طبياً وأن يبقوا شهادة طبية سارية من DOT في الملف. أما السائقون المعفون (EI/EA) فلا يلزمهم ذلك. ويجب أن يكون الفاحص مدرجاً في السجل الوطني لـ FMCSA. المصدر: صفحات تصديق السائق/الشهادة الطبية من DOT لدى WYDOT؛ 49 CFR 383.71(h)."},"80":{"q":"ماذا يحدث لرخصة CDL في وايومنغ إذا سمح حاملها بانقضاء شهادته الطبية المطلوبة من DOT وأصبح \"غير مصدّق\"؟","options":["تخضع رخصة CDL لخفض درجتها إلى رخصة قيادة غير تجارية","تُلغى رخصة CDL فوراً وبشكل دائم دون أي مسار لإعادة الإصدار","تتحول رخصة CDL تلقائياً إلى وضع معفى داخل الولاية دون الحاجة إلى أي إجراء","تُعلّق رخصة CDL لمدة 90 يوماً بالضبط، ثم تُعاد تلقائياً"],"explanation":"إذا لم يبقِ حامل CDL في وايومنغ شهادة طبية سارية في الملف، فإنه يصبح \"غير مصدّق\" وتخضع رخصة CDL لخفض درجتها إلى رخصة غير تجارية. المصدر: صفحات تصديق السائق/الشهادة الطبية من DOT لدى WYDOT؛ 49 CFR 383.73(o)."},"81":{"q":"ما الحد الأدنى لدرجة النجاح التي تشترطها وايومنغ في كل اختبار معرفة (كتابي) لرخصة CDL؟","options":["80 بالمئة","70 بالمئة","75 بالمئة","90 بالمئة"],"explanation":"اختبارات معرفة CDL في وايومنغ من نوع الاختيار من متعدد وتتطلب نسبة 80% صحيحة على الأقل للنجاح؛ ويعيد مقدمو الطلبات فقط الاختبارات التي يرسبون فيها. المصدر: صفحة اختبار CDL لدى WYDOT."},"82":{"q":"كم مرة يجب تجديد رخصة CDL في وايومنغ للحفاظ على امتيازات القيادة التجارية؟","options":["كل 4 سنوات","كل 5 سنوات","كل 8 سنوات","كل سنتين"],"explanation":"تُصدر رخص CDL في وايومنغ بدورة تجديد مدتها 4 سنوات. المصدر: معلومات تجديد رخصة القيادة لدى WYDOT."},"83":{"q":"مع تطبيق وايومنغ لعملية السجل الوطني الثاني (NRII) التابعة لـ FMCSA، كيف يتم عادةً تقديم تصديق السائق الطبي من DOT إلى WYDOT؟","options":["يرسل الفاحص الطبي المعتمد النتائج إلكترونياً عبر السجل الوطني لـ FMCSA إلى سجل القيادة في الولاية","يرسل السائق نسخة مصورة من الشهادة الورقية بالبريد إلى كاتب المقاطعة","يرسل صاحب العمل الشهادة بالفاكس إلى دورية الطرق السريعة في وايومنغ","يرفع السائق صورة ممسوحة ضوئياً إلى حساب سائق شخصي لدى FMCSA"],"explanation":"بموجب قاعدة السجل الوطني الثاني (NRII) التابعة لـ FMCSA (السارية اعتباراً من 23 يونيو 2025)، يرسل الفاحص الطبي المعتمد نتائج التصديق الطبي إلكترونياً عبر السجل الوطني مباشرةً إلى سجل جهة ترخيص السائقين في الولاية؛ ولدى الفاحص حتى منتصف ليل اليوم التقويمي التالي لإدخال النتائج. المصدر: صفحة الشهادة الطبية من DOT لدى WYDOT؛ قاعدة NRII التابعة لـ FMCSA."},"84":{"q":"ما رقم نموذج شهادة الفاحص الطبي الفيدرالي المستخدم لتوثيق التأهيل الطبي من DOT لرخصة CDL في وايومنغ؟","options":["MCSA-5876","MCSA-5875","MCSA-5870","MCSA-5889"],"explanation":"شهادة الفاحص الطبي هي نموذج FMCSA رقم MCSA-5876 (أما تقرير الفحص الطبي الأطول فهو MCSA-5875). المصدر: النماذج الطبية لـ FMCSA؛ صفحة الشهادة الطبية من DOT لدى WYDOT."},"85":{"q":"السائق الذي يصدّق ذاتياً على أنه \"داخل الولاية معفى\" (EA) في وايومنغ يُدلي بأي بيان حول تشغيله؟","options":["أنه يعمل داخل وايومنغ فقط وغير ملزم بتلبية متطلبات البطاقة الطبية الفيدرالية من DOT","أنه يعمل عبر حدود الولايات ويجب أن يحمل بطاقة طبية فيدرالية من DOT","أنه ينقل مواد خطرة فقط ويحتاج إلى إعفاء طبي منفصل","أنه يقود مركبات حكومية فقط معفاة من الترخيص"],"explanation":"يعني داخل الولاية معفى (EA) أن السائق يعمل في التجارة داخل الولاية فقط ومعفى من متطلب الشهادة الطبية الفيدرالية من DOT. المصدر: صفحة تصديق السائق لدى WYDOT؛ 49 CFR 383.71(b)."},"86":{"q":"عند التقدم للحصول على رخصة CDL أو CLP لأول مرة في وايومنغ، ما الوثيقة المطلوبة عادةً لإثبات الهوية؟","options":["شهادة ميلاد مصدّقة أو جواز سفر أمريكي ساري المفعول","بطاقة هوية حالية صادرة عن صاحب العمل","نموذج تنازل عن مصادقة CDL موقّع","بطاقة تسجيل مركبة باسم مقدم الطلب"],"explanation":"تتطلب وايومنغ إثبات الهوية مثل شهادة ميلاد مصدّقة (أو جواز سفر أمريكي بدلاً منها)، بالإضافة إلى إثبات رقم الضمان الاجتماعي والإقامة في وايومنغ، للتقدم بالطلب. المصدر: خدمات السائقين لدى WYDOT؛ متطلبات طلب CDL في وايومنغ."},"87":{"q":"تجري وايومنغ اختبار مهارات CDL بموجب أي ترتيب للجدولة؟","options":["بموعد مسبق فقط، بعد اجتياز جميع الاختبارات الكتابية المطلوبة","على أساس الحضور المباشر في أي كشك DMV على مستوى الولاية","فقط خلال أسبوع اختبار سنوي واحد كل ربيع","عبر الإنترنت من خلال جلسة فيديو مراقبة عن بُعد"],"explanation":"تُجرى اختبارات المهارات في وايومنغ بموعد مسبق فقط وبعد أن يجتاز مقدم الطلب جميع الاختبارات الكتابية (المعرفية) المطلوبة. وتوفر WYDOT اختبار المهارات في عدد محدود من المواقع عبر الولاية. المصدر: صفحة اختبار CDL لدى WYDOT."},"88":{"q":"بالنسبة لاختبار مهارات CDL في وايومنغ، من المسؤول عن توفير مركبة ممثّلة للفئة المناسبة؟","options":["يجب على مقدم الطلب توفير مركبة ممثّلة للفئة/النوع الذي يُختبر عليه","توفر WYDOT مركبة اختبار مملوكة للولاية لكل مقدم طلب","يوفر الفاحص الطبي المعتمد مركبة الاختبار","تعير دورية الطرق السريعة في وايومنغ مركبة مجاناً"],"explanation":"يجب على مقدمي الطلبات توفير مركباتهم الخاصة الممثّلة لفئة ونوع رخصة CDL المطلوبة؛ فعلى سبيل المثال، يجب أن تحمل مركبة الصهريج مصادقة N ووثائق التطهير، ولا يجوز استخدام حمولات المواد الخطرة التي تحمل لافتات أثناء الاختبار. المصدر: صفحة اختبار CDL لدى WYDOT."},"89":{"q":"في وايومنغ، يتطلب الحصول على مصادقة المواد الخطرة (H) أي تسلسل تدريب/اختبار؟","options":["إكمال تدريب ELDT النظري للمواد الخطرة، ثم اجتياز اختبار معرفة المواد الخطرة (إضافة إلى فحص خلفية من TSA)","اجتياز اختبار مهارات إضافي على الطريق خاص بالصهاريج","إكمال 200 ساعة من قيادة المواد الخطرة خلف المقود","الحصول على تصريح شحن خطر صادر عن المقاطعة قبل أي اختبار"],"explanation":"للحصول على مصادقة المواد الخطرة (H) لأول مرة، يجب إكمال تدريب ELDT النظري للمواد الخطرة قبل خوض اختبار معرفة المواد الخطرة؛ كما يُطلب تقييم تهديد أمني (فحص خلفية) من TSA. ولا يوجد اختبار مهارات منفصل للمواد الخطرة. المصدر: صفحات اختبار CDL/الرخصة التجارية لدى WYDOT؛ 49 CFR Part 380 Subpart B."},"90":{"q":"ما الحد الأدنى للسن لإصدار رخصة CDL في وايومنغ للقيادة التجارية داخل الولاية (ضمن وايومنغ)؟","options":["18 عاماً","21 عاماً","19 عاماً","16 عاماً"],"explanation":"يجوز إصدار رخصة CDL في وايومنغ في سن 18 للتشغيل داخل الولاية؛ ويجب أن يكون عمر السائق 21 عاماً للعمل في التجارة بين الولايات، أو نقل مواد خطرة تتطلب لافتات، أو نقل ركاب عبر حدود الولايات. المصدر: صفحات رخصة المتعلم التجارية/الرخصة التجارية لدى WYDOT."},"91":{"q":"كم تبقى رخصة المتعلم التجارية (CLP) في وايومنغ سارية المفعول وفقاً لـ WYDOT؟","options":["365 يوماً","30 يوماً","60 يوماً","10 سنوات"],"explanation":"وفقاً لـ WYDOT، تكون رخصة CLP في وايومنغ سارية المفعول لمدة 365 يوماً. (تتطلب القواعد الفيدرالية من الحامل الانتظار 14 يوماً على الأقل بعد الإصدار قبل خوض اختبار المهارات.) المصدر: صفحة رخصة المتعلم التجارية لدى WYDOT."},"92":{"q":"إذا ترك سائق في وايومنغ رخصة CDL تنتهي صلاحيتها ولم يجددها ضمن فترة السماح في الولاية (نحو سنتين)، فما المطلوب عموماً للحصول على رخصة CDL مرة أخرى؟","options":["البدء من جديد بالحصول على رخصة CLP جديدة وإعادة خوض اختبارات المعرفة والمهارات المطلوبة","دفع رسم تأخير ثابت وتُعاد رخصة CDL دون أي اختبار","تقديم شهادة طبية جديدة من DOT فقط لاستعادة رخصة CDL","الانتظار خمس سنوات إضافية قبل السماح بأي إعادة تقديم"],"explanation":"تسمح وايومنغ بتجديد رخصة CDL منتهية الصلاحية ضمن فترة سماح تبلغ نحو سنتين دون إعادة اختبار؛ وبعد ذلك، يجب على السائق البدء من جديد برخصة CLP جديدة وإعادة خوض اختبارات المعرفة والمهارات المطلوبة. المصدر: معلومات تجديد رخصة القيادة لدى WYDOT."},"93":{"q":"أي بيان يصف على أفضل وجه كيفية معاملة نتائج اختبار معرفة (كتابي) CDL خلال مدة صلاحية رخصة CLP في وايومنغ؟","options":["تبقى اختبارات المعرفة المجتازة سارية طوال مدة CLP، لذا لا يلزم إعادة سوى الاختبارات التي رسب فيها","يجب إعادة اجتياز جميع اختبارات المعرفة في اليوم نفسه الذي يُجرى فيه اختبار المهارات","تنتهي صلاحية نتائج اختبار المعرفة بعد 7 أيام من تاريخ الاختبار","يكفي اجتياز اختبارات المعرفة مرة واحدة ولا تنتهي صلاحيتها أبداً، حتى دون رخصة CLP"],"explanation":"في وايومنغ، ترتبط اختبارات المعرفة برخصة CLP: تبقى الاختبارات المجتازة سارية طوال مدة الرخصة، ويعيد مقدم الطلب فقط الاختبارات التي رسب فيها. المصدر: صفحة اختبار CDL لدى WYDOT."}}};
